<body>
<div class="container">
  <h1>Import Configuration</h1>
  <p class="subtitle">Restore customized entity names from a LibreCoach export file.</p>

  <div class="upload-area" id="uploadArea">
    <p>Select a LibreCoach export JSON file</p>
    <input type="file" id="fileInput" accept=".json">
  </div>

  <div class="preview" id="preview">
    <h3>File Preview</h3>
    <div id="previewContent"></div>
  </div>

  <button id="importBtn" disabled>Import</button>

  <div class="results" id="results">
    <h3 id="resultsTitle"></h3>
    <div id="resultsContent"></div>
  </div>
</div>

<script>
  const importPostUrl = window.location.href;
  const fileInput = document.getElementById("fileInput");
  const uploadArea = document.getElementById("uploadArea");
  const preview = document.getElementById("preview");
  const previewContent = document.getElementById("previewContent");
  const importBtn = document.getElementById("importBtn");
  const results = document.getElementById("results");
  const resultsTitle = document.getElementById("resultsTitle");
  const resultsContent = document.getElementById("resultsContent");

  let parsedConfig = null;

  fileInput.addEventListener("change", function () {
    const file = this.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = function (e) {
      try {
        const data = JSON.parse(e.target.result);
        if (!data.entities || typeof data.entities !== "object") {
          showPreviewError("Invalid file: missing 'entities' key.");
          return;
        }

        parsedConfig = data;
        const entityCount = Object.keys(data.entities).length;

        let html = "";
        html += row("Export Date", data.export_date || "Unknown");
        if (data.rv_info) {
          const rv = data.rv_info;
          const rvLabel = [rv.manufacturer, rv.model, rv.year, rv.other]
            .filter(Boolean).join(" ");
          if (rvLabel) html += row("Vehicle", rvLabel);
        }
        html += row("Customized Names", entityCount);
        if (entityCount === 0) {
          html += '<p class="error-text" style="margin-top:0.5rem">' +
                  "No customized names found — nothing to import.</p>";
        }

        previewContent.innerHTML = html;
        preview.classList.add("visible");
        uploadArea.classList.add("has-file");
        importBtn.disabled = entityCount === 0;
        results.classList.remove("visible");
      } catch (err) {
        showPreviewError("Could not parse JSON: " + err.message);
      }
    };
    reader.readAsText(file);
  });

  function showPreviewError(msg) {
    previewContent.innerHTML = '<p class="error-text">' + msg + "</p>";
    preview.classList.add("visible");
    importBtn.disabled = true;
    parsedConfig = null;
  }

  function row(label, value) {
    return '<div class="preview-row">' +
           '<span class="preview-label">' + label + "</span>" +
           '<span class="preview-value">' + value + "</span></div>";
  }

  importBtn.addEventListener("click", function () {
    if (!parsedConfig) return;
    importBtn.disabled = true;
    importBtn.innerHTML = '<span class="spinner"></span>Importing…';
    results.classList.remove("visible", "success", "failure");

    fetch(importPostUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(parsedConfig),
    })
    .then(function (res) { return res.json(); })
    .then(function (data) {
      resultsTitle.textContent = data.error ? "Import Failed" : "Import Complete";
      results.classList.add(data.error ? "failure" : "success");

      if (data.error) {
        resultsContent.innerHTML = '<p class="error-text">' + data.error + "</p>";
      } else {
        let html = "";
        html += row("Updated", data.updated || 0);
        html += row("Skipped (not in HA)", data.skipped || 0);
        html += row("Failed", data.failed || 0);
        resultsContent.innerHTML = html;
      }
      results.classList.add("visible");
    })
    .catch(function (err) {
      resultsTitle.textContent = "Import Failed";
      results.classList.add("failure", "visible");
      resultsContent.innerHTML = '<p class="error-text">' + err.message + "</p>";
    })
    .finally(function () {
      importBtn.innerHTML = "Import";
      importBtn.disabled = false;
    });
  });
</script>
</body>
</html>`;

msg.headers = { "Content-Type": "text/html" };
node.status({ fill: "green", shape: "dot", text: "Page served" });

return msg;

const victronEnabled = global.get("victronEnabled");
if (!victronEnabled) return null;

// Store active Victron device instances from ProductName topics
// Input: msg.topic = N/{portalId}/{serviceType}/{instance}/ProductName

const topic = msg.topic;
if (!topic) return null;

const parts = topic.split("/");
if (parts.length < 5) return null;

const serviceType = parts[2];
const instance = parts[3];
const key = `${serviceType}_${instance}`;

// Extract product name from payload
let productName = "";
if (typeof msg.payload === "string") {
  try {
    productName = JSON.parse(msg.payload).value || "";
  } catch (e) {
    productName = msg.payload;
  }
} else if (typeof msg.payload === "object" && msg.payload !== null) {
  productName = msg.payload.value || "";
}

// Build short name from first two alpha words of product name (skip model numbers)
const alphaWords = productName.split(/\s+/).filter((w) => /^[a-zA-Z]/.test(w));
const shortName = alphaWords
  .slice(0, 2)
  .join("_")
  .replace(/[^a-zA-Z0-9_-]/g, "")
  .toLowerCase();

// Get or initialize the active devices object
let victronDevices = global.get("victronDevices", "file") || {};

// Store or update device entry
victronDevices[key] = {
  productName: productName,
  shortName: shortName || serviceType,
};

global.set("victronDevices", victronDevices, "file");

node.status({
  fill: "green",
  shape: "dot",
  text: `${Object.keys(victronDevices).length} active devices`,
});

return null;

// Decodes THERMOSTAT_AMBIENT_STATUS messages (1FF9C)
// RV-C §6.16.11 — THERMOSTAT_AMBIENT_STATUS
// Message format: 3 bytes only (B0=instance, B1-2=ambient temp uint16)

// === Helper Functions ===

function decodeUint16LE(data, offset) {
  return data[offset] | (data[offset + 1] << 8);
}

// Table 5.3 uint16 temperature: raw * 0.03125 - 273 = °C
function decodeTemp16(raw, isCelsius) {
  if (raw === 65535) return null; // Not Available
  if (raw === 65534) return "Out of Range";
  const c = raw * 0.03125 - 273;
  if (isCelsius) return parseFloat(c.toFixed(1));
  return parseFloat(((c * 9) / 5 + 32).toFixed(1));
}

// === Main Decode Function ===

function decodeThermostatAmbientStatus(dgn, data) {
  const result = {
    dgn: dgn,
    dgn_name: "THERMOSTAT_AMBIENT_STATUS",
  };

  // Byte 0: Instance
  result.instance = data[0] === 255 ? null : data[0];
  result.raw_instance = data[0];

  // Bytes 1-2: Ambient temperature (uint16 LE, Table 5.3)
  if (data.length >= 3) {
    const rawTemp = decodeUint16LE(data, 1);
    result.ambient_temperature = decodeTemp16(rawTemp, false);
    result.raw_ambient_temperature = rawTemp;
  }

  return result;
}

// === Main Logic ===

if (!msg.payload || typeof msg.payload !== "object") {
  node.warn("Invalid payload: expected object");
  return null;
}

const incomingPayload = msg.payload;
const { dgn, data_payload } = incomingPayload;

if (!dgn || !data_payload) {
  node.warn("Missing required fields: dgn and/or data_payload");
  return null;
}

if (typeof data_payload !== "string" || data_payload.length % 2 !== 0) {
  node.warn("Invalid data_payload: must be even-length hex string");
  return null;
}

const dataBytes = data_payload.match(/.{1,2}/g).map((b) => parseInt(b, 16));

if (dataBytes.length < 3) {
  node.warn(
    `THERMOSTAT_AMBIENT_STATUS requires 3 bytes, got ${dataBytes.length}`,
  );
  return null;
}

const decoded = decodeThermostatAmbientStatus(dgn, dataBytes);

msg.payload = { ...incomingPayload, ...decoded };
delete msg.payload.data_payload;

return msg;

// Handles enable/disable of Geo integration via addon config
// Input: msg from librecoach/config/geo_enabled ("true" / "false")
// Output 1 → MQTT Out (entity deletion on disable)

// Only handle geo_enabled messages
const key = msg.topic.split("/").pop();
if (key !== "geo_enabled") return null;

const enabled = msg.payload.toString() === "true";

if (enabled) {
  node.status({ fill: "green", shape: "dot", text: "Enabled" });
  return null;
}

// === Disable: delete all tracked entities from HA ===
// Only need to delete what we create in status_geo.js
const sensors = ["city", "state", "timezone", "elevation"];

let deletedCount = 0;
sensors.forEach((sensor) => {
  const entityId = `geo_${sensor}`;
  node.send({ topic: `homeassistant/sensor/${entityId}/config`, payload: "" });
  deletedCount++;
});

// Clear persisted tracking state
flow.set("geoSensorsCreated", false);

node.status({
  fill: "red",
  text: `Disabled — removed ${deletedCount} entities`,
});

return null;

// Create/update Home Assistant MQTT Discovery entities from Hughes BLE state.
// Input: librecoach/ble/hughes/{mac}/state
// Output: discovery messages for retained MQTT output.

if (!global.get("hughesEnabled")) return null;

const parts = (msg.topic || "").split("/");
if (parts.length !== 5 || parts[0] !== "librecoach" || parts[2] !== "hughes") {
  return null;
}

let state = msg.payload;
if (typeof state === "string") {
  try {
    state = JSON.parse(state);
  } catch (error) {
    node.warn(`Invalid Hughes state JSON: ${error.message}`);
    return null;
  }
}
if (!state || typeof state !== "object" || !state.protocol) return null;

const mac = parts[3].toLowerCase();
const safeMac = mac.replace(/:/g, "_");
const baseId = `hughes_${safeMac}`;
const stateTopic = `librecoach/ble/hughes/${mac}/state`;
const availabilityTopic = `librecoach/ble/hughes/${mac}/available`;
const device = {
  identifiers: ["librecoach-hughes"],
  name: "Hughes",
  manufacturer: "LibreCoach",
};
const availability = [
  { topic: "librecoach/nodered/status", payload_available: "online", payload_not_available: "offline" },
  { topic: availabilityTopic, payload_available: "online", payload_not_available: "offline" },
];

global.set(`${baseId}_state`, state, "file");

const signature = JSON.stringify({
  protocol: state.protocol,
  is_50a: Boolean(state.is_50a),
  supports_control: Boolean(state.supports_control),
  has_booster: Boolean(state.has_booster),
});
if (global.get(`${baseId}_discovery_signature`, "file") === signature) return null;
global.set(`${baseId}_discovery_signature`, signature, "file");

const messages = [];

function add(component, suffix, payload) {
  const entityId = `${baseId}_${suffix}`;
  const topic = `homeassistant/${component}/${entityId}/config`;
  payload.unique_id = entityId;
  payload.default_entity_id = `${component}.${entityId}`;
  payload.device = device;
  if (!payload.availability && !payload.availability_topic) {
    payload.availability_mode = "all";
    payload.availability = availability;
  }
  messages.push({ topic, payload });
}

function sensor(suffix, name, field, unit, deviceClass, stateClass, icon) {
  const payload = {
    name,
    state_topic: stateTopic,
    value_template: `{{ value_json.${field} if value_json.${field} is not none else 'unknown' }}`,
  };
  if (unit) payload.unit_of_measurement = unit;
  if (deviceClass) payload.device_class = deviceClass;
  if (stateClass) payload.state_class = stateClass;
  if (icon) payload.icon = icon;
  add("sensor", suffix, payload);
}

sensor("voltage_l1", "Shore Voltage L1", "voltage_l1", "V", "voltage", "measurement");
sensor("current_l1", "Shore Current L1", "current_l1", "A", "current", "measurement");
sensor("power_l1", "Shore Power L1", "power_l1", "W", "power", "measurement");
sensor("frequency_l1", "Shore Frequency L1", "frequency_l1", "Hz", "frequency", "measurement");
sensor("energy", "Cumulative Energy", "energy_kwh", "kWh", "energy", "total_increasing");
sensor("combined_power", "Combined Shore Power", "combined_power", "W", "power", "measurement");
sensor("error_code", "Error Code", "error_code", null, null, null, "mdi:alert-circle-outline");
sensor("error_description", "Error Description", "error_description", null, null, null, "mdi:text-box-alert-outline");

if (state.is_50a) {
