  1: { suffix: "house", name: "Main House Battery" },
  2: { suffix: "chassis", name: "Chassis Battery" },
  3: { suffix: "house2", name: "Secondary House Battery" },
  4: { suffix: "generator", name: "Generator Battery" },
};

let entitySuffix, displayName;
