  return null;
}

const dataBytes = [];
for (let i = 0; i < data_payload.length; i += 2) {
  const hexByte = data_payload.substring(i, i + 2);
  const byteValue = parseInt(hexByte, 16);
  if (isNaN(byteValue)) {
    node.warn(`Invalid hex byte in data_payload: ${hexByte}`);
    return null;
  }
  dataBytes.push(byteValue);
}

// Decode the TANK_STATUS message
const decodedData = decodeTankStatusMessage(dgn, dataBytes);

// Handle null return (invalid instance filtered out)
if (!decodedData) {
  return null;
}

// Handle decode errors
if (decodedData.error) {
  incomingPayload.decoding_error = decodedData.error;
  msg.payload = incomingPayload;
  return msg;
}

// Merge the incoming payload and the decoded data into a single flat object
msg.payload = {
  ...incomingPayload,
  ...decodedData,
};

// Clean up the final object by removing the raw data field
delete msg.payload.data_payload;

return msg;

// Handles enable/disable of MicroAir integration via addon config
// Input: msg from librecoach/config/microair_enabled ("true" / "false")
// Output 1 → Filter nodes (reset on enable)
// Output 2 → MQTT Out (entity deletion on disable)

// Only handle microair_enabled messages
const key = msg.topic.split("/").pop();
if (key !== "microair_enabled") return [null, null];

const enabled = msg.payload.toString() === "true";

if (enabled) {
  node.status({ fill: "green", shape: "dot", text: "Enabled" });
  // Reset filter nodes when enabling so stale state doesn't block messages
  return [{ reset: true }, null];
}

// === Disable: delete all MicroAir entities ===
const index = global.get("discoveryIndex", "file") || {};
const topics = index.microair || [];

if (topics.length === 0) {
  node.status({
    fill: "yellow",
    shape: "ring",
    text: "Disabled (no entities)",
  });
  return [null, null];
}

// Send retained empty payloads to output 2 (MQTT Out) to remove the configs.
topics.forEach((topic) => {
  node.send([null, { topic: topic, payload: "" }]);
});

// Clear the ingest unique-filter so re-enable rediscovers cleanly.
global.set("uniqueMicroair", []);

node.status({
  fill: "red",
  shape: "dot",
  text: `Disabled — removed ${topics.length} entities`,
});

return [null, null];

// Output 1: derived availability status (-> "MQTT out: Retain TRUE")
// Output 2: Victron keepalive (-> "Victron out")
const victronEnabled = global.get("victronEnabled");
if (!victronEnabled) return null;

// --- Keepalive (output 2) ---
const portalId = global.get("victronPortalId", "file");
let keepaliveMsg = null;
if (portalId) {
    keepaliveMsg = {
        topic: `R/${portalId}/keepalive`,
        payload: { "keepalive-options": ["suppress-republish"] },
    };
}

// --- Availability watchdog (output 1) ---
// Venus OS publishes no online/offline topic, so derive one from data freshness.
// victron_decode_mqtt stamps victronLastSeen on every inbound N/+/# message.
// STALE_MS spans ~3 keepalive cycles so a single missed publish won't flap.
const STALE_MS = 90000;
const lastSeen = global.get("victronLastSeen") || 0;
const fresh = lastSeen > 0 && Date.now() - lastSeen < STALE_MS;
const desired = fresh ? "online" : "offline";

let statusMsg = null;
if (desired !== context.get("victronStatusPublished")) {
    context.set("victronStatusPublished", desired);
    statusMsg = {
        topic: "librecoach/victron/status",
        payload: desired,
        retain: true,
    };
}

return [statusMsg, keepaliveMsg];

