// === AQUAHOT_THERMOSTAT_STATUS_2 (FF01) ===
// Provides current zone temperature
if (dgn_name === "AQUAHOT_THERMOSTAT_STATUS_2") {
  const z = p.zone_index + 1; // 00=Zone 1, 01=Zone 2

  if (typeof p.zone_temperature === "number") {
    // Create Climate Entity and publish current temperature
    publishClimate(
      `aquahot_zone_${z}`,
      undefined, // Mode handled by FF2F
      p.zone_temperature, // Current temp
      undefined, // Action handled by FF2F
      () => climateConfig(`aquahot_zone_${z}`, `Zone ${z}`),
    );
  }

  if (typeof p.config_byte === "number") {
    publishSensor(`aquahot_zone_${z}_config`, toHex(p.config_byte), () =>
      sensorConfig(
        `aquahot_zone_${z}_config`,
        `Zone ${z} Config`,
        null,
        null,
        null,
        "mdi:cog",
      ),
    );
  }
}

// === AQUAHOT_COMMAND_2 (FF2F) ===
// Event-driven commands from 0x9E. Not periodic — only sent on state changes.
else if (dgn_name === "AQUAHOT_COMMAND_2") {
  if (p.command_type === 0x07 && typeof p.quiet_mode_on === "boolean") {
    // Quiet Mode on/off
    publishSwitch(
      "aquahot_quiet_mode",
      onOff(p.quiet_mode_on),
      () => switchConfig(
        "aquahot_quiet_mode",
        "Quiet Mode",
        "mdi:volume-off",
        "homeassistant/switch/aquahot_quiet_mode/set",
      ),
    );
  } else if (p.command_type === 0x0a && typeof p.interior_heating_on === "boolean") {
    // Interior Heating Priority on/off
    publishSwitch(
      "aquahot_interior_heating",
      onOff(p.interior_heating_on),
      () => switchConfig(
        "aquahot_interior_heating",
        "Interior Heating Priority",
        "mdi:home-thermometer",
        "homeassistant/switch/aquahot_interior_heating/set",
      ),
    );
  }
}

// === WATERHEATER_STATUS_2 (1FE99) — AquaHot zone active flags ===
// On AquaHot systems, byte 2 bits 0 and 2 encode per-zone active state.
// VALIDATED: C0=none, C1=zone_0, C4=zone_1, C5=both (from recordings)
// Route WATERHEATER_STATUS_2 to this node in addition to the standard decoder.
else if (dgn_name === "WATERHEATER_STATUS_2") {
  if (Array.isArray(p.zone_active)) {
    for (let i = 0; i < p.zone_active.length; i++) {
      const active = p.zone_active[i];
      if (typeof active !== "boolean") continue;
      const z = i + 1;
      const mode = active ? "HEAT" : "OFF";
      publishClimate(`aquahot_zone_${z}`, mode, undefined, active, () =>
        climateConfig(`aquahot_zone_${z}`, `Zone ${z}`),
      );
    }
    // Store per-zone active state for downstream use
    if (typeof p.zone_active[0] === "boolean") {
      flow.set("aquahot_zone_front_active", p.zone_active[0]);
    }
    if (typeof p.zone_active[1] === "boolean") {
      flow.set("aquahot_zone_floor_active", p.zone_active[1]);
    }
  }
}

// === AQUAHOT_STATUS_2 (6C00) ===
else if (dgn_name === "AQUAHOT_STATUS_2") {
  const nn = toHex(p.sub_index).substring(2);
  if (p.value_a !== undefined && p.value_a !== null) {
    publishSensor(`aquahot_status_2_sub_${nn}`, p.value_a, () =>
      sensorConfig(
        `aquahot_status_2_sub_${nn}`,
        `Status Sub ${nn}`,
        null,
        null,
        null,
        "mdi:information",
      ),
    );
  }
}

// === AQUAHOT_SYSTEM_STATUS_2 (FF2E) ===
else if (dgn_name === "AQUAHOT_SYSTEM_STATUS_2") {
  const nn = toHex(p.sub_index).substring(2);

  if (p.primary_value !== undefined && p.primary_value !== null) {
    publishSensor(`aquahot_sys_status_sub_${nn}`, p.primary_value, () =>
      sensorConfig(
        `aquahot_sys_status_sub_${nn}`,
        `System Status Sub ${nn}`,
        null,
        null,
        null,
        "mdi:information",
      ),
    );
  }
}

if (messages.length === 0) {
  return null;
}

return [messages];

// HA Status Publisher for THERMOSTAT_AMBIENT_STATUS (1FF9C)
// Self-creating: publishes MQTT discovery on first valid reading per zone instance.

if (!msg.payload || typeof msg.payload !== "object") {
  node.warn("Invalid payload: expected object");
  return null;
}

const p = msg.payload;
const instance = p.instance;
const temperature = p.ambient_temperature;

if (typeof instance !== "number") {
  node.warn("Missing 'instance'");
  return null;
}

if (temperature === null || temperature === "Out of Range") {
  return null;
}

if (typeof temperature !== "number") {
  return null;
}

// === Deadband filter: suppress updates smaller than 0.5°F ===

const LAST_TEMP_KEY = "thermostatAmbientLastTemp";
const lastTemp = flow.get(LAST_TEMP_KEY) || {};
const DEADBAND = 0.2;

if (
  lastTemp[instance] !== undefined &&
  Math.abs(temperature - lastTemp[instance]) < DEADBAND
) {
  return null;
}
lastTemp[instance] = temperature;
flow.set(LAST_TEMP_KEY, lastTemp);

// === Entity identifiers ===

const entityId = `thermostat_ambient_zone${instance}`;
const stateTopic = `homeassistant/sensor/${entityId}/state`;

// === Flow context: track which zones have had discovery published ===

const CREATED_KEY = "thermostatAmbientCreated";
const created = flow.get(CREATED_KEY) || {};

const messages = [];

if (!created[instance]) {
  messages.push({
    topic: `homeassistant/sensor/${entityId}/config`,
    payload: {
      name: `Zone ${instance + 1} Ambient Temperature`,
      unique_id: entityId,
      default_entity_id: `sensor.${entityId}`,
      icon: "mdi:thermometer",
      state_topic: stateTopic,
      device_class: "temperature",
      state_class: "measurement",
      unit_of_measurement: "°F",
      availability_mode: "all",
      availability: [
        { topic: "librecoach/nodered/status", payload_available: "online", payload_not_available: "offline" },
        { topic: "can/status", value_template: "{{ 'online' if value == 'online' else 'offline' }}", payload_available: "online", payload_not_available: "offline" },
      ],
      device: {
        identifiers: ["librecoach-climate"],
        name: "Climate",
        manufacturer: "LibreCoach",
      },
    },
  });
  created[instance] = true;
  flow.set(CREATED_KEY, created);
}

messages.push({ topic: stateTopic, payload: temperature });

return [messages];

// Reconciles the Victron GX broker connection to the desired enabled state.
//
// Output 1 -> Victron out  (GX broker connect/disconnect control)
// Output 2 -> MQTT Out      (entity deletion on disable)
// Output 3 -> Filter nodes  (reset on enable)

const enabled = global.get("victronEnabled") === true;
const wasEnabled = context.get("reconciledEnabled");

if (enabled) {
  node.status({ fill: "green", shape: "dot", text: "Enabled" });
  // Reset the ingest filters only on a real disabled -> enabled transition.
  const resetMsg = wasEnabled === true ? null : { reset: true };
  context.set("reconciledEnabled", true);
  // connect is idempotent: node-red ignores it when already connected/connecting.
  return [{ action: "connect" }, null, resetMsg];
}

// === Disabled ===
context.set("reconciledEnabled", false);

// Disconnect only on a real enabled -> disabled transition.
if (wasEnabled === true) {
  node.send([{ action: "disconnect" }, null, null]);
}

// Remove any HA entities still advertised for Victron.
const index = global.get("discoveryIndex", "file") || {};
const topics = index.victron || [];

if (topics.length === 0) {
  node.status({ fill: "yellow", shape: "ring", text: "Disabled" });
  return [null, null, null];
}

// Send retained empty payloads to output 2 (MQTT Out) to remove the configs.
topics.forEach((topic) => {
  node.send([null, { topic: topic, payload: "" }, null]);
});

// Clear discovery state so a future enable rediscovers and republishes cleanly.
global.set("uniqueVictron", []);
const keys = global.keys ? global.keys("file") : [];
for (const k of keys) {
  if (k.startsWith("victron_") && k.endsWith("_dsig"))
    global.set(k, undefined, "file");
}

node.status({
  fill: "red",
  text: `Disabled — removed ${topics.length} entities`,
});

return [null, null, null];

// HA Status Publisher for DC Dimmer (STATUS_3 1FEDAh §6.23.6 + STATUS_1 1FFBBh §6.23.3)
// Self-creating: publishes MQTT discovery on first valid reading per instance.
// Output 1: MQTT messages (discovery + state)
// Entity naming: switch_N (routing key "switch"), "Switches" device.

if (!msg.payload || typeof msg.payload !== "object") {
  return null;
}

const p = msg.payload;
const instance = p.instance;

if (typeof instance !== "number" || instance < 1 || instance > 250) {
  return null;
}

// Track instances that report real dimmer status so command-inferred fallback
// can be disabled for those lights after the first acknowledgement.
const statusBackedInstances =
  global.get("dcDimmerStatusBackedInstances", "file") || [];
if (!statusBackedInstances.includes(instance)) {
  statusBackedInstances.push(instance);
  global.set("dcDimmerStatusBackedInstances", statusBackedInstances, "file");
}

// Dimmable detection
const dimmableLights = global.get("dimmableLights", "file") || [];
let isDimmable = dimmableLights.includes(instance);

function markDimmable() {
  if (!isDimmable) {
    dimmableLights.push(instance);
    global.set("dimmableLights", dimmableLights, "file");
    isDimmable = true;
  }
}

let haStatus;
let brightness;

if (p.master_brightness !== undefined) {
  // STATUS_1 message: has master_brightness (0-100%)
  brightness = p.master_brightness;
  haStatus = brightness > 0 ? "ON" : "OFF";

  if (brightness > 0 && brightness < 100) {
    markDimmable();
  }
} else if (typeof p.load_status === "string") {
  // STATUS_3 message: has load_status and operating_status
  haStatus = p.load_status.includes("Off") ? "OFF" : "ON";

  const opStatus = p.operating_status;

  if (opStatus === "Value Changing (Ramp)") {
    markDimmable();
  } else if (typeof opStatus === "number" && opStatus > 0 && opStatus < 100) {
    markDimmable();
  }

  if (isDimmable && typeof opStatus === "number") {
    brightness = opStatus;
  }
} else {
  return null;
}

const entityId = `switch_${instance}`;
const stateTopic = `homeassistant/light/${entityId}/state`;
const commandTopic = `homeassistant/light/${entityId}/set`;

const messages = [];

// Self-creating discovery. The capability (onoff vs brightness) is discovered
// at runtime, and HA won't hot-swap supported_color_modes on an existing entity
// (a later discovery claiming ["brightness"] is silently ignored). So an
// onoff -> brightness change requires a delete-then-recreate.
//
// The published capability is persisted per instance in the FILE store so it
// survives Node-RED restarts: this block then runs only on a genuine capability
// change, never on every boot, so a normal restart touches nothing in HA (the
// retained config already in the broker is correct). Shared with the command
// path (dcDimmerCmdCreated -> same key) so the two never fight over switch_N.
//
// Dimmability is monotonic: a light only ever proves it CAN dim — absence of a
// dim reading is not proof it can't — so we never downgrade brightness -> onoff.
// This also neutralizes the dimmableLights file-store load race at startup,
// where the first message can briefly read isDimmable === false.
const PUBLISHED_KEY = "dcDimmerPublishedMode";
const publishedModes = global.get(PUBLISHED_KEY, "file") || {};
const priorMode = publishedModes[instance];
const desiredMode =
  isDimmable || priorMode === "brightness" ? "brightness" : "onoff";

// Keep isDimmable aligned with the capability we will actually publish so the
// state payload below advertises the matching color_mode.
if (desiredMode === "brightness") {
  isDimmable = true;
}

if (priorMode !== desiredMode) {
  // Remove any existing retained config first, then republish so HA recreates
  // the entity fresh with the new capability. Unconditional within this block:
  // it heals an already-registered entity stuck on the wrong mode (priorMode
  // may be undefined on the first deploy even though HA has a stale entity).
  // Removing a non-existent/unretained config is a harmless no-op.
  messages.push({
    topic: `homeassistant/light/${entityId}/config`,
    payload: "",
  });

  const config = {
    name: `Switch ${instance}`,
    unique_id: entityId,
    default_entity_id: `light.${entityId}`,
    icon: "mdi:light-recessed",
    schema: "json",
    command_topic: commandTopic,
    state_topic: stateTopic,
    availability_mode: "all",
    availability: [
      {
        topic: "librecoach/nodered/status",
        payload_available: "online",
        payload_not_available: "offline",
      },
      {
        topic: "can/status",
        value_template: "{{ 'online' if value == 'online' else 'offline' }}",
        payload_available: "online",
        payload_not_available: "offline",
      },
    ],
    device: {
      identifiers: ["librecoach-switches"],
      name: "Switches",
      manufacturer: "LibreCoach",
    },
  };

  if (isDimmable) {
    config.brightness = true;
    config.brightness_scale = 100;
    config.supported_color_modes = ["brightness"];
  } else {
    config.supported_color_modes = ["onoff"];
  }

  messages.push({
    topic: `homeassistant/light/${entityId}/config`,
    payload: config,
  });

  publishedModes[instance] = desiredMode;
  global.set(PUBLISHED_KEY, publishedModes, "file");
}

// Store last brightness for dimmable recall on toggle
if (isDimmable && typeof brightness === "number" && brightness > 0) {
  global.set("dimmerBrightness_" + instance, brightness, "file");
}

// Build JSON state payload
const stateObj = { state: haStatus };

if (haStatus === "ON") {
  if (isDimmable) {
    stateObj.color_mode = "brightness";
    if (brightness !== undefined) {
      stateObj.brightness = brightness;
    }
  } else {
    stateObj.color_mode = "onoff";
  }
}

messages.push({
  topic: stateTopic,
  payload: JSON.stringify(stateObj),
});

return [messages];

// DC Dimmer Decoder
// Decodes DC_DIMMER_STATUS_1/2/3 messages (1FFBB, 1FFBA, 1FEDA)

// --- Helper Functions ---

function decodeBits(value, startBit, endBit) {
  const mask = ((1 << (endBit - startBit + 1)) - 1) << startBit;
  return (value & mask) >> startBit;
}

// --- DC_DIMMER_STATUS Specific Decoders ---

function decodeDimmerInstance(value) {
  // Dimmer instance interpretation
  if (value === 0) {
    return "Invalid";
  } else if (value <= 250) {
    return value; // Direct instance number
  } else if (value === 251) {
    return "Error";
  } else if (value === 252) {
    return "Not Supported";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

function decodeBrightnessLevel(value) {
  // Brightness level (0-200% per Table 5.3)
  if (value <= 200) {
    return parseFloat((value * 0.5).toFixed(1)); // 0.5% per step, 0-100%
  } else if (value === 251) {
    return "Value Changing (Ramp)";
  } else if (value === 252) {
    return "Output Flashing";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

function decodeDCCurrent(value) {
  // DC Current per Table 5.3 (0.05A resolution for small currents)
  if (value <= 250) {
    return parseFloat((value * 0.05).toFixed(2)); // 0.05A per step
  } else if (value === 251) {
    return "Error";
  } else if (value === 252) {
    return "Not Supported";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

function decodeChannelFault(value) {
  // Channel fault status (2-bit field)
  const faultStates = {
    0: "No Fault",
    1: "Undercurrent (Open Circuit)",
    2: "Overcurrent",
    3: "Reserved",
  };
  return faultStates[value] || "Unknown";
}

function decodeFaultByte(value) {
  // Decode fault bits from byte 5 (STATUS_2)
  const masterFault = decodeBits(value, 0, 1);
  const redFault = decodeBits(value, 2, 3);
  const greenFault = decodeBits(value, 4, 5);
  const blueFault = decodeBits(value, 6, 7);

  const faults = [];
  if (masterFault > 0)
    faults.push(`Master: ${decodeChannelFault(masterFault)}`);
  if (redFault > 0) faults.push(`Red: ${decodeChannelFault(redFault)}`);
  if (greenFault > 0) faults.push(`Green: ${decodeChannelFault(greenFault)}`);
  if (blueFault > 0) faults.push(`Blue: ${decodeChannelFault(blueFault)}`);

  return {
    fault_summary: faults.length > 0 ? faults.join(", ") : "No Faults",
    master_fault: decodeChannelFault(masterFault),
    red_fault: decodeChannelFault(redFault),
    green_fault: decodeChannelFault(greenFault),
    blue_fault: decodeChannelFault(blueFault),
    any_fault: faults.length > 0,
  };
}

function decodeGroupBitmap(value) {
  // Group membership bitmap (7 groups max)
  if (value === 0) {
    return "All Groups";
  } else if (value === 255) {
    return "No Data";
  }

  const groups = [];
  for (let i = 1; i <= 7; i++) {
    const groupBit = 1 << i;
    if (!(value & groupBit)) {
      // Inverted logic - 0 means member
      groups.push(i);
    }
  }

  return groups.length > 0 ? `Groups: ${groups.join(", ")}` : "No Groups";
}

function decodeOperatingStatus(value) {
  // Operating status for STATUS_3
  if (value <= 200) {
    return parseFloat((value * 0.5).toFixed(1)); // 0.5% per step
  } else if (value === 251) {
    return "Value Changing (Ramp)";
  } else if (value === 252) {
    return "Output Flashing";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

function decodeStatus3Byte3(value) {
  // Decode status bits from byte 3 (STATUS_3)
  const lockStatus = decodeBits(value, 0, 1);
  const overcurrentStatus = decodeBits(value, 2, 3);
  const overrideStatus = decodeBits(value, 4, 5);
  const enableStatus = decodeBits(value, 6, 7);

  const lockStates = ["Unlocked", "Locked", "Reserved", "Not Supported"];
  const statusStates = [
    "Normal/Inactive",
    "Active/Abnormal",
    "Reserved",
    "Not Supported",
  ];
  const enableStates = ["Enabled", "Disabled", "Reserved", "Not Supported"];

  return {
    lock_status: lockStates[lockStatus] || "Unknown",
    overcurrent_status: statusStates[overcurrentStatus] || "Unknown",
    override_status: statusStates[overrideStatus] || "Unknown",
    enable_status: enableStates[enableStatus] || "Unknown",
  };
}

function decodeLastCommand(value) {
  // Last executed command (STATUS_3)
  const commands = {
    0: "Set Brightness",
    1: "ON",
    2: "ON Delay",
    3: "OFF",
    4: "Stop",
    5: "Toggle",
    6: "Memory OFF",
    7: "Save Scene",
    11: "Ramp Brightness",
    12: "Ramp Toggle",
    13: "Ramp Up",
    14: "Ramp Down",
    15: "Ramp Up/Down",
    16: "Ramp Up/Down Toggle",
    21: "Lock",
    22: "Unlock",
    31: "Flash",
    32: "Flash Momentary",
    33: "Flash Pattern",
    34: "Scene Recall",
    35: "Scene Store",
    36: "Group Command",
    37: "Reset",
    38: "Factory Reset",
    39: "Calibrate",
    40: "Test Mode",
    251: "Error",
    252: "Not Supported",
    253: "Out of Range",
    254: "Reserved",
    255: "Not Available",
  };

  return commands[value] || `Unknown Command ${value}`;
}

function decodeDelayDuration(value) {
  // Delay/Duration field (STATUS_3)
  if (value === 0) {
    return "Expired";
  } else if (value <= 240) {
    return `${value} seconds`;
  } else if (value >= 241 && value <= 250) {
    return `${value - 236} minutes`; // 241-250 = 5-14 minutes
  } else if (value === 252) {
    return "Flashing";
  } else if (value === 253) {
    return ">240 seconds";
  } else if (value === 255) {
    return "No delay active";
  }
  return "Invalid";
}

function decodeStatus3Byte6(value) {
  // Decode status bits from byte 6 (STATUS_3)
  const interlockStatus = decodeBits(value, 0, 1);
  const loadStatus = decodeBits(value, 2, 3);
  const undercurrentStatus = decodeBits(value, 6, 7);

  const interlockStates = ["Not Active", "Active", "Reserved", "Not Supported"];
  const loadStates = [
    "Off (status=0)",
    "On (status>0 or flashing)",
    "Reserved",
    "Reserved",
  ];
  const undercurrentStates = [
    "Normal",
    "Active",
    "Timeout Error",
    "Not Supported",
  ];

  return {
    interlock_status: interlockStates[interlockStatus] || "Unknown",
    load_status: loadStates[loadStatus] || "Unknown",
    undercurrent_status: undercurrentStates[undercurrentStatus] || "Unknown",
  };
}

// --- Main Decode Function ---

function decodeDCDimmerMessage(dgn, data) {
  // Map DGN hex codes to specific names for unified routing
  let dgn_name = "DC_DIMMER_STATUS"; // fallback
  const dgnHex = dgn.toUpperCase();
  if (dgnHex === "1FFBB") {
    dgn_name = "DC_DIMMER_STATUS_1";
  } else if (dgnHex === "1FFBA") {
    dgn_name = "DC_DIMMER_STATUS_2";
  } else if (dgnHex === "1FEDA") {
    dgn_name = "DC_DIMMER_STATUS_3";
  }

  const result = {
    dgn: dgn,
    dgn_name: dgn_name,
  };

  // Determine which STATUS message based on DGN and decode accordingly

  if (dgnHex === "1FFBB") {
    // DC_DIMMER_STATUS_1 - Brightness levels and timing
    result.status_type = "STATUS_1";

    if (data.length >= 7) {
      result.instance = data[0];
      result.instance_name = decodeDimmerInstance(data[0]);
      result.master_brightness = decodeBrightnessLevel(data[1]);
      result.red_brightness = decodeBrightnessLevel(data[2]);
      result.green_brightness = decodeBrightnessLevel(data[3]);
      result.blue_brightness = decodeBrightnessLevel(data[4]);

      // Byte 5: On/Off Duration (4 bits each)
      result.on_duration = decodeBits(data[5], 0, 3); // 0-14 seconds
      result.off_duration = decodeBits(data[5], 4, 7); // 0-14 seconds

      if (data.length > 6) {
        result.white_brightness = decodeBrightnessLevel(data[6]);
      }
    }
  } else if (dgnHex === "1FFBA") {
    // DC_DIMMER_STATUS_2 - Current measurements and faults
    result.status_type = "STATUS_2";

    if (data.length >= 8) {
      result.instance = data[0];
      result.instance_name = decodeDimmerInstance(data[0]);
      result.red_current = decodeDCCurrent(data[2]);
      result.green_current = decodeDCCurrent(data[3]);
      result.blue_current = decodeDCCurrent(data[4]);

      // Byte 5: Fault bits
      const faultInfo = decodeFaultByte(data[5]);
      Object.assign(result, faultInfo);

      if (data.length > 6) {
        result.white_current = decodeDCCurrent(data[6]);
      }

      if (data.length > 7) {
        // Byte 7: White fault (bits 0-1)
        const whiteFault = decodeBits(data[7], 0, 1);
        result.white_fault = decodeChannelFault(whiteFault);
      }
    }
  } else if (dgnHex === "1FEDA") {
    // DC_DIMMER_STATUS_3 - Comprehensive operational status
    result.status_type = "STATUS_3";

    if (data.length >= 8) {
      result.instance = data[0];
      result.instance_name = decodeDimmerInstance(data[0]);
      result.group_membership = decodeGroupBitmap(data[1]);
      result.operating_status = decodeOperatingStatus(data[2]);

      // Byte 3: Status bits
      const status3Info = decodeStatus3Byte3(data[3]);
      Object.assign(result, status3Info);

      result.delay_duration = decodeDelayDuration(data[4]);
