// Encodes WINDOW_SHADE_COMMAND messages (1FEDF)

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "1FEDF";

// --- Input Validation ---
const instance = msg.instance;
const command = msg.command; // Expects "OPEN", "CLOSE", or "STOP"

if (typeof instance !== "number" || instance < 1 || instance > 250) {
  node.warn(`[encode_shade_command] Invalid instance: ${instance}`);
  return null;
}

// --- Command Mapping ---
let shadeCommand;
let duration = 30; // 30 seconds duration (matches switch panel)

switch (command) {
  case "OPEN":
    shadeCommand = 0x85; // Toggle Forward (Raise/Open)
    break;
  case "CLOSE":
    shadeCommand = 0x45; // Toggle Reverse (Lower/Close)
    break;
  case "STOP":
    shadeCommand = 0x04; // Stop
    duration = 0; // Duration is ignored for STOP
    break;
  default:
    node.warn(
      `[encode_shade_command] Invalid command: "${command}". Expected "OPEN", "CLOSE", or "STOP"`,
    );
    return null;
}

// --- Build Payload ---
const motorDuty = 200; // Use 200% motor duty (matches switch panel)
const dataBytes = new Array(8).fill(0xff);
dataBytes[0] = instance; // Byte 0: Instance Number
dataBytes[1] = 0xff; // Byte 1: Group (Non-group command)
dataBytes[2] = motorDuty; // Byte 2: Motor Duty Cycle
dataBytes[3] = shadeCommand; // Byte 3: Command Code
dataBytes[4] = duration; // Byte 4: Duration
dataBytes[5] = 0x00; // Byte 5: Interlock (No Interlock)
dataBytes[6] = 0xff; // Byte 6: Not Available
dataBytes[7] = 0xff; // Byte 7: Not Available

const dataHex = dataBytes
  .map((byte) => byte.toString(16).padStart(2, "0"))
  .join("");

// Construct the CAN ID
const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// --- Send Message ---
node.send({
  topic: "can/send",
  payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
});

return null;

// Convert Home Assistant Hughes commands to the add-on MQTT command contract.
// Output 1: bridge command. Output 2: optimistic state update.

if (!global.get("hughesEnabled")) return null;

const parts = (msg.topic || "").split("/");
if (parts.length !== 4 || parts[0] !== "homeassistant" || parts[3] !== "set") return null;

const component = parts[1];
const entityId = parts[2];
if (!entityId.startsWith("hughes_")) return null;

let suffix;
if (component === "switch" && entityId.endsWith("_neutral_detection")) {
  suffix = "neutral_detection";
} else if (component === "switch" && entityId.endsWith("_relay")) {
  suffix = "relay";
} else if (component === "button" && entityId.endsWith("_reset_energy")) {
  suffix = "reset_energy";
} else {
  return null;
}

const baseId = entityId.slice(0, -(suffix.length + 1));
const safeMac = baseId.slice("hughes_".length);
const mac = safeMac.replace(/_/g, ":");
const bridgeTopic = `librecoach/ble/hughes/${mac}/set`;

let command;
if (suffix === "reset_energy") {
  command = { command: "reset_energy" };
} else {
  const enabled = msg.payload.toString().toUpperCase() === "ON";
  command = { command: suffix, value: enabled };
}

const bridgeMsg = { topic: bridgeTopic, payload: JSON.stringify(command) };
if (suffix === "reset_energy") return [bridgeMsg, null];

const stateKey = `${baseId}_state`;
const optimistic = { ...(global.get(stateKey, "file") || {}) };
if (!optimistic.protocol) return [bridgeMsg, null];
if (suffix === "relay") optimistic.relay_status = command.value ? 0 : 1;
if (suffix === "neutral_detection") optimistic.neutral_detection = command.value ? 0 : 1;
global.set(stateKey, optimistic, "file");

return [
  bridgeMsg,
  { topic: `librecoach/ble/hughes/${mac}/state`, payload: JSON.stringify(optimistic) },
];

// Status Updater for Air Conditioner
// Decodes AIR_CONDITIONER_STATUS messages (1FFE1)

// === Helper Functions ===

function decodeOperatingMode(value) {
  // Operating mode mapping
  const modes = {
    0: "Automatic",
    1: "Manual",
    255: "Not Available",
  };
  return modes[value] || `Unknown (${value})`;
}

function decodePercentage(value) {
  // Percentage decoding: 0.5% per count, range 0-100%
  if (value <= 200) {
    return parseFloat((value * 0.5).toFixed(1));
  } else if (value === 251) {
    return "Error";
  } else if (value === 252) {
    return "Not Supported";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

function decodeDeadband(value) {
  // Dead band: 0.1°C precision, range 0-25.0°C
  if (value <= 250) {
    return parseFloat((value * 0.1).toFixed(1));
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

function decodeInstance(value) {
  // Instance decoding per Table 5.3
  if (value === 0) {
    return 0; // All instances / Auto fan speed
  } else if (value >= 1 && value <= 250) {
    return value;
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

// === Main Decode Function ===

function decodeAirConditionerStatusMessage(dgn, data) {
  const result = {
    dgn: dgn,
    dgn_name: "AIR_CONDITIONER_STATUS",
  };

  if (data.length < 6) {
    result.error = "Data payload too short (expected at least 6 bytes)";
    return result;
  }

  // Byte 0: Instance (Zone)
  result.instance = decodeInstance(data[0]);
  if (typeof result.instance === "number") {
    result.instance_description =
      result.instance === 0 ? "All zones" : `Zone ${result.instance}`;
  } else {
    result.instance_description = result.instance;
  }

  // Byte 1: Operating Mode
  result.operating_mode = decodeOperatingMode(data[1]);
  result.is_automatic = data[1] === 0;
  result.is_manual = data[1] === 1;

  // Byte 2: Max Fan Speed (%)
  result.max_fan_speed = decodePercentage(data[2]);
  result.max_fan_speed_limited =
    typeof result.max_fan_speed === "number" && result.max_fan_speed < 100;

  // Byte 3: Max AC Output Level (%)
  result.max_ac_output_level = decodePercentage(data[3]);
  result.max_output_limited =
    typeof result.max_ac_output_level === "number" &&
    result.max_ac_output_level < 100;

  // Byte 4: Fan Speed (%)
  result.fan_speed = decodePercentage(data[4]);
  result.fan_running =
    typeof result.fan_speed === "number" && result.fan_speed > 0;

  // Byte 5: AC Output Level (%)
  result.ac_output_level = decodePercentage(data[5]);
  result.compressor_running =
    typeof result.ac_output_level === "number" && result.ac_output_level > 0;

  // Byte 6: Dead Band (optional)
  if (data.length >= 7) {
    result.dead_band = decodeDeadband(data[6]);
    result.dead_band_unit = "°C";
  }

  // Byte 7: Second Stage Dead Band (optional)
  if (data.length >= 8) {
    result.second_stage_dead_band = decodeDeadband(data[7]);
    result.second_stage_dead_band_unit = "°C";
  }

  // Convenience fields
  result.ac_active = result.compressor_running;
  result.status = result.compressor_running
    ? "COOLING"
    : result.fan_running
      ? "FAN ONLY"
      : "OFF";

  // Power sharing status
  result.power_limited =
    result.max_fan_speed_limited || result.max_output_limited;

  // Raw values for debugging
  result.raw_instance = data[0];
  result.raw_operating_mode = data[1];
  result.raw_max_fan_speed = data[2];
  result.raw_max_ac_output_level = data[3];
  result.raw_fan_speed = data[4];
  result.raw_ac_output_level = data[5];
  if (data.length >= 7) result.raw_dead_band = data[6];
  if (data.length >= 8) result.raw_second_stage_dead_band = data[7];

  return result;
}

// === Main Logic ===

// Validate input payload
if (!msg.payload || typeof msg.payload !== "object") {
  node.warn("Invalid payload: expected object");
  return null;
}

const incomingPayload = msg.payload;
const { dgn, data_payload } = incomingPayload;

if (!dgn || !data_payload) {
  node.warn("Missing required fields: dgn and/or data_payload");
  return null;
}

// Validate and convert hex payload to byte array
if (typeof data_payload !== "string" || data_payload.length % 2 !== 0) {
  node.warn("Invalid data_payload: must be even-length hex string");
  return null;
}

const dataBytes = [];
for (let i = 0; i < data_payload.length; i += 2) {
  const hexByte = data_payload.substring(i, i + 2);
  const byteValue = parseInt(hexByte, 16);
  if (isNaN(byteValue)) {
    node.warn(`Invalid hex byte in data_payload: ${hexByte}`);
    return null;
  }
  dataBytes.push(byteValue);
}

// Decode the AIR_CONDITIONER_STATUS message
const decodedData = decodeAirConditionerStatusMessage(dgn, dataBytes);

// Handle decode errors
if (decodedData.error) {
  incomingPayload.decoding_error = decodedData.error;
  msg.payload = incomingPayload;
  return msg;
}

// Merge the incoming payload and the decoded data into a single flat object
msg.payload = {
  ...incomingPayload,
  ...decodedData,
};

// Clean up the final object by removing the raw data field
delete msg.payload.data_payload;

return msg;

// Decodes GO Power GP-RVC-30-MPPT Solar Controller messages
// Handles DGNs: 1FE80, 1FDFF, 1FEB3, 1FE85, 1FE84, 1FE83, 1FE82, 1FE81

// === Helper Functions ===

function decodeUint16LE(data, offset) {
  if (!data || offset + 1 >= data.length) return 65535;
  return data[offset] | (data[offset + 1] << 8);
}

// DC voltage: uint16 LE, 0.05V/bit, 65535=N/A
function decodeDCVoltage(raw) {
  if (raw === 65535 || raw === 65534) return null;
  return parseFloat((raw * 0.05).toFixed(2));
}

// DC current with -1600A offset: uint16 LE, 0.05A/bit
// 32000 = 0A (special zero), values encode as (amps + 1600) / 0.05
function decodeDCCurrentOffset(raw) {
  if (raw === 65535 || raw === 65534) return null;
  return parseFloat((raw * 0.05 - 1600).toFixed(2));
}

// Charging stage byte
function decodeChargingStage(raw) {
  const stages = {
    0: "Off",
    1: "Bulk",
    2: "Absorption",
    3: "Float",
    4: "Equalize",
    5: "Fault",
  };
  return stages[raw] !== undefined ? stages[raw] : `Unknown (${raw})`;
}

// Temperature: uint8, offset -40°C, output °F
function decodeTemp8(raw) {
  if (raw === 255) return null;
  const tempC = raw - 40;
  return parseFloat(((tempC * 9) / 5 + 32).toFixed(1));
}

// === Main Decode ===

if (!msg.payload || typeof msg.payload !== "object") {
  node.warn("Invalid payload");
  return null;
}

const incomingPayload = msg.payload;
const { dgn, dgn_name, data_payload } = incomingPayload;

if (!dgn || !data_payload) {
  node.warn("Missing dgn or data_payload");
  return null;
}

if (typeof data_payload !== "string" || data_payload.length % 2 !== 0) {
  node.warn("Invalid data_payload");
  return null;
}

const d = data_payload.match(/.{1,2}/g).map((b) => parseInt(b, 16));
if (d.some(isNaN) || d.length < 8) {
  node.warn("Invalid hex bytes or insufficient length");
  return null;
}

const result = {
  dgn,
  dgn_name,
  instance: d[0],
};

const dgnUpper = dgn.toUpperCase();

if (dgnUpper === "1FE80") {
  // SOLAR_CONTROLLER_BATTERY_STATUS
  // byte[1]: charging stage
  // bytes[3:4]: battery voltage uint16 LE, 0.05V/bit
  // bytes[5:6]: battery current uint16 LE, 0.05A/bit with -1600A offset
  // byte[7]: battery temperature uint8, offset -40°C
  result.charging_stage = decodeChargingStage(d[1]);
  result.raw_charging_stage = d[1];
  const vRaw = decodeUint16LE(d, 3);
  result.battery_voltage = decodeDCVoltage(vRaw);
  result.raw_battery_voltage = vRaw;
  const iRaw = decodeUint16LE(d, 5);
  result.battery_current = decodeDCCurrentOffset(iRaw);
  result.raw_battery_current = iRaw;
  result.battery_temperature = decodeTemp8(d[7]);

  // Convenience
  result.is_charging = typeof result.battery_current === "number" && result.battery_current > 0.1;
  result.charging_active = result.charging_stage !== "Off" && result.charging_stage !== "Fault";

  // Calculated watts
  if (typeof result.battery_voltage === "number" && typeof result.battery_current === "number") {
    result.battery_watts = parseFloat((result.battery_voltage * result.battery_current).toFixed(1));
  }

} else if (dgnUpper === "1FDFF") {
  // SOLAR_CONTROLLER_SOLAR_ARRAY_STATUS
  // bytes[1:2]: panel voltage uint16 LE, 0.05V/bit
  // bytes[3:4]: panel current uint16 LE, 0.05A/bit with -1600A offset
  const pvRaw = decodeUint16LE(d, 1);
  result.panel_voltage = decodeDCVoltage(pvRaw);
  result.raw_panel_voltage = pvRaw;
  const piRaw = decodeUint16LE(d, 3);
  result.panel_current = decodeDCCurrentOffset(piRaw);
  result.raw_panel_current = piRaw;

  // Calculated panel watts
  if (typeof result.panel_voltage === "number" && typeof result.panel_current === "number") {
    result.panel_watts = parseFloat((result.panel_voltage * result.panel_current).toFixed(1));
  }

  result.panels_active = typeof result.panel_voltage === "number" && result.panel_voltage > 5;

} else if (dgnUpper === "1FE81") {
  // SOLAR_CONTROLLER_STATUS_6 — charge setpoints
  // bytes[1:2]: absorption voltage setpoint
  // bytes[3:4]: float voltage setpoint
  const absRaw = decodeUint16LE(d, 1);
  result.absorption_setpoint = decodeDCVoltage(absRaw);
  result.raw_absorption_setpoint = absRaw;
  const floatRaw = decodeUint16LE(d, 3);
  result.float_setpoint = decodeDCVoltage(floatRaw);
  result.raw_float_setpoint = floatRaw;

} else if (dgnUpper === "1FEB3") {
  // SOLAR_CONTROLLER_STATUS_1 — basic status
  result.raw_byte1 = d[1];
  result.raw_byte2 = d[2];
  result.raw_byte5 = d[5];
  result.raw_byte6 = d[6];
  result.raw_byte7 = d[7];

} else if (dgnUpper === "1FE85") {
  // SOLAR_CONTROLLER_STATUS_2
  const v2Raw = decodeUint16LE(d, 1);
  result.output_voltage = decodeDCVoltage(v2Raw);
  result.raw_output_voltage = v2Raw;
  const i2Raw = decodeUint16LE(d, 3);
  result.output_current = decodeDCCurrentOffset(i2Raw);
  result.raw_output_current = i2Raw;

} else if (dgnUpper === "1FE84") {
  // SOLAR_CONTROLLER_STATUS_3
  const v3Raw = decodeUint16LE(d, 1);
  result.voltage_3 = decodeDCVoltage(v3Raw);
  result.raw_voltage_3 = v3Raw;

} else if (dgnUpper === "1FE83") {
  // SOLAR_CONTROLLER_STATUS_4
  result.raw_byte1 = d[1];
  result.raw_byte2 = d[2];
  result.raw_byte3 = d[3];
  result.raw_byte4 = d[4];
  result.raw_byte5 = d[5];

} else if (dgnUpper === "1FE82") {
  // SOLAR_CONTROLLER_STATUS_5
  result.raw_byte1 = d[1];
  result.raw_byte2 = d[2];
  result.raw_byte3 = d[3];
  result.raw_byte4 = d[4];

} else {
  node.warn(`Unhandled solar DGN: ${dgn}`);
  return null;
}

msg.payload = { ...incomingPayload, ...result };
delete msg.payload.data_payload;

return msg;

// Combined decoder for WATERHEATER_STATUS (1FFF7) and WATERHEATER_STATUS_2 (1FE99)
// RV-C spec 6.9.2 and 6.9.4

// === Helper Functions ===

function decodeBits(value, startBit, endBit) {
  const mask = ((1 << (endBit - startBit + 1)) - 1) << startBit;
  return (value & mask) >> startBit;
}

function decodeUint16(data, startByte) {
  return data[startByte] | (data[startByte + 1] << 8);
}

// Decodes a standard RV-C temperature value (uint16).
// Uses 0.03125°C resolution (per RVC spec) with -273.15°C offset (Kelvin).
function decodeTemperature(value, isCelsius = false) {
  if (value <= 65530) {
    const tempK = value * 0.03125; // Kelvin
    const tempC = tempK - 273.15; // Convert to Celsius

    if (isCelsius) {
      return parseFloat(tempC.toFixed(1));
    } else {
      // Convert to Fahrenheit: F = C * 9/5 + 32
      return parseFloat(((tempC * 9) / 5 + 32).toFixed(1));
    }
  } else if (value === 65533) {
    return "Out of Range";
  } else if (value === 65534) {
    return "Reserved";
  } else if (value === 65535) {
    return "Not Available";
  }
  return "Invalid";
}

function decodeEnginePreheat(value) {
  // Engine preheat status mapping
  const statuses = {
    0: "Off",
    1: "On",
    5: "Test (Forced On)",
  };
  return statuses[value] || `Unknown (${value})`;
}

function decode2BitOnOff(value) {
  // Generic 2-bit on/off status
  const statuses = {
    0: "Off",
    1: "On",
    2: "Reserved",
    3: "Not Available",
  };
  return statuses[value] || `Unknown (${value})`;
}

function decode2BitWarning(value) {
  // Generic 2-bit warning status
  const statuses = {
    0: "OK",
    1: "Warning",
    2: "Reserved",
    3: "Not Available",
  };
  return statuses[value] || `Unknown (${value})`;
}

function decodeCoolantLevel(value) {
  const statuses = {
    0: "Sufficient",
    1: "Low",
    2: "Reserved",
    3: "Not Available",
  };
  return statuses[value] || `Unknown (${value})`;
}

function decodeHotWaterPriority(value) {
  const priorities = {
    0: "Domestic Water",
    1: "Heating",
    2: "Reserved",
    3: "Not Available",
  };
  return priorities[value] || `Unknown (${value})`;
}

// === WATERHEATER_STATUS (1FFF7) — §6.9.2 ===

function decodeOperatingMode(value) {
  const modes = {
    0: "Off",
    1: "Combustion",
    2: "Electric",
    3: "Gas+Electric",
    4: "Auto",
    5: "Test Combustion",
    6: "Test Electric",
  };
  return modes[value] || `Unknown (${value})`;
}

function decodeStatus(data, result) {
  // Byte 1: Operating Mode
  result.operating_mode = decodeOperatingMode(data[1]);
  result.raw_operating_mode = data[1];

  // Bytes 2-3: Setpoint Temp
  const setpointRaw = decodeUint16(data, 2);
  result.setpoint_temperature = decodeTemperature(setpointRaw);
  result.raw_setpoint_temperature = setpointRaw;

  // Bytes 4-5: Water Temp
  // AquaHot 125D uses raw LE uint16 / 128 = °C (not standard RV-C Kelvin encoding)
  const waterTempRaw = decodeUint16(data, 4);
  const waterTempC = parseFloat((waterTempRaw / 128).toFixed(1));
  result.water_temperature_c = waterTempC;
  result.water_temperature = parseFloat(((waterTempC * 9) / 5 + 32).toFixed(1));
  result.raw_water_temperature = waterTempRaw;

  // Byte 6: Thermostat, Burner, AC Element, High Temp
  const byte6 = data[6];
  const thermostatRaw = decodeBits(byte6, 0, 1);
  result.thermostat_not_met = thermostatRaw === 1;
  result.raw_thermostat_not_met = thermostatRaw;

  const burnerRaw = decodeBits(byte6, 2, 3);
  result.burner_active = burnerRaw === 1;
  result.raw_burner_active = burnerRaw;

  const acElementRaw = decodeBits(byte6, 4, 5);
  result.ac_element_active = acElementRaw === 1;
  result.raw_ac_element_active = acElementRaw;

  const highTempRaw = decodeBits(byte6, 6, 7);
  result.high_temp_tripped = highTempRaw === 1;
  result.raw_high_temp_tripped = highTempRaw;

  // Byte 7: Failures and Warnings
  const byte7 = data[7];
  const igniteFailedRaw = decodeBits(byte7, 0, 1);
  result.ignite_failed = igniteFailedRaw === 1;
  result.raw_ignite_failed = igniteFailedRaw;

  const acPowerRaw = decodeBits(byte7, 2, 3);
  result.ac_power_absent = acPowerRaw === 1;
  result.raw_ac_power_absent = acPowerRaw;

  const dcPowerRaw = decodeBits(byte7, 4, 5);
  result.dc_power_absent = dcPowerRaw === 1;
  result.raw_dc_power_absent = dcPowerRaw;

  const dcPowerWarningRaw = decodeBits(byte7, 6, 7);
  result.dc_power_low = dcPowerWarningRaw === 1;
  result.raw_dc_power_low = dcPowerWarningRaw;

  // Convenience fields
  result.has_fault = result.high_temp_tripped || result.ignite_failed;
  result.any_heat_active = result.burner_active || result.ac_element_active;
}

// === WATERHEATER_STATUS_2 (1FE99) — §6.9.4 ===

function decodeStatus2(data, result) {
  // Byte 1: Electric Element Levels
  const byte1 = data[1];
  result.electric_element_level = byte1 & 0x0f; // Bits 0-3
  result.max_electric_element_level = (byte1 >> 4) & 0x0f; // Bits 4-7

  // Byte 2: Engine Preheat, Coolant Level, Hot Water Priority
  const byte2 = data[2];
  const enginePreheatRaw = byte2 & 0x0f; // Bits 0-3
  result.engine_preheat = decodeEnginePreheat(enginePreheatRaw);
  result.engine_preheat_active =
    enginePreheatRaw === 1 || enginePreheatRaw === 5;

  const coolantLevelRaw = (byte2 >> 4) & 0x03; // Bits 4-5
  result.coolant_level = decodeCoolantLevel(coolantLevelRaw);
  result.coolant_low = coolantLevelRaw === 1;

  const hotWaterPriorityRaw = (byte2 >> 6) & 0x03; // Bits 6-7
  result.hot_water_priority = decodeHotWaterPriority(hotWaterPriorityRaw);

  // Byte 3: Output Statuses
  const byte3 = data[3];
  const burnerOutputRaw = byte3 & 0x03; // Bits 0-1
  result.burner_output = decode2BitOnOff(burnerOutputRaw);
  result.burner_on = burnerOutputRaw === 1;

  const burnerIndicatorRaw = (byte3 >> 2) & 0x03; // Bits 2-3
  result.burner_indicator = decode2BitOnOff(burnerIndicatorRaw);

  const electricLowOutputRaw = (byte3 >> 4) & 0x03; // Bits 4-5
  result.electric_low_output = decode2BitOnOff(electricLowOutputRaw);
  result.electric_low_on = electricLowOutputRaw === 1;

  const electricHighOutputRaw = (byte3 >> 6) & 0x03; // Bits 6-7
  result.electric_high_output = decode2BitOnOff(electricHighOutputRaw);
  result.electric_high_on = electricHighOutputRaw === 1;

  // Byte 4: Burner Status Flags
  const byte4 = data[4];
  const burnerOvercurrentRaw = byte4 & 0x03; // Bits 0-1
  result.burner_overcurrent = decode2BitWarning(burnerOvercurrentRaw);

  const burnerUndercurrentRaw = (byte4 >> 2) & 0x03; // Bits 2-3
  result.burner_undercurrent = decode2BitWarning(burnerUndercurrentRaw);

  const burnerTempRaw = (byte4 >> 4) & 0x03; // Bits 4-5
  result.burner_temperature = decode2BitWarning(burnerTempRaw);

  const burnerInputRaw = (byte4 >> 6) & 0x03; // Bits 6-7
  result.burner_input = decode2BitOnOff(burnerInputRaw);

  // Byte 5: Burner Indicator Status Flags
  const byte5 = data[5];
  const burnerIndOvercurrentRaw = byte5 & 0x03; // Bits 0-1
  result.burner_indicator_overcurrent = decode2BitWarning(
    burnerIndOvercurrentRaw,
  );

  const burnerIndUndercurrentRaw = (byte5 >> 2) & 0x03; // Bits 2-3
  result.burner_indicator_undercurrent = decode2BitWarning(
    burnerIndUndercurrentRaw,
  );

  const burnerIndTempRaw = (byte5 >> 4) & 0x03; // Bits 4-5
  result.burner_indicator_temperature = decode2BitWarning(burnerIndTempRaw);

  const burnerIndInputRaw = (byte5 >> 6) & 0x03; // Bits 6-7
  result.burner_indicator_input = decode2BitOnOff(burnerIndInputRaw);

  // Byte 6: Electric Low Element Status Flags
  const byte6 = data[6];
  const elecLowOvercurrentRaw = byte6 & 0x03; // Bits 0-1
  result.electric_low_overcurrent = decode2BitWarning(elecLowOvercurrentRaw);

  const elecLowUndercurrentRaw = (byte6 >> 2) & 0x03; // Bits 2-3
  result.electric_low_undercurrent = decode2BitWarning(elecLowUndercurrentRaw);

  const elecLowTempRaw = (byte6 >> 4) & 0x03; // Bits 4-5
  result.electric_low_temperature = decode2BitWarning(elecLowTempRaw);

  const elecLowInputRaw = (byte6 >> 6) & 0x03; // Bits 6-7
  result.electric_low_input = decode2BitOnOff(elecLowInputRaw);

  // Byte 7: Electric High Element Status Flags
  const byte7 = data[7];
  const elecHighOvercurrentRaw = byte7 & 0x03; // Bits 0-1
  result.electric_high_overcurrent = decode2BitWarning(elecHighOvercurrentRaw);

  const elecHighUndercurrentRaw = (byte7 >> 2) & 0x03; // Bits 2-3
  result.electric_high_undercurrent = decode2BitWarning(
    elecHighUndercurrentRaw,
  );

  const elecHighTempRaw = (byte7 >> 4) & 0x03; // Bits 4-5
  result.electric_high_temperature = decode2BitWarning(elecHighTempRaw);

  const elecHighInputRaw = (byte7 >> 6) & 0x03; // Bits 6-7
  result.electric_high_input = decode2BitOnOff(elecHighInputRaw);

  // === Convenience Fields ===

  // AquaHot-specific: byte 2 bits 0 and 2 encode per-zone active flags
  // On standard RV-C water heaters these bits are engine preheat/coolant/priority
  // VALIDATED: Recordings confirm C0=none, C1=zone_0, C4=zone_1, C5=both
  // Zone numbering is bit-positional (bit 0 → zone 0, bit 2 → zone 1)
  result.zone_active = [
    (byte2 & 0x01) === 1, // zone 0: bit 0
    ((byte2 >> 2) & 0x01) === 1, // zone 1: bit 2
  ];
  result.any_zone_active = result.zone_active[0] || result.zone_active[1];

  // Overall heating status
  result.any_heat_source_on =
    result.burner_on ||
    result.electric_low_on ||
    result.electric_high_on ||
    result.engine_preheat_active;

  // Determine primary status for simple display
  if (result.burner_on && (result.electric_low_on || result.electric_high_on)) {
    result.status = "GAS+ELECTRIC";
  } else if (result.burner_on) {
    result.status = "GAS";
  } else if (result.electric_high_on) {
    result.status = "ELECTRIC HIGH";
  } else if (result.electric_low_on) {
    result.status = "ELECTRIC LOW";
  } else if (result.engine_preheat_active) {
    result.status = "ENGINE PREHEAT";
  } else {
    result.status = "OFF";
  }

  // Fault detection
  result.burner_fault =
    burnerOvercurrentRaw === 1 ||
    burnerUndercurrentRaw === 1 ||
    burnerTempRaw === 1;
  result.electric_low_fault =
    elecLowOvercurrentRaw === 1 ||
    elecLowUndercurrentRaw === 1 ||
    elecLowTempRaw === 1;
  result.electric_high_fault =
    elecHighOvercurrentRaw === 1 ||
    elecHighUndercurrentRaw === 1 ||
    elecHighTempRaw === 1;
  result.has_fault =
    result.burner_fault ||
    result.electric_low_fault ||
    result.electric_high_fault ||
    result.coolant_low;

  // Raw values for debugging
  result.raw_byte1 = data[1];
  result.raw_byte2 = data[2];
  result.raw_byte3 = data[3];
  result.raw_byte4 = data[4];
  result.raw_byte5 = data[5];
  result.raw_byte6 = data[6];
  result.raw_byte7 = data[7];
}

// === Main Decode Function ===

function decodeWaterheaterMessage(dgn, dgn_name, data) {
  const result = {
    dgn: dgn,
    dgn_name: dgn_name,
  };

  if (data.length < 8) {
    result.error = "Data payload too short (expected 8 bytes)";
    return result;
  }

  // Byte 0: Instance
  result.instance = data[0];
  result.raw_instance = data[0];
  if (result.instance === 0) {
    result.instance_description = "All water heaters";
  } else if (result.instance >= 1 && result.instance <= 250) {
    result.instance_description = `Water Heater ${result.instance}`;
  } else {
    result.instance_description = "Invalid";
  }

  if (dgn_name === "WATERHEATER_STATUS") {
    decodeStatus(data, result);
  } else if (dgn_name === "WATERHEATER_STATUS_2") {
    decodeStatus2(data, result);
  } else {
    result.error = `Unhandled WATERHEATER DGN: ${dgn_name}`;
  }

  return result;
}

// === Main Logic ===

// Validate input payload
if (!msg.payload || typeof msg.payload !== "object") {
  node.warn("Invalid payload: expected object");
  return null;
}

const incomingPayload = msg.payload;
const { dgn, dgn_name, data_payload } = incomingPayload;

if (!dgn || !dgn_name || !data_payload) {
  node.warn("Missing required fields: dgn, dgn_name, and/or data_payload");
  return null;
}

// Validate and convert hex payload to byte array
if (typeof data_payload !== "string" || data_payload.length % 2 !== 0) {
  node.warn("Invalid data_payload: must be even-length hex string");
  return null;
}

const dataBytes = [];
for (let i = 0; i < data_payload.length; i += 2) {
  const hexByte = data_payload.substring(i, i + 2);
  const byteValue = parseInt(hexByte, 16);
  if (isNaN(byteValue)) {
    node.warn(`Invalid hex byte in data_payload: ${hexByte}`);
    return null;
  }
  dataBytes.push(byteValue);
}

// Decode the message
const decodedData = decodeWaterheaterMessage(dgn, dgn_name, dataBytes);

// Handle decode errors
if (decodedData.error) {
  incomingPayload.decoding_error = decodedData.error;
  msg.payload = incomingPayload;
  return msg;
}

// Merge the incoming payload and the decoded data into a single flat object
msg.payload = {
  ...incomingPayload,
  ...decodedData,
};

// Clean up the final object by removing the raw data field
delete msg.payload.data_payload;

return msg;

// Status Updater for Aqua-Hot
// Decodes proprietary AQUAHOT status byte into individual status messages

// Maps the bit position to the instance name
const BIT_MAP = {
  0: "burner", // Burner Status (Bit 0)
  2: "ac_1", // AC Element 1 Status (Bit 2)
  3: "ac_2", // AC Element 2 Status (Bit 3)
  6: "engine", // Engine Pre-heat Status (Bit 6)
};

if (!msg.payload || typeof msg.payload !== "object") {
  node.warn("Invalid payload: expected object");
  return null;
}

const data_payload = msg.payload.data_payload;

if (!data_payload || data_payload.length < 4) {
  node.warn("Missing or short data_payload");
  return null;
}

// Extract the status byte (Byte 2 of the data payload)
const statusByte = parseInt(data_payload.substring(2, 4), 16);

let outputMessages = [];

// Decode the individual status bits
for (const bit in BIT_MAP) {
  const bitIndex = Number(bit);
  const instance = BIT_MAP[bitIndex];

  // Check if the bit is set (Bit = 1 for ON)
  const isBitSet = (statusByte >> bitIndex) & 1;
  const status = isBitSet ? "ON" : "OFF";

  // Prepare the message following the standard pattern
  const statusMsg = {
    payload: {
      instance,
      status,
    },
  };

  outputMessages.push(statusMsg);
}

// Send all four status updates simultaneously
return [outputMessages];

// RV-C Address Claim Success Function
// Called after 250ms timer expires - finalizes address claim if no conflict lost
// Reference: RV-C Spec Section 3.3.2 - Source Address Claiming
//
// IMPORTANT: This does NOT send a second ADDRESS_CLAIMED message.
// We already sent ADDRESS_CLAIMED at the start of the process.
// Success = 250ms timer expires without losing a conflict.

// Get the address we were trying to claim when this timer started
const claimedAddress = msg.claiming_address;

if (claimedAddress === undefined || claimedAddress === null) {
  node.error("No address to claim - timer message missing claiming_address");
  return null;
}

// Check if this timer is still valid (claim hasn't been cancelled by monitor)
const claimInProgress = flow.get("claim_in_progress");
if (!claimInProgress) {
  // Claim was cancelled during the 250ms window (we lost a conflict)
  node.warn(
    `Timer expired for address ${claimedAddress}, but claim was cancelled - ignoring`,
  );
  return null;
}

// Verify we're still trying to claim the same address
const currentClaimingAddress = flow.get("claiming_address");
if (currentClaimingAddress !== claimedAddress) {
  node.warn(
    `Timer expired for address ${claimedAddress}, but we're now trying ${currentClaimingAddress} - ignoring stale timer`,
  );
  return null;
}

// SUCCESS! No conflict detected during the 250ms monitoring window
// Store the claimed address to global context
global.set("rvc_source_address", claimedAddress);

// Clear claiming flags
flow.set("claim_in_progress", false);
flow.set("claiming_address", null);
flow.set("our_device_name", null);

//node.warn(`Successfully claimed address ${claimedAddress} (0x${claimedAddress.toString(16).toUpperCase()})`);
//node.warn(`Address stored to global.rvc_source_address: ${claimedAddress}`);

node.log(
  `Successfully claimed address ${claimedAddress} (0x${claimedAddress.toString(16).toUpperCase()})`,
);

// Return msg to trigger downstream polling
return msg;

// Publishes water heater and circulation pump entity states to MQTT state topics.
// Also publishes MQTT discovery configs the first time a valid value is received.

if (!msg.payload || typeof msg.payload !== "object") {
  node.warn("Invalid payload: expected object");
  return null;
}

const p = msg.payload;
const dgn_name = p.dgn_name;
const i = p.instance !== undefined ? p.instance : "";
const i_name = i !== "" ? ` ${i}` : "";
const messages = [];

// === Device definition ===

const device = {
  identifiers: ["librecoach-waterheater"],
  name: "Water Heater",
  manufacturer: "LibreCoach",
};

const aquahotDevice = {
  identifiers: ["librecoach-aquahot"],
  name: "Aqua-Hot",
  manufacturer: "LibreCoach",
};

// === Flow context: tracks which entities have had discovery published ===

const CREATED_KEY = "waterheater_entities_created";
const created = flow.get(CREATED_KEY) || {};

function markCreated(entityId) {
  created[entityId] = true;
  flow.set(CREATED_KEY, created);
}

// === Discovery config builders ===

function sensorConfig(entityId, name, unit, deviceClass, stateClass, icon) {
  const cfg = {
    name,
    unique_id: entityId,
    default_entity_id: `sensor.${entityId}`,
    state_topic: `homeassistant/sensor/${entityId}/state`,
    availability_mode: "all",
    availability: [
      { topic: "librecoach/nodered/status", payload_available: "online", payload_not_available: "offline" },
      { topic: "can/status", value_template: "{{ 'online' if value == 'online' else 'offline' }}", payload_available: "online", payload_not_available: "offline" },
    ],
    device,
  };
  if (unit) cfg.unit_of_measurement = unit;
  if (deviceClass) cfg.device_class = deviceClass;
  if (stateClass) cfg.state_class = stateClass;
  if (icon) cfg.icon = icon;
  return {
    topic: `homeassistant/sensor/${entityId}/config`,
    payload: cfg,
  };
}

function binarySensorConfig(entityId, name, deviceClass, icon) {
  return {
    topic: `homeassistant/binary_sensor/${entityId}/config`,
    payload: {
      name,
      unique_id: entityId,
      default_entity_id: `binary_sensor.${entityId}`,
      state_topic: `homeassistant/binary_sensor/${entityId}/state`,
      payload_on: "ON",
      payload_off: "OFF",
      device_class: deviceClass,
      icon,
      availability_mode: "all",
      availability: [
        { topic: "librecoach/nodered/status", payload_available: "online", payload_not_available: "offline" },
        { topic: "can/status", value_template: "{{ 'online' if value == 'online' else 'offline' }}", payload_available: "online", payload_not_available: "offline" },
      ],
      device,
    },
  };
}

// === Helpers ===

function stateMsg(topic, payload) {
  return { topic, payload };
}

function onOff(value) {
  return value ? "ON" : "OFF";
}

function publishSensor(entityId, stateValue, configFn, canCreate = true) {
  if (!created[entityId]) {
    if (!canCreate) return;
    messages.push(configFn());
    markCreated(entityId);
  }
  messages.push(stateMsg(`homeassistant/sensor/${entityId}/state`, stateValue));
}

function publishBinary(entityId, stateValue, configFn) {
  if (!created[entityId]) {
    messages.push(configFn());
    markCreated(entityId);
  }
  messages.push(
    stateMsg(`homeassistant/binary_sensor/${entityId}/state`, stateValue),
  );
}

function switchConfig(entityId, name, icon, commandTopic) {
  return {
    topic: `homeassistant/switch/${entityId}/config`,
    payload: {
      name,
      unique_id: entityId,
      default_entity_id: `switch.${entityId}`,
      state_topic: `homeassistant/switch/${entityId}/state`,
      command_topic: commandTopic,
      payload_on: "ON",
      payload_off: "OFF",
      icon,
      device: aquahotDevice,
    },
  };
}

function publishSwitch(entityId, stateValue, configFn) {
  if (!created[entityId]) {
    messages.push(configFn());
    markCreated(entityId);
  }
  messages.push(stateMsg(`homeassistant/switch/${entityId}/state`, stateValue));
}

function aquahotBinarySensorConfig(entityId, name, deviceClass, icon) {
  return {
    topic: `homeassistant/binary_sensor/${entityId}/config`,
    payload: {
      name,
      unique_id: entityId,
      default_entity_id: `binary_sensor.${entityId}`,
      state_topic: `homeassistant/binary_sensor/${entityId}/state`,
      payload_on: "ON",
      payload_off: "OFF",
      device_class: deviceClass,
      icon,
      device: aquahotDevice,
    },
  };
}

// === WATERHEATER_STATUS (1FFF7) ===
if (dgn_name === "WATERHEATER_STATUS") {
  if (
    typeof p.operating_mode === "string" &&
    p.operating_mode !== "Not Available"
  ) {
    publishSensor(`waterheater_${i}_mode`, p.operating_mode, () =>
      sensorConfig(
        `waterheater_${i}_mode`,
        `Mode${i_name}`,
        null,
        null,
        null,
        "mdi:water-boiler",
      ),
    );
  }

  if (typeof p.water_temperature === "number") {
    publishSensor(`waterheater_${i}_water_temp`, p.water_temperature, () =>
      sensorConfig(
        `waterheater_${i}_water_temp`,
        `Water Temp${i_name}`,
        "°F",
        "temperature",
        "measurement",
        "mdi:thermometer",
      ),
    );
  }

  if (typeof p.setpoint_temperature === "number") {
    publishSensor(`waterheater_${i}_setpoint`, p.setpoint_temperature, () =>
      sensorConfig(
        `waterheater_${i}_setpoint`,
        `Setpoint${i_name}`,
        "°F",
        "temperature",
        "measurement",
        "mdi:thermometer-check",
      ),
    );
  }

  if (typeof p.burner_active === "boolean") {
    publishBinary(`waterheater_${i}_burner`, onOff(p.burner_active), () =>
      binarySensorConfig(
        `waterheater_${i}_burner`,
        `Burner${i_name}`,
        "running",
        "mdi:fire",
      ),
    );
  }

  if (typeof p.ac_element_active === "boolean") {
    publishBinary(
      `waterheater_${i}_ac_element`,
      onOff(p.ac_element_active),
      () =>
        binarySensorConfig(
          `waterheater_${i}_ac_element`,
          `AC Element${i_name}`,
          "running",
          "mdi:lightning-bolt",
        ),
    );
  }

  if (typeof p.thermostat_not_met === "boolean") {
    publishBinary(
      `waterheater_${i}_thermostat`,
      onOff(p.thermostat_not_met),
      () =>
        binarySensorConfig(
          `waterheater_${i}_thermostat`,
          `Thermostat${i_name}`,
          null,
          "mdi:thermostat",
        ),
    );
  }

  if (typeof p.high_temp_tripped === "boolean") {
    publishBinary(
      `waterheater_${i}_high_temp`,
      onOff(p.high_temp_tripped),
      () =>
        binarySensorConfig(
          `waterheater_${i}_high_temp`,
          `High Temp${i_name}`,
          "problem",
          "mdi:thermometer-alert",
        ),
    );
  }

  if (typeof p.ignite_failed === "boolean") {
    publishBinary(`waterheater_${i}_ignite_fail`, onOff(p.ignite_failed), () =>
      binarySensorConfig(
        `waterheater_${i}_ignite_fail`,
        `Ignite Fail${i_name}`,
        "problem",
        "mdi:fire-alert",
      ),
    );
  }

  // AquaHot 125D — diesel burner switch (controlled via 1FE98 toggle)
  if (typeof p.burner_active === "boolean") {
    publishSwitch("aquahot_diesel_burner", onOff(p.burner_active), () =>
      switchConfig(
        "aquahot_diesel_burner",
        "Diesel Burner",
        "mdi:fire",
        "homeassistant/switch/aquahot_diesel_burner/set",
      ),
    );
  }

  // AquaHot 125D — electric element switch (controlled via 1FE98 toggle)
  if (typeof p.ac_element_active === "boolean") {
    publishSwitch("aquahot_electric_element", onOff(p.ac_element_active), () =>
      switchConfig(
        "aquahot_electric_element",
        "Electric Element",
        "mdi:lightning-bolt",
        "homeassistant/switch/aquahot_electric_element/set",
      ),
    );
  }
}

// === WATERHEATER_STATUS_2 (1FE99) ===
else if (dgn_name === "WATERHEATER_STATUS_2") {
