// Polling Function for Locks
// Requests LOCK_STATUS (1FEE5)

// --- Configuration ---
// The source address of this Node-RED system.
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;       // Standard priority for requests
const DGN = "18EAFF";     // DGN for a broadcast request message

// Build the data payload
// This is the DGN for LOCK_STATUS (1FEE5), sent in little-endian format (least-significant byte first).
const data_payload = "E5FE01FFFFFFFF";

// Construct the CAN ID
const dgnInt = parseInt(DGN, 16);
const canIdInt = (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, '0');

// Construct the final output message in CAN bus format
msg.topic = "can/send";
msg.payload = `${canIdHex.toUpperCase()}#${data_payload.toUpperCase()}`;

//node.warn(`[Poll Locks] Sending global request for lock status. CAN: ${msg.payload}`);

return msg;

// Handles enable/disable of Beta features and tracks beta entities for automatic deletion.
// Input can be both config trigger and MQTT discovery configs.
// Output 1 → MQTT Out (entity creation configs or entity deletion payloads)
// Output 2 → Filter nodes (reset on enable)

// 1. Handle config enable/disable messages
const key = msg.topic.split("/").pop();
if (key === "beta_enabled") {
  const enabled = msg.payload.toString() === "true";

  if (enabled) {
    node.status({ fill: "green", shape: "dot", text: "Enabled" });
    // Output 2 reset for filter nodes
    return [null, { reset: true }];
  }

  // === Disable: delete all tracked beta entities from HA ===
  const discoveryTopics = global.get("betaDiscoveryTopics", "file") || [];

  if (discoveryTopics.length === 0) {
    node.status({
      fill: "yellow",
      shape: "ring",
      text: "Disabled (no entities)",
    });
    return [null, null];
  }

  // Send deletion messages to output 1 (MQTT Out)
  const msgs = discoveryTopics.map((topic) => ({ topic: topic, payload: "" }));

  // Clear persisted tracking state
  global.set("betaDiscoveryTopics", [], "file");

  node.status({
    fill: "red",
    text: `Disabled — removed ${discoveryTopics.length} entities`,
  });

  return [msgs, null];
}

// 2. Handle incoming discovery config messages (from beta Create nodes)
if (
  msg.topic &&
  msg.topic.startsWith("homeassistant/") &&
  msg.topic.endsWith("/config")
) {
  const isBetaEnabled = global.get("betaEnabled");

  // Only process if beta is actually enabled
  if (isBetaEnabled === true) {
    let discoveryTopics = global.get("betaDiscoveryTopics", "file") || [];

    // Add to tracked list if not already there
    if (!discoveryTopics.includes(msg.topic)) {
      discoveryTopics.push(msg.topic);
      global.set("betaDiscoveryTopics", discoveryTopics, "file");
      node.status({
        fill: "green",
        shape: "dot",
        text: `Tracking ${discoveryTopics.length} entities`,
      });
    }

    // Pass the message through to Output 1 (MQTT Out) to actually create the entity
    return [msg, null];
  } else {
    // If a create message arrives while beta is disabled, block it.
    return [null, null];
  }
}

// Ignore unknown messages
return [null, null];

// Decodes GENERATOR_STATUS_1 (1FFDC) and GENERATOR_STATUS_2 (1FFDB) messages
// RV-C spec 6.18.23 and 6.18.24

// === Helper Functions ===

function decodeBits(value, startBit, endBit) {
  const mask = ((1 << (endBit - startBit + 1)) - 1) << startBit;
  return (value & mask) >> startBit;
}

function decodeUint16(data, startByte) {
  return data[startByte] | (data[startByte + 1] << 8);
}

function decodeUint32(data, startByte) {
  return (
    data[startByte] |
    (data[startByte + 1] << 8) |
    (data[startByte + 2] << 16) |
    (data[startByte + 3] << 24)
  );
}

// === GENERATOR_STATUS Specific Decoders ===

// RV-C Table 5.3 uint2 indicator
const BIT2_STATES = {
  0: "Not Active",
  1: "Active",
  2: "Error",
  3: "Not Available",
};

// STATUS_1 - Byte 0: Operational status (§6.18.23)
function decodeGeneratorStatus(value) {
  const states = {
    0: "Stopped",
    1: "Preheat",
    2: "Cranking",
    3: "Running",
    4: "Priming",
    5: "Fault",
    6: "Engine Run Only",
    7: "Test Mode",
    8: "Voltage Adjust Mode",
    9: "Fault Bypass Mode",
    10: "Configuration Mode",
  };
  return states[value] !== undefined ? states[value] : `Unknown (${value})`;
}

// STATUS_1 - Bytes 6-7: Start battery voltage (uint16 LE, Table 5.3)
// Spec defines this as Vdc using Table 5.3 — resolution not explicitly stated.
// Using 0.05 Vdc/bit consistent with other RV-C DC voltage fields and the
// CHARGER_STATUS approach, valid range tops at ~3276.75 V (0xFFFA = out of range).
function decodeStartBatteryVoltage(value) {
  if (value <= 65530) {
    return parseFloat((value * 0.05).toFixed(2));
  } else if (value === 65533) {
    return "Out of Range";
  } else if (value === 65534) {
    return "Reserved";
  } else if (value === 65535) {
    return "Not Available";
  }
  return "Invalid";
}

// STATUS_2 - Byte 1: Coolant temperature (uint8, °C, -40 offset per Table 5.3)
// Output in °F by default to match project convention (see decode_thermostat_ambient_status.js)
function decodeCoolantTemperature(value, isCelsius = false) {
  if (value <= 250) {
    const tempC = value - 40; // -40°C to +210°C range
    return isCelsius ? tempC : parseFloat(((tempC * 9) / 5 + 32).toFixed(1));
  } else if (value === 251) {
    return "Error";
  } else if (value === 252) {
    return "Not Supported";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

// STATUS_2 - Byte 2: Oil pressure (uint8, kPa, 4 kPa/bit, 0-1000 kPa)
function decodeOilPressure(value) {
  if (value <= 250) {
    return value * 4; // 4 kPa per step
  } else if (value === 251) {
    return "Error";
  } else if (value === 252) {
    return "Not Supported";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

// STATUS_2 - Bytes 3-4: Engine RPM (uint16 LE, 0.125 rpm/bit)
function decodeEngineRPM(value) {
  if (value <= 65530) {
    return parseFloat((value * 0.125).toFixed(2));
  } else if (value === 65533) {
    return "Out of Range";
  } else if (value === 65534) {
    return "Reserved";
  } else if (value === 65535) {
    return "Not Available";
  }
  return "Invalid";
}

// STATUS_2 - Bytes 5-6: Fuel rate (uint16 LE, 0.05 lph/bit)
function decodeFuelRate(value) {
  if (value <= 65530) {
    return parseFloat((value * 0.05).toFixed(2));
  } else if (value === 65533) {
    return "Out of Range";
  } else if (value === 65534) {
    return "Reserved";
  } else if (value === 65535) {
    return "Not Available";
  }
  return "Invalid";
}

// === DGN-specific Decode Functions ===

// GENERATOR_STATUS_1 (1FFDC) - §6.18.23
function decodeStatus1(data, result) {
  // Byte 0: Status
  result.status = decodeGeneratorStatus(data[0]);
  result.raw_status = data[0];

  // Bytes 1-4: Engine Run Time (uint32 LE, minutes) — converted to hours
  const runTimeRaw = decodeUint32(data, 1);
  result.engine_run_time = parseFloat((runTimeRaw / 60).toFixed(1));
  result.raw_engine_run_time = runTimeRaw;

  // Byte 5: Engine Load (uint8, %, Table 5.3)
  if (data[5] <= 250) {
    result.engine_load = data[5];
  } else if (data[5] === 251) {
    result.engine_load = "Error";
  } else if (data[5] === 252) {
    result.engine_load = "Not Supported";
  } else if (data[5] === 253) {
    result.engine_load = "Out of Range";
  } else if (data[5] === 254) {
    result.engine_load = "Reserved";
  } else {
    result.engine_load = "Not Available";
  }
  result.raw_engine_load = data[5];

  // Bytes 6-7: Start Battery Voltage (uint16 LE)
  const batteryVoltageRaw = decodeUint16(data, 6);
  result.start_battery_voltage = decodeStartBatteryVoltage(batteryVoltageRaw);
  result.raw_start_battery_voltage = batteryVoltageRaw;

  // Convenience fields
  result.generator_running = result.status === "Running";
  result.generator_fault = result.status === "Fault";
  result.generator_starting =
    result.status === "Cranking" ||
    result.status === "Preheat" ||
    result.status === "Priming";
}

// GENERATOR_STATUS_2 (1FFDB) - §6.18.24
function decodeStatus2(data, result) {
  // Byte 0: Fault/switch bits (4x uint2)
  const faultByte = data[0];
  result.temperature_shutdown = BIT2_STATES[decodeBits(faultByte, 0, 1)];
  result.oil_pressure_shutdown = BIT2_STATES[decodeBits(faultByte, 2, 3)];
  result.oil_level_switch = BIT2_STATES[decodeBits(faultByte, 4, 5)];
  result.caution_light = BIT2_STATES[decodeBits(faultByte, 6, 7)];
  result.raw_fault_byte = faultByte;

  // Byte 1: Coolant Temperature (uint8, °C, offset -40)
  result.coolant_temperature = decodeCoolantTemperature(data[1]);
  result.raw_coolant_temperature = data[1];

  // Byte 2: Oil Pressure (uint8, kPa, 4 kPa/bit)
  result.oil_pressure = decodeOilPressure(data[2]);
  result.raw_oil_pressure = data[2];

  // Bytes 3-4: Engine RPM (uint16 LE, 0.125 rpm/bit)
  const rpmRaw = decodeUint16(data, 3);
  result.engine_rpm = decodeEngineRPM(rpmRaw);
  result.raw_engine_rpm = rpmRaw;

  // Bytes 5-6: Fuel Rate (uint16 LE, 0.05 lph/bit)
  const fuelRateRaw = decodeUint16(data, 5);
  result.fuel_rate = decodeFuelRate(fuelRateRaw);
  result.raw_fuel_rate = fuelRateRaw;

  // Convenience fields
  result.temperature_shutdown_active = result.temperature_shutdown === "Active";
  result.oil_pressure_shutdown_active =
    result.oil_pressure_shutdown === "Active";
  result.low_oil_level = result.oil_level_switch === "Active";
  result.caution_light_on = result.caution_light === "Active";
  result.engine_running =
    typeof result.engine_rpm === "number" && result.engine_rpm > 0;
}

// === Main Decode Function ===

function decodeGeneratorMessage(dgn, dgn_name, data) {
  const result = {
    dgn: dgn,
    dgn_name: dgn_name,
  };

  if (data.length < 8) {
    result.error = `Expected 8 bytes, got ${data.length}`;
    return result;
  }

  if (dgn_name === "GENERATOR_STATUS_1") {
    decodeStatus1(data, result);
  } else if (dgn_name === "GENERATOR_STATUS_2") {
    decodeStatus2(data, result);
  } else {
    result.error = `Unhandled GENERATOR_STATUS DGN: ${dgn_name}`;
  }

  return result;
}

// === Main Logic ===

// Validate input payload
if (!msg.payload || typeof msg.payload !== "object") {
  node.warn("Invalid payload: expected object");
  return null;
}

const incomingPayload = msg.payload;
const { dgn, dgn_name, data_payload } = incomingPayload;

if (!dgn || !dgn_name || !data_payload) {
  node.warn("Missing required fields: dgn, dgn_name, and/or data_payload");
  return null;
}

// Validate and convert hex payload to byte array
if (typeof data_payload !== "string" || data_payload.length % 2 !== 0) {
  node.warn("Invalid data_payload: must be even-length hex string");
  return null;
}

const dataBytes = [];
for (let i = 0; i < data_payload.length; i += 2) {
  const hexByte = data_payload.substring(i, i + 2);
  const byteValue = parseInt(hexByte, 16);
  if (isNaN(byteValue)) {
    node.warn(`Invalid hex byte in data_payload: ${hexByte}`);
    return null;
  }
  dataBytes.push(byteValue);
}

// Decode the GENERATOR_STATUS message
const decodedData = decodeGeneratorMessage(dgn, dgn_name, dataBytes);

// Handle decode errors
if (decodedData.error) {
  incomingPayload.decoding_error = decodedData.error;
  msg.payload = incomingPayload;
  return msg;
}

// Merge the incoming payload and the decoded data into a single flat object
msg.payload = {
  ...incomingPayload,
  ...decodedData,
};

// Clean up the raw data field
delete msg.payload.data_payload;

return msg;

// Encodes GENERATOR_DEMAND_COMMAND messages (1FEFF)
// §6.35.3 — preferred method for network-initiated start/stop (respects Quiet Time)

const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "1FEFF";

const command = msg.command; // Expects "ON" or "OFF"

let demandByte;
switch (command) {
  case "ON":
    demandByte = 0x01; // bits 0-1 = 01 = Generator power demanded
    break;
  case "OFF":
    demandByte = 0x00; // bits 0-1 = 00 = No demand
    break;
  default:
    node.warn(
      `[encode_generator_demand_command] Invalid command: "${command}". Expected "ON" or "OFF"`,
    );
    return null;
}

const dataBytes = new Array(8).fill(0xff);
dataBytes[0] = demandByte;

const dataHex = dataBytes
  .map((b) => b.toString(16).padStart(2, "0"))
  .join("");

const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

node.send({
  topic: "can/send",
  payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
});

return null;

// HA Status Publisher for Tank (DGN 1FFB7, §6.28)
// Self-creating: publishes MQTT discovery on first valid reading per instance.
// Output 1: MQTT messages (discovery + state)

if (!msg.payload || typeof msg.payload !== "object") {
  return null;
}

const p = msg.payload;
const instance = p.instance;

if (typeof instance !== "number") {
  return null;
}

const tankType = p.tank_type;
const levelPercentage = p.level_percentage;

if (!tankType || typeof levelPercentage !== "number") {
  return null;
}

// Instance-to-name map (per RV-C spec §6.28)
const tankNameMap = {
  0: "Fresh Water",
  1: "Black Water",
  2: "Gray Water",
  3: "LPG",
  16: "Fresh Water 2",
  17: "Black Water 2",
  18: "Gray Water 2",
  19: "LPG 2",
};

const displayName = tankNameMap[instance] || `Unknown Tank ${instance}`;
const entityId = `tank_${tankType}`;
const componentType = "sensor";
const stateTopic = `homeassistant/${componentType}/${entityId}/state`;

// Clamp level to 0-100%
const level = Math.max(0, Math.min(100, Math.round(levelPercentage)));

const messages = [];

// Self-creating discovery: publish config on first valid reading
const CREATED_KEY = "tankCreated";
const created = flow.get(CREATED_KEY) || {};

if (!created[instance]) {
  messages.push({
    topic: `homeassistant/${componentType}/${entityId}/config`,
    payload: {
      name: displayName,
      unique_id: entityId,
      default_entity_id: `sensor.${entityId}`,
      icon: "mdi:water-percent",
      state_topic: stateTopic,
      unit_of_measurement: "%",
      value_template: "{{ value | float }}",
      availability_mode: "all",
      availability: [
        { topic: "librecoach/nodered/status", payload_available: "online", payload_not_available: "offline" },
        { topic: "can/status", value_template: "{{ 'online' if value == 'online' else 'offline' }}", payload_available: "online", payload_not_available: "offline" },
      ],
      device: {
        identifiers: ["librecoach-water"],
        name: "Water",
        manufacturer: "LibreCoach",
      },
    },
  });

  created[instance] = true;
  flow.set(CREATED_KEY, created);
}

// State update
messages.push({
  topic: stateTopic,
  payload: level,
});

return [messages];

// Polling Function for DC Dimmer
// Requests DC_DIMMER_STATUS_3 (1FEDA)

// --- Configuration ---
// The source address of this Node-RED system.
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6; // Standard priority for requests
const DGN = "18EAFF"; // DGN for a broadcast request message

// Build the data payload
// This is the DGN for DC_DIMMER_STATUS_3 (1FEDA), sent in little-endian format (least-significant byte first).
const data_payload = "DAFE01FFFFFFFF";

// Construct the CAN ID
const dgnInt = parseInt(DGN, 16);
const canIdInt = (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// Construct the final output message in CAN bus format
msg.topic = "can/send";
msg.payload = `${canIdHex.toUpperCase()}#${data_payload.toUpperCase()}`;

node.log(`Polling started`);

return msg;

// Encodes MQTT Climate commands into THERMOSTAT_COMMAND_1 messages (1FEF9)
// §6.16.4 — same byte layout as THERMOSTAT_STATUS_1 (§6.16.2b)
//
// Byte 0: Instance
// Byte 1: bits 0-3 Operating mode, bits 4-5 Fan mode, bits 6-7 Schedule mode
// Byte 2: Fan speed (0-200 at 0.5% per step, 0=auto)
// Bytes 3-4: Setpoint heat (uint16 LE, Table 5.3 temperature)
// Bytes 5-6: Setpoint cool (uint16 LE, Table 5.3 temperature)
// Byte 7: Reserved (0xFF)

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "1FEF9"; // THERMOSTAT_COMMAND_1

// --- Input Validation ---
const topic = msg.topic;
if (!topic) return null;

const payload = msg.payload;

const parts = topic.split("/");
// Expected: homeassistant/climate/thermostat_zone_{instance}/{cmd}/set
const entityPart = parts[2];
if (!entityPart || !entityPart.startsWith("thermostat_zone_")) return null;

const instanceMatch = entityPart.match(/thermostat_zone_(\d+)/);
if (!instanceMatch) return null;

const instance = parseInt(instanceMatch[1], 10);
if (isNaN(instance)) return null;

const cmdPart = parts[3]; // "mode", "fan", "temp", "temp_high", "temp_low"

// --- Read cached state ---
const cached = global.get(`thermostat_zone_${instance}_status`, "file") || {};

// --- Temperature conversion: °F → raw uint16 (Table 5.3) ---
// raw = ((°F - 32) × 5/9 + 273) / 0.03125
function tempToRaw(fahrenheit) {
  const celsius = ((fahrenheit - 32) * 5) / 9;
  return Math.round((celsius + 273) / 0.03125);
}

// --- Build 8-byte payload, default all fields to "no change" ---
const dataBytes = new Array(8).fill(0xff);
dataBytes[0] = instance;

// Byte 1 bitfield helpers
// bits 6-7: schedule mode — always "no change" (0x3)
// bits 4-5: fan mode — 0=Auto, 1=On, 3=no change
// bits 0-3: operating mode — 0=Off..6=Defrost, 0xF=no change
const SCHED_NC = 0x03;

// --- HA → RV-C mode mapping ---
const HA_TO_RVC_MODE = {
  off: 0x00,
  cool: 0x01,
  heat: 0x02,
  heat_cool: 0x03,
  fan_only: 0x04,
  dry: 0x06,
};

// --- Process command ---

if (topic.endsWith("/mode/set")) {
  const val = payload.toString().toLowerCase();
  const modeRaw = HA_TO_RVC_MODE[val];
  if (modeRaw === undefined) return null;

  if (val === "off") {
    // Off: explicitly set fan to auto (matches observed wireless remote behavior)
    dataBytes[1] = (SCHED_NC << 6) | (0x00 << 4) | modeRaw; // 0xC0
  } else {
    // Other modes: leave fan as "no change"
    dataBytes[1] = (SCHED_NC << 6) | (0x03 << 4) | modeRaw;
  }
} else if (topic.endsWith("/fan/set")) {
  const val = payload.toString().toLowerCase();

  // Leave mode as "no change" (0xF), set fan mode + speed
  if (val === "auto") {
    dataBytes[1] = (SCHED_NC << 6) | (0x00 << 4) | 0x0f; // fan=Auto, mode=nc
    dataBytes[2] = 0x00; // auto speed
  } else if (val === "low") {
    dataBytes[1] = (SCHED_NC << 6) | (0x01 << 4) | 0x0f; // fan=On, mode=nc
    dataBytes[2] = 100; // 50% (0.5% per step)
  } else if (val === "high") {
    dataBytes[1] = (SCHED_NC << 6) | (0x01 << 4) | 0x0f; // fan=On, mode=nc
    dataBytes[2] = 200; // 100%
  } else {
    return null;
  }
} else if (topic.endsWith("/temp/set")) {
  // Single setpoint: set heat or cool depending on current mode
  const temp = parseFloat(payload);
  if (isNaN(temp)) return null;

  const raw = tempToRaw(temp);
  const rawLo = raw & 0xff;
  const rawHi = (raw >> 8) & 0xff;

  // Determine which setpoint to set based on cached operating mode
  const mode = cached.operating_mode || "Cool";
  if (mode === "Heat" || mode === "Aux Heat") {
    dataBytes[3] = rawLo;
    dataBytes[4] = rawHi;
  } else {
    dataBytes[5] = rawLo;
    dataBytes[6] = rawHi;
  }
} else if (topic.endsWith("/temp_low/set")) {
  // Heat setpoint (for heat_cool mode)
  const temp = parseFloat(payload);
  if (isNaN(temp)) return null;

  const raw = tempToRaw(temp);
  dataBytes[3] = raw & 0xff;
  dataBytes[4] = (raw >> 8) & 0xff;
} else if (topic.endsWith("/temp_high/set")) {
  // Cool setpoint (for heat_cool mode)
  const temp = parseFloat(payload);
  if (isNaN(temp)) return null;

  const raw = tempToRaw(temp);
  dataBytes[5] = raw & 0xff;
  dataBytes[6] = (raw >> 8) & 0xff;
} else {
  return null;
}

// --- Construct CAN frame ---

const dataHex = dataBytes
  .map((byte) => byte.toString(16).padStart(2, "0"))
  .join("");

const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// --- Send Message ---

node.send({
  topic: "can/send",
  payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
});

const cmdLabel = cmdPart === "mode" ? payload : `${cmdPart}=${payload}`;
node.status({
  fill: "green",
  shape: "dot",
  text: `Zone ${instance} → ${cmdLabel}`,
});

return null;

// Decode MicroAir Zone Config
// Input: MQTT message from librecoach/ble/microair/{mac}/zone/{z}/config
// Caches config in persistent global context and triggers re-discovery

const topic = msg.topic;
if (!topic) return null;

const parts = topic.split("/");
// Expecting: librecoach/ble/microair/{mac}/zone/{z}/config
if (parts.length < 7) return null;

const mac = parts[3];
const zone = parseInt(parts[5]);
const safeMac = mac.replace(/:/g, "_");

let config;
if (typeof msg.payload === "string") {
    try {
        config = JSON.parse(msg.payload);
    } catch (e) {
        return null;
    }
} else {
    config = msg.payload;
}

if (!config) return null;

// Cache config in persistent global context
const configKey = `microair_${safeMac}_zone_${zone}_config`;
global.set(configKey, config, "file");

// Build a standardized message for microair_unique to trigger re-discovery
msg.payload = {
    mac: mac,
    zone: zone,
    config_updated: true,
};

return msg;

// Create MicroAir Outdoor Temp sensor

const microairEnabled = global.get("microairEnabled");
if (!microairEnabled) return null;

const payload = msg.payload;
if (!payload || !payload.mac) return null;

const mac = payload.mac;
const safeMac = mac.replace(/:/g, "_");
// Only create outdoor sensor for Zone 0 (or duplicative?)
if (payload.zone !== 0) return null;

const uniqueId = `microair_${safeMac}_outdoor_temp`;
const entityId = uniqueId;

const discoveryTopic = `homeassistant/sensor/${entityId}/config`;
const stateTopic = `librecoach/ble/microair/${mac}/zone/0/state`;

const discoveryPayload = {
  name: `Outdoor Temperature`,
  unique_id: uniqueId,
  default_entity_id: "sensor.temperature_outdoor",
  state_topic: stateTopic,
  value_template:
    "{% if value_json.outdoorTemperature is defined and value_json.outdoorTemperature != 255 %}{{ value_json.outdoorTemperature }}{% else %}None{% endif %}",
  unit_of_measurement: "°F",
  device_class: "temperature",
  icon: "mdi:thermometer",
  device: {
    identifiers: ["librecoach-climate"],
    name: "Climate",
    manufacturer: "LibreCoach",
  },
  availability_topic: `librecoach/ble/microair/${mac}/available`,
};

msg.topic = discoveryTopic;
msg.payload = discoveryPayload;

msg.stateTopic = stateTopic;
msg.entityId = entityId;

return msg;

// Encodes MQTT Climate commands into FURNACE_COMMAND messages (1FFE6)

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "1FFE6"; // FURNACE_COMMAND

// --- Input Validation ---
const topic = msg.topic;
if (!topic) return null;

const payload = msg.payload;

const parts = topic.split("/");
// Expected: homeassistant/climate/furnace_{instance}/{cmd}/set
const entityPart = parts[2];
if (!entityPart || !entityPart.startsWith("furnace_")) return null;

const instanceMatch = entityPart.match(/furnace_(\d+)/);
if (!instanceMatch) return null;

const instance = parseInt(instanceMatch[1], 10);
if (isNaN(instance)) return null;

// Read cached furnace state to preserve current settings while changing others
const cached = global.get(`furnace_${instance}_status`, "file") || {};
const cachedHeatSource =
  cached.raw_heat_source !== undefined ? cached.raw_heat_source : 0x00;

// --- Determine Changes ---
let newModeRaw =
  cached.operating_mode !== undefined ? cached.operating_mode : 0;
let fanSpeed = 0xff; // Not Available (let furnace decide)
let heatOutput = 0xff; // Not Available (let furnace decide)

if (topic.endsWith("/mode/set")) {
  const val = payload.toString().toLowerCase();

  if (val === "heat") {
    // HA "heat" -> RV-C Automatic (0x00): furnace runs its own thermostat
    newModeRaw = 0x00;
    fanSpeed = 200; // 100% Fan (0.5% per step)
    heatOutput = 100; // 100% Heat (1% per step)
  } else if (val === "off") {
    // No explicit "off" mode in RV-C; turn off by setting output levels to 0%
    fanSpeed = 0;
    heatOutput = 0;
  } else {
    return null;
  }
} else if (topic.endsWith("/temp/set")) {
  // FURNACE_COMMAND (1FFE6) does not contain temperature setpoint bytes.
  // Temperature is controlled via THERMOSTAT_COMMAND (1FFE1) or internal config.
  node.warn(
    `[encode_furnace_command] Temperature setpoint not supported by FURNACE_COMMAND. Dropping.`,
  );
  return null;
} else {
  return null;
}

// --- Build Payload (1FFE6) ---
const dataBytes = new Array(8).fill(0xff);
dataBytes[0] = instance; // Byte 0: Instance
dataBytes[1] = (newModeRaw & 0x03) | ((cachedHeatSource & 0x3f) << 2); // Byte 1: Operating mode (bits 0-1) + Heat source (bits 2-7)
dataBytes[2] = fanSpeed; // Byte 2: Fan Speed
dataBytes[3] = heatOutput; // Byte 3: Heat Output Level

const dataHex = dataBytes
  .map((byte) => byte.toString(16).padStart(2, "0"))
  .join("");

// --- Construct CAN ID ---
const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// --- Send Message ---
node.send({
  topic: "can/send",
  payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
});

node.status({
  fill: "green",
  shape: "dot",
  text: `Furnace ${instance} -> ${fanSpeed > 0 ? "ON" : "OFF"}`,
});

return null;

// Validates incoming import JSON and prepares HA states request
// Input: msg.payload = parsed JSON body from POST /librecoach/import
// Output 1: valid → msg configured for GET /api/states (with msg.importConfig)
// Output 2: error → msg.payload = error JSON for HTTP Response

const data = msg.payload;

if (!data || typeof data !== "object") {
  msg.payload = { error: "Invalid request: expected a JSON object." };
  msg.statusCode = 400;
  return [null, msg];
}

if (!data.entities || typeof data.entities !== "object") {
  msg.payload = { error: "Invalid file: missing 'entities' key." };
  msg.statusCode = 400;
  return [null, msg];
}

const haBaseUrl = "http://supervisor/core";
const haToken = env.get("SUPERVISOR_TOKEN");

if (!haToken) {
  msg.payload = {
    error: "Server configuration error: no Supervisor token available.",
  };
  msg.statusCode = 500;
  return [null, msg];
}

const allEntities = Object.values(data.entities);
const customized = [];
let skippedUnchanged = 0;

for (const entity of allEntities) {
  if (
    entity.friendly_name &&
    entity.original_name &&
    entity.friendly_name !== entity.original_name
  ) {
    customized.push({
      entity_id: entity.entity_id,
      friendly_name: entity.friendly_name,
    });
  } else {
    skippedUnchanged++;
  }
}

msg.importConfig = {
  customized: customized,
  skippedUnchanged: skippedUnchanged,
  totalInFile: allEntities.length,
};

msg.url = `${haBaseUrl}/api/states`;
msg.method = "GET";
msg.headers = {
  Authorization: `Bearer ${haToken}`,
  "Content-Type": "application/json",
};
msg.payload = "";

node.status({
  fill: "blue",
  shape: "dot",
  text: `${customized.length} customized of ${allEntities.length}`,
});

return [msg, null];

// Encodes DC_DIMMER_COMMAND_2 messages (1FEDB)

// --- Configuration ---
const CMD_SET_BRIGHTNESS = 0x00;
const CMD_ON = 0x01;
const CMD_OFF = 0x03;
const CMD_STOP = 0x04;
const CMD_RAMP_UP_DOWN = 0x15;
const CMD_UNLOCK = 0x22;
const LEVEL_FULL_ON = 200;
const NON_GROUP = 0xff;
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "1FEDB";

// --- Input Validation ---
const instance = msg.instance;

if (typeof instance !== "number" || instance < 1 || instance > 250) {
  node.warn(`[encode_dc_dimmer_command_2] Invalid instance: ${instance}`);
  return null;
}

// --- Parse Command ---
// All lights use JSON schema: msg.payload is always an object
const command = msg.payload.state;
const brightness = msg.payload.brightness;

// Check if this is a dimmable light
const dimmableLights = global.get("dimmableLights", "file") || [];
const isDimmable = dimmableLights.includes(instance);

// --- Command Mapping ---
let commandCode, desiredLevel;

if (command === "OFF") {
  commandCode = CMD_OFF;
  desiredLevel = 0;
} else if (command === "ON" && brightness !== undefined && brightness > 0) {
  // Brightness command: map 0-100 to 0-200 RV-C scale
  commandCode = CMD_SET_BRIGHTNESS;
  desiredLevel = Math.round(brightness * 2);
} else if (isDimmable) {
  // Dimmable light toggled ON without brightness — recall last known level
  const lastBrightness =
    global.get("dimmerBrightness_" + instance, "file") || 100;
  commandCode = CMD_SET_BRIGHTNESS;
  desiredLevel = Math.round(lastBrightness * 2);
} else {
  // Non-dimmable light — full on
  commandCode = CMD_ON;
  desiredLevel = LEVEL_FULL_ON;
}

// --- Helper Functions ---
function buildCanMessage(instance, desiredLevel, commandCode) {
  const dataBytes = new Array(8).fill(0xff);
  dataBytes[0] = instance; // Byte 0: Instance
  dataBytes[1] = NON_GROUP; // Byte 1: Group (non-group)
  dataBytes[2] = desiredLevel; // Byte 2: Desired Level
  dataBytes[3] = commandCode; // Byte 3: Command
  dataBytes[4] = 0xff; // Byte 4: Delay/Duration
  dataBytes[5] = 0x00; // Byte 5: Interlock
  dataBytes[6] = 0xff; // Byte 6: Ramp Time
  dataBytes[7] = 0xff; // Byte 7: Reserved

  const dataHex = dataBytes
    .map((byte) => byte.toString(16).padStart(2, "0"))
    .join("");

  const dgnInt = parseInt(DGN, 16);
  const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
  const canIdHex = canIdInt.toString(16).padStart(8, "0");

  return `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`;
}

// --- Store last brightness for dimmable recall ---
if (brightness !== undefined && brightness > 0) {
  global.set("dimmerBrightness_" + instance, brightness, "file");
}

// --- Build and Send ---
// Message 1: UNLOCK
node.send({
  topic: "can/send",
  payload: buildCanMessage(instance, desiredLevel, CMD_UNLOCK),
});

// Message 2: Command
node.send({
  topic: "can/send",
  payload: buildCanMessage(instance, desiredLevel, commandCode),
});

// Messages 3-4: Save brightness to dimmer memory (dimmable lights only)
// After SET_BRIGHTNESS, send Ramp Up/Down + Stop to trigger memory save.
if (isDimmable && commandCode === CMD_SET_BRIGHTNESS && desiredLevel > 0) {
  node.send({
    topic: "can/send",
    payload: buildCanMessage(instance, 0, CMD_RAMP_UP_DOWN),
  });
  node.send({
    topic: "can/send",
    payload: buildCanMessage(instance, 0, CMD_STOP),
  });
}

return null;

// --- Reset persistent and in-memory context cleanly ---

// Helper function to clear both stores
function clearContext(key) {
    // Remove persistent value
    global.set(key, undefined, "file");
    // Remove in-memory value
    global.set(key, undefined);
}

// --- Clear specific global variables ---
clearContext("uniqueFloorHeatLevels");
clearContext("floorHeatLevelMap");

// --- Clear specific flow variables ---
flow.set("uniqueFloorHeat", undefined, "file");
flow.set("uniqueFloorHeat", undefined);
flow.set("floorHeatLevelMap", undefined, "file");
flow.set("floorHeatLevelMap", undefined);

node.warn("Context cleared");
return null;

// Record Unknown CAN — Toggle Handler
// Input: MQTT payload "ON" or "OFF" from HA switch
// On start: clears log, sets start time, sets recording flag
// On stop: clears flag, shows message count
// Output: retained state publish back to HA

const cmd = msg.payload;

if (cmd === "1") {
  global.set("recordUnknown", true, "file");
  global.set("recordUnknownStart", Date.now(), "file");
  global.set("recordUnknownLog", [], "file");

  node.status({ fill: "red", shape: "dot", text: "Recording..." });

  return {
    topic: "homeassistant/switch/librecoach_record_unknown/state",
    payload: "1",
    retain: true,
  };
}

if (cmd === "0") {
  global.set("recordUnknown", false, "file");

  const log = global.get("recordUnknownLog", "file") || [];
  node.status({
    fill: "green",
    shape: "dot",
    text: `Stopped — ${log.length} messages`,
  });

  return {
    topic: "homeassistant/switch/librecoach_record_unknown/state",
    payload: "0",
    retain: true,
  };
}

return null;

// Encodes LOCK_COMMAND messages (1FEE4)

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "1FEE4";

// --- Input Validation ---
const instance = msg.instance;
const command = msg.command; // Expects "LOCK" or "UNLOCK"

// Accept Instance 0 (broadcast to all locks)
if (typeof instance !== "number" || instance < 0 || instance > 250) {
  node.warn(`[encode_lock_command] Invalid instance: ${instance}`);
  return null;
}

// --- Command Mapping ---
let lockCommand;
switch (command) {
  case "UNLOCK":
    lockCommand = 0; // Unlock
    break;
  case "LOCK":
    lockCommand = 1; // Lock
    break;
  default:
    node.warn(
      `[encode_lock_command] Invalid command: "${command}". Expected "LOCK" or "UNLOCK"`,
    );
    return null;
}

// --- Build Payload ---
const dataBytes = new Array(8).fill(0xff);
dataBytes[0] = instance; // Byte 0: Instance Number
dataBytes[1] = lockCommand; // Byte 1: Lock Command (0=unlock, 1=lock)
dataBytes[2] = 0; // Byte 2: Additional Command (0=no action)
dataBytes[3] = 0xff; // Byte 3: Not Available
dataBytes[4] = 0xff; // Byte 4: Not Available
dataBytes[5] = 0xff; // Byte 5: Not Available
dataBytes[6] = 0xff; // Byte 6: Not Available
dataBytes[7] = 0xff; // Byte 7: Not Available

const dataHex = dataBytes
  .map((byte) => byte.toString(16).padStart(2, "0"))
  .join("");

// Construct the CAN ID
const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// --- Send Message ---
node.send({
  topic: "can/send",
  payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
});

return null;

// Handles enable/disable of Hughes integration via addon config
// Input: msg from librecoach/config/hughes_enabled ("true" / "false")
// Output → MQTT Out (entity deletion on disable)

// Only handle hughes_enabled messages
const key = (msg.topic || "").split("/").pop();
if (key !== "hughes_enabled") return null;

const enabled = msg.payload.toString() === "true";
global.set("hughesEnabled", enabled);

if (enabled) {
  node.status({ fill: "green", shape: "dot", text: "Enabled" });
  return null;
}

// === Disable: delete all Hughes entities ===
const index = global.get("discoveryIndex", "file") || {};
const topics = index.hughes || [];

if (topics.length === 0) {
  node.status({ fill: "yellow", shape: "ring", text: "Disabled (no entities)" });
  return null;
}

// Send retained empty payloads to remove the configs.
for (const topic of topics) node.send({ topic, payload: "" });

// Clear the per-entity discovery signatures so re-enable republishes cleanly.
const keys = global.keys ? global.keys("file") : [];
for (const contextKey of keys) {
  if (contextKey.startsWith("hughes_") && contextKey.endsWith("_discovery_signature")) {
    global.set(contextKey, undefined, "file");
  }
}

node.status({ fill: "red", shape: "dot", text: `Disabled - removed ${topics.length}` });
return null;

// RV-C CAN Message Parser
// Decodes a raw CAN message to output only the fields needed for
// downstream routing (dgn_name) and decoding (data_payload).

const originalMessage = msg.payload;

// Validate input
if (!originalMessage || typeof originalMessage !== "string") {
  node.warn(
    "Invalid message payload: expected string, got " + typeof originalMessage,
  );
  return null;
}
const dgnMap = global.get("dgnMap");
if (!dgnMap) {
  node.error(
    "dgnMap not found in global context. Ensure the map is initialized.",
  );
  return null;
}

// Parse CAN message format: CANID#PAYLOAD
const parts = originalMessage.split("#");
if (parts.length !== 2) {
  node.warn("Invalid CAN message format: " + originalMessage);
  return null;
}
const canIdHex = parts[0];
const data_payload = parts[1];
const canIdNum = parseInt(canIdHex, 16);

if (isNaN(canIdNum)) {
  node.warn("Invalid CAN ID: " + canIdHex);
  return null;
}

// Extract PGN (4-digit) and DGN (5-digit) keys

// Get the 4-digit J1939 PGN (PF + PS). This value is consistent.
const pf = (canIdNum >> 16) & 0xff; // PDU Format (Bits 16-23)
const ps = (canIdNum >> 8) & 0xff; // PDU Specific (Bits 8-15)
let pgn = ((pf << 8) | ps).toString(16).toUpperCase();

// Ensure 4 characters for known PGNs (e.g., EF4D)
while (pgn.length < 4) {
  pgn = "0" + pgn;
}

// PDU1 handling: For PF < 240, PS is destination address, not part of DGN
// Replace PS with 00 for lookup (with exceptions)
let lookupPgn = pgn;
if (pf < 0xf0) {
  // PDU1 format
  if (pf === 0xef) {
    // Exception: Proprietary messages keep PS (EF4D, EF64, EF9F)
    lookupPgn = pgn;
  } else if (pf === 0xec || pf === 0xeb) {
    // Exception: Multi-packet transport uses FF
    lookupPgn = pf.toString(16).toUpperCase() + "FF";
  } else {
    // Standard PDU1: Replace PS with 00
    lookupPgn = pf.toString(16).toUpperCase() + "00";
  }
  // Ensure 4 characters
  while (lookupPgn.length < 4) {
    lookupPgn = "0" + lookupPgn;
  }
}

// The lookup DGN starts as the lookup PGN
let dgn = lookupPgn;
let dgn_name;

// --- DGN Conversion and Primary Lookup ---
// Extract Data Page (DP) bit from CAN ID (bit 24)
const dp = (canIdNum >> 24) & 1;
if (dp) {
  dgn = "1" + lookupPgn;
}
dgn_name = dgnMap.get(dgn);

// For PDU1 messages (PF < 0xF0), PS is the destination address (DSA)
let destination_address = null;
if (pf < 0xf0 && pf !== 0xef && pf !== 0xec && pf !== 0xeb) {
  destination_address = ps;
}

// Fallback: some PDU2 devices transmit with DP=0 instead of DP=1 (non-conformant).
// If DP=0 lookup failed for a PDU2 message, try the DP=1 variant from the table.
if (!dgn_name && dp === 0 && pf >= 0xf0) {
  const altDgn = "1" + lookupPgn;
  const altName = dgnMap.get(altDgn);
  if (altName) {
    dgn = altDgn;
    dgn_name = altName;
  }
}

// Fallback logic for proprietary PGNs not in lookup table
if (!dgn_name) {
  if (pgn === "EF64") {
    dgn_name = "AQUAHOT_COMMAND_1";
  } else if (pgn === "EF9F") {
    dgn_name = "AQUAHOT_STATUS_1";
  } else if (pgn === "EF4D") {
    dgn_name = "AQUAHOT_THERMOSTAT_STATUS_1";
  } else if (lookupPgn === "6F00") {
    dgn_name = "AQUAHOT_UNUSED";
  } else if (lookupPgn === "6C00") {
    dgn_name = "AQUAHOT_STATUS_2";
  } else if (lookupPgn === "FF01") {
    dgn_name = "AQUAHOT_THERMOSTAT_STATUS_2";
  } else if (lookupPgn === "FF2E") {
    dgn_name = "AQUAHOT_SYSTEM_STATUS_2";
  } else if (lookupPgn === "FF2F") {
    dgn_name = "AQUAHOT_COMMAND_2";
  } else if (lookupPgn === "BF00") {
    dgn_name = "WIRELESS_PANEL_SIGNAL_STATUS";
  } else if (dgn === "1AA00") {
    dgn_name = "WIRELESS_PANEL_QUALITY_STATUS";
  } else if (pgn.startsWith("EF")) {
    dgn_name = "AQUAHOT_UNUSED";
  }
}

// Final output
if (!dgn_name) {
  dgn_name = "UNKNOWN";
}

const singleInstanceDgns = {
  WATER_PUMP_STATUS: "water_pump",
  AUTOFILL_STATUS: "autofill",
  GENERATOR_STATUS_1: "generator",
  GENERATOR_STATUS_2: "generator",
  GENERATOR_DEMAND_STATUS: "generator",
  LEVELING_CONTROL_STATUS: "leveling_control",
  WASTEDUMP_STATUS: "wastedump",
};

// These DGNs are defined by RV-C as single-instance devices; byte 0 is a
// status/command bit field, not a device instance.
const instance =
  singleInstanceDgns[dgn_name] || parseInt(data_payload.substring(0, 2), 16);

msg.payload = {
  originalMessage: originalMessage,
  dgn: dgn,
  dgn_name: dgn_name,
  instance: instance,
  destination_address: destination_address,
  data_payload: data_payload,
};

msg.filter_key = `${dgn_name}_${instance}`;

// Bypass RBE/deduplication exclusively for DC_DIMMER_COMMAND_2 "Toggle" buttons.
// Byte 3 equals: 0x05 (Toggle). Other commands will naturally change byte values.
if (dgn_name === "DC_DIMMER_COMMAND_2" && data_payload.length >= 8) {
  const cmdByte = parseInt(data_payload.substring(6, 8), 16);
  if (cmdByte === 0x05) {
    msg.payload._ts = Date.now();
  }
}

return msg;

// Polling Function for DC Load
// Requests DC_LOAD_STATUS (1FFBD)

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "18EAFF";

// DC_LOAD_STATUS DGN 1FFBD in little-endian: BD FF 01
const data_payload = "BDFF01FFFFFFFF";

// Construct the CAN ID
const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

msg.topic = "can/send";
msg.payload = `${canIdHex.toUpperCase()}#${data_payload.toUpperCase()}`;

node.log(`Polling DC Load status`);

return msg;

// HA Status Publisher for DC Dimmer — inferred from COMMAND_2 (DGN 1FEDBh)
// Self-creating: publishes MQTT discovery on first valid command per instance.
// Uses switch_N entity naming (same as STATUS_3 path).
// Output 1: MQTT messages [messages] (discovery + state)

if (!msg.payload || typeof msg.payload !== "object") {
  return null;
}

const p = msg.payload;
const instance = p.instance;
const commandRaw = p.command_raw;
const levelRaw = p.desired_level_raw;

if (typeof instance !== "number" || instance < 1 || instance > 250) {
  return null;
}

// This node is only a fallback for RVs that never acknowledge light changes
// with DC_DIMMER_STATUS_* messages. Once real status is seen for an instance,
// let the status-based publisher own discovery and state permanently.
const statusBackedInstances =
  global.get("dcDimmerStatusBackedInstances", "file") || [];
if (statusBackedInstances.includes(instance)) {
  return null;
}

if (typeof commandRaw !== "number") {
  return null;
}

// --- Command-to-state mapping ---
// Returns: "ON", "OFF", or null (ignore / no state change)
function inferState(cmd, level) {
  switch (cmd) {
    case 0x01: // On Duration
    case 0x02: // On Delay
      return "ON";
    case 0x05: // Toggle — assume ON (can't know current state)
      return "ON";
    case 0x03: // Off Delay
    case 0x06: // Memory Off
      return "OFF";
    case 0x00: // Set Level
    case 0x0b: // Ramp Brightness
      if (typeof level === "number") {
        return level > 0 ? "ON" : "OFF";
      }
      return null;
    default:
      // Stop (0x04), Save Scene (0x07), Ramp Up (0x0D), Ramp Down (0x0E),
      // Ramp Up/Down (0x0F/0x15), Lock (0x21), Unlock (0x22),
      // Flash (0x1F), Flash Momentary (0x20), Ramp Toggle (0x0C/0x10)
      return null;
  }
}

const haStatus = inferState(commandRaw, levelRaw);

if (haStatus === null) {
  return null;
}

// --- Dimmable detection ---
const dimmableLights = global.get("dimmableLights", "file") || [];
let isDimmable = dimmableLights.includes(instance);

function markDimmable() {
  if (!isDimmable) {
    dimmableLights.push(instance);
    global.set("dimmableLights", dimmableLights, "file");
    isDimmable = true;
  }
}

// Intermediate levels (1-199 raw = 0.5%-99.5%) indicate dimmable
if (typeof levelRaw === "number" && levelRaw >= 1 && levelRaw <= 199) {
  markDimmable();
}

// Ramp commands indicate dimmable regardless of level
const rampCommands = [0x0b, 0x0c, 0x0d, 0x0e, 0x0f, 0x10, 0x15];
if (rampCommands.includes(commandRaw)) {
  markDimmable();
}

// --- Brightness from COMMAND_2 ---
let brightness;
if (typeof levelRaw === "number" && levelRaw <= 200) {
  // 0-200 raw → 0-100%
  brightness = parseFloat((levelRaw * 0.5).toFixed(1));
}
// Special values (250=Dimmed Memory, 251=Master Memory, scenes) → no brightness
// (actual level unknown — report ON without brightness)

// --- Entity identifiers — switch_N (same as STATUS_3 path) ---
const entityId = `switch_${instance}`;
const stateTopic = `homeassistant/light/${entityId}/state`;
const commandTopic = `homeassistant/light/${entityId}/set`;

const messages = [];

// --- Self-creating discovery ---
// Capability is persisted in the FILE store (shared key with the status path,
// status_dc_dimmer_3.js) so this block runs only on a genuine capability change
// rather than on every restart, and so the two paths never fight over switch_N.
// Dimmability is monotonic, so we never downgrade brightness -> onoff. HA can't
// hot-swap supported_color_modes, so a change requires delete-then-recreate.
const PUBLISHED_KEY = "dcDimmerPublishedMode";
const publishedModes = global.get(PUBLISHED_KEY, "file") || {};
const priorMode = publishedModes[instance];
const desiredMode =
  isDimmable || priorMode === "brightness" ? "brightness" : "onoff";

// Keep isDimmable aligned with the capability we will actually publish.
if (desiredMode === "brightness") {
  isDimmable = true;
}

if (priorMode !== desiredMode) {
  // Remove any existing retained config first so HA recreates the entity fresh
  // with the new capability. Harmless no-op if nothing is retained yet.
  messages.push({
    topic: `homeassistant/light/${entityId}/config`,
    payload: "",
  });

  const config = {
    name: `Switch ${instance}`,
    unique_id: entityId,
    default_entity_id: `light.${entityId}`,
    icon: "mdi:light-recessed",
    schema: "json",
    command_topic: commandTopic,
    state_topic: stateTopic,
    availability_mode: "all",
    availability: [
      {
        topic: "librecoach/nodered/status",
        payload_available: "online",
        payload_not_available: "offline",
      },
      {
        topic: "can/status",
        value_template: "{{ 'online' if value == 'online' else 'offline' }}",
        payload_available: "online",
        payload_not_available: "offline",
      },
    ],
    device: {
      identifiers: ["librecoach-switches"],
      name: "Switches",
      manufacturer: "LibreCoach",
    },
  };

  if (isDimmable) {
    config.brightness = true;
    config.brightness_scale = 100;
    config.supported_color_modes = ["brightness"];
  } else {
    config.supported_color_modes = ["onoff"];
  }

  messages.push({
    topic: `homeassistant/light/${entityId}/config`,
    payload: config,
  });

  publishedModes[instance] = desiredMode;
  global.set(PUBLISHED_KEY, publishedModes, "file");
}

// --- Store last brightness for dimmable recall on toggle ---
if (isDimmable && typeof brightness === "number" && brightness > 0) {
  global.set("dimmerBrightness_" + instance, brightness, "file");
}

// --- Build JSON state payload ---
const stateObj = { state: haStatus };

if (haStatus === "ON") {
  if (isDimmable) {
    stateObj.color_mode = "brightness";
    if (brightness !== undefined && brightness > 0) {
      stateObj.brightness = brightness;
    }
  } else {
    stateObj.color_mode = "onoff";
  }
}

messages.push({
  topic: stateTopic,
  payload: JSON.stringify(stateObj),
});

if (messages.length === 0) return null;

return [messages];

// Publishes generator entity states to MQTT state topics.
// Also publishes MQTT discovery configs the first time a valid value is
// received for each entity.
// Handles output from decode_generator_status.js and decode_generator_ac_status.js.

if (!msg.payload || typeof msg.payload !== "object") {
  node.warn("Invalid payload: expected object");
  return null;
}

const p = msg.payload;
const dgn_name = p.dgn_name;
const messages = [];

// --- Device definition ---

const device = {
  identifiers: ["librecoach-generator"],
  name: "Generator",
  manufacturer: "LibreCoach",
};

// --- Flow context: tracks which entities have had discovery published ---

const CREATED_KEY = "generator_entities_created";
const created = flow.get(CREATED_KEY) || {};

function markCreated(entityId) {
  created[entityId] = true;
  flow.set(CREATED_KEY, created);
}

// --- Discovery config builders ---

function sensorConfig(entityId, name, unit, deviceClass, stateClass, icon) {
  const cfg = {
    name,
    unique_id: entityId,
    default_entity_id: `sensor.${entityId}`,
    state_topic: `homeassistant/sensor/${entityId}/state`,
    availability_mode: "all",
    availability: [
      { topic: "librecoach/nodered/status", payload_available: "online", payload_not_available: "offline" },
      { topic: "can/status", value_template: "{{ 'online' if value == 'online' else 'offline' }}", payload_available: "online", payload_not_available: "offline" },
    ],
    device,
  };
  if (unit) cfg.unit_of_measurement = unit;
  if (deviceClass) cfg.device_class = deviceClass;
  if (stateClass) cfg.state_class = stateClass;
  if (icon) cfg.icon = icon;
  return {
    topic: `homeassistant/sensor/${entityId}/config`,
    payload: cfg,
  };
}

function binarySensorConfig(entityId, name, deviceClass, icon) {
  return {
    topic: `homeassistant/binary_sensor/${entityId}/config`,
    payload: {
      name,
      unique_id: entityId,
      default_entity_id: `binary_sensor.${entityId}`,
      state_topic: `homeassistant/binary_sensor/${entityId}/state`,
      payload_on: "ON",
      payload_off: "OFF",
      device_class: deviceClass,
      icon,
      availability_mode: "all",
      availability: [
        { topic: "librecoach/nodered/status", payload_available: "online", payload_not_available: "offline" },
        { topic: "can/status", value_template: "{{ 'online' if value == 'online' else 'offline' }}", payload_available: "online", payload_not_available: "offline" },
      ],
      device,
    },
  };
}

// --- Helpers ---

function stateMsg(topic, payload) {
  return { topic, payload };
}

function onOff(value) {
  return value ? "ON" : "OFF";
}

// Publish discovery config the first time a valid value is seen for an entity,
// then always publish the state.
// canCreate: pass a reasonableness check expression — entity won't be created
// until the value makes physical sense (e.g., RPM > 0 means engine is spinning).
// Once created, state is always published (including zeros).
function publishSensor(entityId, stateValue, configFn, canCreate = true) {
  if (!created[entityId]) {
    if (!canCreate) return;
    messages.push(configFn());
    markCreated(entityId);
  }
  messages.push(stateMsg(`homeassistant/sensor/${entityId}/state`, stateValue));
}

function publishBinary(entityId, stateValue, configFn) {
  if (!created[entityId]) {
    messages.push(configFn());
    markCreated(entityId);
  }
  messages.push(
    stateMsg(`homeassistant/binary_sensor/${entityId}/state`, stateValue),
  );
}

// --- STATUS_1 ---

if (dgn_name === "GENERATOR_STATUS_1") {
  if (typeof p.status === "string" && p.status !== "Not Available") {
    publishSensor("generator_status", p.status, () =>
      sensorConfig(
        "generator_status",
        "Generator Status",
        null,
        null,
        null,
        "mdi:engine",
      ),
    );
  }

  if (typeof p.engine_run_time === "number") {
    publishSensor(
      "generator_run_time",
      p.engine_run_time,
      () =>
        sensorConfig(
          "generator_run_time",
          "Generator Run Time",
          "h",
          null,
          "total_increasing",
          "mdi:timer",
        ),
      p.engine_run_time > 0,
    );
  }

  if (typeof p.engine_load === "number") {
    publishSensor("generator_engine_load", p.engine_load, () =>
      sensorConfig(
        "generator_engine_load",
        "Generator Engine Load",
        "%",
        null,
        "measurement",
        "mdi:gauge",
      ),
    );
  }

  if (typeof p.start_battery_voltage === "number") {
    publishSensor(
      "generator_battery_voltage",
      p.start_battery_voltage,
      () =>
        sensorConfig(
          "generator_battery_voltage",
          "Generator Battery Voltage",
          "V",
          "voltage",
          "measurement",
          "mdi:battery",
        ),
      p.start_battery_voltage > 0,
    );
  }

  // Binary sensors — false is a valid state
  if (typeof p.generator_running === "boolean") {
    publishBinary("generator_running", onOff(p.generator_running), () =>
      binarySensorConfig(
        "generator_running",
        "Generator Running",
        "running",
        "mdi:engine",
      ),
    );
  }

  if (typeof p.generator_fault === "boolean") {
    publishBinary("generator_fault", onOff(p.generator_fault), () =>
      binarySensorConfig(
        "generator_fault",
        "Generator Fault",
        "problem",
        "mdi:alert-circle",
      ),
    );
  }

  if (typeof p.generator_running === "boolean") {
    if (!created["generator_control"]) {
      messages.push({
        topic: "homeassistant/switch/generator_control/config",
        payload: {
          name: "Generator Control",
          unique_id: "generator_control",
          default_entity_id: "switch.generator_control",
          state_topic: "homeassistant/switch/generator_control/state",
          command_topic: "homeassistant/switch/generator_control/set",
          payload_on: "ON",
          payload_off: "OFF",
          icon: "mdi:engine",
          availability_mode: "all",
          availability: [
            { topic: "librecoach/nodered/status", payload_available: "online", payload_not_available: "offline" },
            { topic: "can/status", value_template: "{{ 'online' if value == 'online' else 'offline' }}", payload_available: "online", payload_not_available: "offline" },
          ],
          device,
        },
      });
      markCreated("generator_control");
    }
    messages.push(
      stateMsg(
        "homeassistant/switch/generator_control/state",
        onOff(p.generator_running),
      ),
    );
  }

  // --- STATUS_2 ---
} else if (dgn_name === "GENERATOR_STATUS_2") {
  if (typeof p.coolant_temperature === "number") {
    publishSensor(
      "generator_coolant_temp",
      p.coolant_temperature,
      () =>
        sensorConfig(
          "generator_coolant_temp",
          "Generator Coolant Temp",
          "°F",
          "temperature",
          "measurement",
          "mdi:thermometer",
        ),
      p.coolant_temperature > 100, // running engine threshold (~38°C+)
    );
  }

  if (typeof p.oil_pressure === "number") {
    publishSensor(
      "generator_oil_pressure",
      p.oil_pressure,
      () =>
        sensorConfig(
          "generator_oil_pressure",
          "Generator Oil Pressure",
          "kPa",
          "pressure",
          "measurement",
          "mdi:gauge",
        ),
      p.oil_pressure > 0,
    );
  }

  if (typeof p.engine_rpm === "number") {
    publishSensor(
      "generator_rpm",
      p.engine_rpm,
      () =>
        sensorConfig(
          "generator_rpm",
          "Generator RPM",
          "RPM",
          null,
          "measurement",
          "mdi:rotate-right",
        ),
      p.engine_rpm > 0,
    );
  }

  if (typeof p.fuel_rate === "number") {
    publishSensor("generator_fuel_rate", p.fuel_rate, () =>
      sensorConfig(
        "generator_fuel_rate",
        "Generator Fuel Rate",
        "L/h",
        null,
        "measurement",
        "mdi:fuel",
      ),
    );
  }

  if (typeof p.caution_light_on === "boolean") {
    publishBinary("generator_caution", onOff(p.caution_light_on), () =>
      binarySensorConfig(
        "generator_caution",
        "Generator Caution",
        "problem",
        "mdi:alert",
      ),
    );
  }

  // --- GENERATOR_DEMAND_STATUS ---
} else if (dgn_name === "GENERATOR_DEMAND_STATUS") {
  if (
    typeof p.demand_summary === "string" &&
    p.demand_summary !== "Not Available"
  ) {
    publishSensor("generator_demand_summary", p.demand_summary, () =>
      sensorConfig(
        "generator_demand_summary",
        "Generator Demand",
        null,
        null,
        null,
        "mdi:engine",
      ),
    );
  }

  if (typeof p.generator_should_run === "boolean") {
    publishBinary(
      "generator_demand_active",
      onOff(p.generator_should_run),
      () =>
        binarySensorConfig(
          "generator_demand_active",
          "Generator Demand Active",
          "running",
          "mdi:engine",
        ),
    );
  }

  if (typeof p.quiet_time_active === "boolean") {
    publishBinary("generator_quiet_time", onOff(p.quiet_time_active), () =>
      binarySensorConfig(
        "generator_quiet_time",
        "Generator Quiet Time",
        null,
        "mdi:moon-waning-crescent",
      ),
    );
  }

  // --- GENERATOR_AC_STATUS_1 ---
} else if (dgn_name === "GENERATOR_AC_STATUS_1") {
  const active = !!p.ac_output_active;

  if (typeof p.rms_voltage === "number") {
    publishSensor(
      "generator_ac_voltage",
      active ? p.rms_voltage : 0,
      () =>
        sensorConfig(
          "generator_ac_voltage",
          "Generator AC Voltage",
          "V",
          "voltage",
          "measurement",
          "mdi:lightning-bolt",
        ),
      active,
    );
  }

  if (typeof p.rms_current === "number") {
    publishSensor(
      "generator_ac_current",
      active ? p.rms_current : 0,
      () =>
        sensorConfig(
          "generator_ac_current",
          "Generator AC Current",
          "A",
          "current",
          "measurement",
          "mdi:current-ac",
        ),
      active,
    );
  }

  if (typeof p.frequency === "number") {
    publishSensor(
      "generator_frequency",
      active ? p.frequency : 0,
      () =>
        sensorConfig(
          "generator_frequency",
          "Generator Frequency",
          "Hz",
          "frequency",
          "measurement",
          "mdi:sine-wave",
        ),
      active,
    );
  }

  if (typeof p.rms_voltage === "number" && typeof p.rms_current === "number") {
    const power = active
      ? parseFloat((p.rms_voltage * p.rms_current).toFixed(1))
      : 0;
    publishSensor(
      "generator_ac_power",
      power,
      () =>
        sensorConfig(
          "generator_ac_power",
          "Generator AC Power",
          "VA",
          "apparent_power",
          "measurement",
          "mdi:flash",
        ),
      active,
    );
  }
}

if (messages.length === 0) {
  return null;
}

return [messages];

// Encodes WATER_PUMP_COMMAND messages (1FFB2)

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "1FFB2";

// --- Input Validation ---
const command = msg.command; // Expects "ON" or "OFF"

// --- Command Mapping ---
let pumpCommandValue;
switch (command) {
  case "ON":
    pumpCommandValue = 1; // 01b = Enable pump (standby)
    break;
  case "OFF":
    pumpCommandValue = 0; // 00b = Disable pump
    break;
  default:
    node.warn(
      `[encode_water_pump_command] Invalid command: "${command}". Expected "ON" or "OFF"`,
    );
    return null;
}

// --- Build Payload ---
// Byte 0 contains the command. All other bytes are set to 0xFF (Not Available)
const dataBytes = new Array(8).fill(0xff);
dataBytes[0] = pumpCommandValue; // Byte 0: Pump command

const dataHex = dataBytes
  .map((byte) => byte.toString(16).padStart(2, "0"))
  .join("");

// Construct the CAN ID
const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// --- Send Message ---
node.send({
  topic: "can/send",
  payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
});

return null;

