  const instance = parseInt(rvcTopicMatch[1], 10);
  const command = String(msg.payload).toUpperCase();
  msg.routingKey = "cover";
  msg.instance = instance;
  msg.command = command;
  msg.entityType = "cover";
  msg.entityId = `shade_${instance}`;
  return msg;
}

// --- Lock entities ---
const lockTopicMatch = msg.topic.match(
  /^homeassistant\/lock\/lock_(\d+)\/set$/,
);
if (lockTopicMatch) {
  const instance = parseInt(lockTopicMatch[1], 10);
  const command = String(msg.payload).toUpperCase();
  msg.routingKey = "lock";
  msg.instance = instance;
  msg.command = command;
  msg.entityType = "lock";
  msg.entityId = `lock_${instance}`;
  return msg;
}

// --- Climate (Floor Heat) Preset entities ---
const climatePresetMatch = msg.topic.match(
  /^homeassistant\/climate\/floor_heat_(\d+)\/set_preset_mode$/,
);
if (climatePresetMatch) {
  const instance = parseInt(climatePresetMatch[1], 10);
  msg.routingKey = "floor_heat";
  msg.instance = instance;
  msg.entityType = "climate";
  msg.entityId = `floor_heat_${instance}`;
  msg.command = "SET_PRESET";
  msg.value = String(msg.payload); // e.g., "Level 5"
  return msg;
}

// --- Climate (Floor Heat) Mode entities ---
const climateTopicMatch = msg.topic.match(
  /^homeassistant\/climate\/floor_heat_(\d+)\/set_mode$/,
);
if (climateTopicMatch) {
  const instance = parseInt(climateTopicMatch[1], 10);
  msg.routingKey = "floor_heat";
  msg.instance = instance;
  msg.entityType = "climate";
  msg.entityId = `floor_heat_${instance}`;
  msg.command = String(msg.payload).toUpperCase(); // "HEAT" or "OFF"
  return msg;
}

// --- Aqua-Hot entities ---
const aquahotTopicMatch = msg.topic.match(
  /^homeassistant\/light\/aquahot_(burner|ac_1|ac_2|engine)\/set$/,
);
if (aquahotTopicMatch) {
  const instance = aquahotTopicMatch[1]; // "burner", "ac_1", "ac_2", or "engine"
  const command = String(msg.payload).toUpperCase();
  msg.routingKey = "aquahot";
  msg.instance = instance;
  msg.command = command;
  msg.entityType = "light";
  msg.entityId = `aquahot_${instance}`;
  return msg;
}

// --- AquaHot 125D switch entities (1FE98 / FF2F commands) ---
const aquahot125dMatch = msg.topic.match(
  /^homeassistant\/switch\/aquahot_(diesel_burner|electric_element|quiet_mode|interior_heating)\/set$/,
);
if (aquahot125dMatch) {
  const entityId = `aquahot_${aquahot125dMatch[1]}`;
  msg.routingKey = "aquahot_125d";
  msg.entityId = entityId;
  msg.command = String(msg.payload).toUpperCase();
  msg.entityType = "switch";
  return msg;
}

// --- Generator control ---
if (msg.topic === "homeassistant/switch/generator_control/set") {
  msg.routingKey = "generator";
  msg.command = String(msg.payload).toUpperCase();
  msg.entityType = "switch";
  msg.entityId = "generator_control";
  return msg;
}

// --- Switch and Light entities (Fallback) ---
const topicParts = msg.topic.split("/");
if (
  topicParts.length === 4 &&
  topicParts[0] === "homeassistant" &&
  (topicParts[1] === "switch" || topicParts[1] === "light") &&
  topicParts[3] === "set"
) {
  const entityId = topicParts[2];
  msg.entityType = topicParts[1];
  msg.entityId = entityId;

  // Handle JSON payloads from dimmable lights (JSON schema entities)
  try {
    const parsed = JSON.parse(msg.payload);
    if (typeof parsed === "object" && parsed !== null) {
      msg.payload = parsed;
      msg.command = parsed.state ? parsed.state.toUpperCase() : "ON";
    } else {
      msg.command = String(msg.payload).toUpperCase();
    }
  } catch (e) {
    // Simple string payload (non-dimmable lights)
    msg.command = String(msg.payload).toUpperCase();
  }

  if (entityId === "water_pump" || entityId === "autofill") {
    msg.instance = entityId;
    msg.routingKey = entityId;
  } else {
    const entityIdParts = entityId.split("_");
    const instanceStr = entityIdParts[entityIdParts.length - 1];
    const instanceNum = parseInt(instanceStr, 10);
    if (isNaN(instanceNum)) {
      node.warn(`Could not parse instance number from entityId: ${entityId}`);
      return null;
    }
    msg.instance = instanceNum;
    msg.routingKey = entityIdParts.slice(0, -1).join("_");
  }
  return msg;
}

node.warn(`Unhandled MQTT topic: ${msg.topic}`);
return null;

// Cross-references import entities with current HA entities
// Input:
//   msg.payload = array of state objects from GET /api/states
//   msg.importConfig = { customized, skippedUnchanged, totalInFile }
// Output 1: msg.payload = array of { entity_id, friendly_name } for Split pipeline
// Output 2: msg.payload = early HTTP response when no entities to update

const states = msg.payload;
const config = msg.importConfig;

if (!Array.isArray(states) || !config) {
    msg.payload = { error: "Failed to retrieve HA states." };
    msg.statusCode = 500;
    return [null, msg];
}

// Build set of entity IDs currently in HA
const haEntityIds = new Set(states.map((s) => s.entity_id));

// Cross-reference: only include entities that exist in HA
const toUpdate = [];
let skippedMissing = 0;

for (const entity of config.customized) {
    if (haEntityIds.has(entity.entity_id)) {
        toUpdate.push(entity);
    } else {
        skippedMissing++;
    }
}

// Store counts for summarize_import
msg.importCounts = {
    totalInFile: config.totalInFile,
    skippedUnchanged: config.skippedUnchanged,
    skippedMissing: skippedMissing,
    toUpdate: toUpdate.length,
};

if (toUpdate.length === 0) {
    msg.payload = {
        updated: 0,
        skipped: skippedMissing + config.skippedUnchanged,
        failed: 0,
        message: "No matching entities found in HA to update.",
    };
    msg.statusCode = 200;
    node.status({ fill: "yellow", shape: "dot", text: "Nothing to update" });
    return [null, msg];
}

msg.payload = toUpdate;

node.status({
    fill: "blue",
    shape: "dot",
    text: `${toUpdate.length} to update, ${skippedMissing} skipped`,
});

return [msg, null];

// Encodes AC_LOAD_COMMAND messages (DGN 1FFBEh, §6.22.4)

const CMD_SET_LEVEL = 0x00;
const CMD_ON = 0x01;
const CMD_OFF = 0x03;
const CMD_STOP = 0x04;
const CMD_UNLOCK = 0x22;
const LEVEL_FULL_ON = 200;
const NON_GROUP = 0xff;
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "1FFBE";

const instance = msg.instance;

if (typeof instance !== "number" || instance < 1 || instance > 250) {
  node.warn(`[encode_ac_load_command] Invalid instance: ${instance}`);
  return null;
}

// Parse command — JSON schema: msg.payload is always an object
const command = msg.payload.state;
const brightness = msg.payload.brightness;

const dimmableAcLoads = global.get("dimmableAcLoads", "file") || [];
const isDimmable = dimmableAcLoads.includes(instance);

let commandCode, desiredLevel;

if (command === "OFF") {
  commandCode = CMD_OFF;
  desiredLevel = 0;
} else if (command === "ON" && brightness !== undefined && brightness > 0) {
  commandCode = CMD_SET_LEVEL;
  desiredLevel = Math.round(brightness * 2);
} else if (isDimmable) {
  const lastBrightness =
    global.get("acLoadBrightness_" + instance, "file") || 100;
  commandCode = CMD_SET_LEVEL;
  desiredLevel = Math.round(lastBrightness * 2);
} else {
  commandCode = CMD_ON;
  desiredLevel = LEVEL_FULL_ON;
}

function buildCanMessage(inst, level, cmd) {
  const dataBytes = new Array(8).fill(0xff);
  dataBytes[0] = inst; // Byte 0: Instance
  dataBytes[1] = NON_GROUP; // Byte 1: Group
  dataBytes[2] = level; // Byte 2: Desired Level
  dataBytes[3] = 0xff; // Byte 3: Mode/Interlock/Priority (no change)
  dataBytes[4] = cmd; // Byte 4: Command
  dataBytes[5] = 0xff; // Byte 5: Delay/Duration
  dataBytes[6] = 0xff; // Byte 6: Reserved
  dataBytes[7] = 0xff; // Byte 7: Reserved

  const dataHex = dataBytes
    .map((byte) => byte.toString(16).padStart(2, "0"))
    .join("");

  const dgnInt = parseInt(DGN, 16);
  const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
  const canIdHex = canIdInt.toString(16).padStart(8, "0");

  return `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`;
}

// Store last brightness for dimmable recall
if (brightness !== undefined && brightness > 0) {
  global.set("acLoadBrightness_" + instance, brightness, "file");
}

// Message 1: UNLOCK
node.send({
  topic: "can/send",
  payload: buildCanMessage(instance, desiredLevel, CMD_UNLOCK),
});

// Message 2: Command
node.send({
  topic: "can/send",
  payload: buildCanMessage(instance, desiredLevel, commandCode),
});

return null;

// Decoder for Proprietary AquaHot _2 DGNs:
// FF01 (AQUAHOT_THERMOSTAT_STATUS_2), FF2F (AQUAHOT_COMMAND_2), FF2E (AQUAHOT_SYSTEM_STATUS_2), 6C00 (AQUAHOT_STATUS_2)
//
// Note: These are NOT part of the standard RV-C specification. Decoding is based on
// reverse-engineered analysis of recordings. Confidence levels differ per field.

function decodeUint16(data, startByte) {
    return data[startByte] | (data[startByte + 1] << 8);
}

// === AQUAHOT_THERMOSTAT_STATUS_2 (FF01) ===
function decodeZoneThermostat(data, result) {
    // Byte 0: Zone Index [HIGH confidence] (00=Zone 1, 01=Zone 2)
    result.zone_index = data[0];
    result.raw_zone_index = data[0];

    // Byte 1: Sub-Index [HIGH confidence] (01=primary, 02=secondary, FF=summary)
    result.sub_index = data[1];

    // Byte 2: Config/Capability Byte [MEDIUM confidence]
    result.config_byte = data[2];

    // Byte 3: Unknown [LOW confidence] (always 0x01 in recordings)
    result.unknown_byte3 = data[3];

    // Byte 4: Status/Mode [MEDIUM confidence]
    result.status_mode = data[4];

    // Byte 5: Unknown [LOW confidence]
    result.unknown_byte5 = data[5];

    // Byte 6: Temperature [HIGH confidence for sub-index 01, °F]
    if (data[1] === 0x01 && data[6] !== 0xff) {
        result.zone_temperature = data[6];
    }
    result.raw_temperature = data[6];

    // Byte 7: Unknown [LOW confidence]
    result.unknown_byte7 = data[7];
}

// === AQUAHOT_COMMAND_2 (FF2F) ===
function decodeCommand(data, result) {
    // Byte 0: Instance [HIGH confidence] (Always 0x01)
    result.instance = data[0];

    // Byte 1: Command Type [HIGH confidence]
    //   0x07 = Quiet Mode (observed during quiet mode on/off from 0x9E)
    //   0x0A = Interior Heating Priority (observed during interior heating on/off from 0x9E)
    result.command_type = data[1];
    if (data[1] === 0x07) {
        result.command_name = "Quiet Mode";
    } else if (data[1] === 0x0a) {
        result.command_name = "Interior Heating Priority";
    } else {
        result.command_name = `Unknown (0x${data[1].toString(16)})`;
    }

    // Byte 2: Reserved [HIGH confidence] (Always 0x00)

    // Byte 3: Meaning depends on command type
    result.value_raw = data[3];
    if (data[1] === 0x07) {
        // Quiet Mode: byte 3 = on/off (0x01=On, 0x00=Off)
        result.quiet_mode_on = data[3] === 0x01;
    } else if (data[1] === 0x0a) {
        // Interior Heating Priority: byte 3 = on/off (0x01=On, 0x00=Off)
        result.interior_heating_on = data[3] === 0x01;
    }

    // Bytes 4-7: Reserved/Padding [HIGH confidence]
}

// === AQUAHOT_STATUS_2 (6C00) ===
function decodeStatus(data, result) {
    // Byte 0: Instance [HIGH confidence] (0xFF = all zones)
    result.instance = data[0];

    // Byte 1: Sub-Index [HIGH confidence]
    result.sub_index = data[1];

    // Bytes 2–5: Values [LOW confidence]
    result.value_a = data[2];
    result.value_b = data[3];
    result.value_c = data[4];
    result.value_d = data[5];
}

// === AQUAHOT_SYSTEM_STATUS_2 (FF2E) ===
function decodeSystemStatus(data, result) {
    // Byte 0: Instance [HIGH confidence] (Always 0x01)
    result.instance = data[0];

    // Byte 1: Sub-Index [HIGH confidence] (0x00 through 0x0B observed)
    result.sub_index = data[1];

    // Byte 2: Reserved [HIGH confidence] (Always 0xFF)

    // Byte 3: Value (primary) [MEDIUM confidence]
    result.primary_value = data[3];

    // Bytes 4-5: Value (secondary) [LOW confidence]
    result.secondary_value = decodeUint16(data, 4);

    // Bytes 6-7: Padding [HIGH confidence] (0xFF 0xFF)
}

// === Main Decode Function ===

function decodeAquaHotZone(dgn, dgn_name, data) {
    const result = {
        dgn: dgn,
        dgn_name: dgn_name,
    };

    if (data.length < 8) {
        result.error = "Data payload too short (expected 8 bytes)";
        return result;
    }

    // Include raw data for all proprietary analysis
    result.raw_byte0 = data[0];
    result.raw_byte1 = data[1];
    result.raw_byte2 = data[2];
    result.raw_byte3 = data[3];
    result.raw_byte4 = data[4];
    result.raw_byte5 = data[5];
    result.raw_byte6 = data[6];
    result.raw_byte7 = data[7];

    if (dgn_name === "AQUAHOT_THERMOSTAT_STATUS_2") {
        decodeZoneThermostat(data, result);
    } else if (dgn_name === "AQUAHOT_COMMAND_2") {
        decodeCommand(data, result);
    } else if (dgn_name === "AQUAHOT_SYSTEM_STATUS_2") {
        decodeSystemStatus(data, result);
    } else if (dgn_name === "AQUAHOT_STATUS_2") {
        decodeStatus(data, result);
    } else {
        result.error = `Unhandled AquaHot DGN: ${dgn_name}`;
    }

    return result;
}

// === Node-RED Parsing ===

if (!msg.payload || typeof msg.payload !== "object") {
    node.warn("Invalid payload: expected object");
    return null;
}

const incomingPayload = msg.payload;
const { dgn, dgn_name, data_payload } = incomingPayload;

if (!dgn || !dgn_name || !data_payload) {
    node.warn("Missing required fields: dgn, dgn_name, data_payload");
    return null;
}

if (typeof data_payload !== "string" || data_payload.length % 2 !== 0) {
    node.warn("Invalid data_payload: must be even-length hex string");
    return null;
}

const dataBytes = [];
for (let i = 0; i < data_payload.length; i += 2) {
    const hexByte = data_payload.substring(i, i + 2);
    const byteValue = parseInt(hexByte, 16);
    if (isNaN(byteValue)) {
        node.warn(`Invalid hex byte in data_payload: ${hexByte}`);
        return null;
    }
    dataBytes.push(byteValue);
}

const decodedData = decodeAquaHotZone(dgn, dgn_name, dataBytes);

if (decodedData.error) {
    incomingPayload.decoding_error = decodedData.error;
    msg.payload = incomingPayload;
    return msg;
}

// Merge the incoming payload and the decoded data
msg.payload = {
    ...incomingPayload,
    ...decodedData,
};

delete msg.payload.data_payload;

return msg;

// Encodes MQTT Climate commands into proprietary AquaHot zone CAN messages.
// Uses FF2F (AQUAHOT_COMMAND_2) cmd_type 0x0a for interior heating priority.

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "FF2F";

// --- Input Validation ---
const topic = msg.topic;
if (!topic) return null;

const payload = msg.payload;
const parts = topic.split("/");
// Expected: homeassistant/climate/aquahot_zone_{z}/{cmd}/set
const entityPart = parts[2];
if (!entityPart || !entityPart.startsWith("aquahot_zone_")) return null;

// E.g., aquahot_zone_1
const zoneMatch = entityPart.match(/aquahot_zone_(\d+)/);
if (!zoneMatch) return null;
const zone = parseInt(zoneMatch[1], 10);
if (isNaN(zone)) return null;

// From decode_aquahot_status_2.js:
// command_type 0x0a = Interior Heating Priority (on/off)

let isHeating = false;

if (topic.endsWith("/mode/set")) {
  const val = payload.toString().toLowerCase();
  if (val === "heat") {
    isHeating = true;
  } else if (val === "off") {
    isHeating = false;
  } else {
    return null;
  }
} else if (topic.endsWith("/temp/set")) {
  // Temperature setpoints are LOCAL to the wall panel (0x97). They are not
  // broadcast on the CAN bus. The panel compares room temp vs setpoint locally
  // and only sends zone demand on/off via WATERHEATER_COMMAND_2 (1FE98).
  // Confirmed by Phase 3 recordings: setpoint changes produced no new CAN traffic.
  node.warn(
    `[encode_aquahot_command_2] Temperature setpoints are local to the wall panel and cannot be set via CAN bus.`,
  );
  return null;
} else {
  return null;
}

// --- Build Payload (FF2F) ---
const dataBytes = new Array(8).fill(0xff);
dataBytes[0] = 0x01; // Byte 0: Instance
dataBytes[1] = 0x0a; // Byte 1: Command Type (Interior Heating = 0x0a)
dataBytes[2] = 0x00; // Byte 2: Reserved
dataBytes[3] = isHeating ? 0x01 : 0x00; // Byte 3: Status (0x01=ON, 0x00=OFF)
dataBytes[4] = 0x00;
dataBytes[5] = 0x00;

const dataHex = dataBytes
  .map((byte) => byte.toString(16).padStart(2, "0"))
  .join("");

// --- Construct CAN ID ---
const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// --- Send Message ---
node.send({
  topic: "can/send",
  payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
});

node.status({
  fill: "blue",
  shape: "dot",
  text: `Set Interior Heating Priority -> ${isHeating ? "ON" : "OFF"}`,
});

return null;

// Encodes AquaHot Commands (EF64)

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const DESTINATION_ADDRESS = 0x9f; // Aqua-Hot Module
const PRIORITY = 6; // Confirmed priority for Aqua-Hot control
const PGN = "EF64";
const PGN_INT = parseInt(PGN, 16);
const CONTROL_BYTE = 0xab; // First data byte for all commands

// --- Command Mapping (PGN EF64) ---
const COMMAND_MAP = {
    // Diesel Burner Control
    burner: {
        ON: 0xfd,
        OFF: 0xfc,
    },
    // AC Element 1 Control
    ac_1: {
        ON: 0xc7,
        OFF: 0xc3,
    },
    // AC Element 2 Control
    ac_2: {
        ON: 0xcb,
        OFF: 0xc3,
    },
    // Engine Pre-heat Control
    engine: {
        ON: 0x7f,
        OFF: 0x3f,
    },
};

// --- Input Validation ---
const instance = msg.instance; // Expects "burner", "ac_1", "ac_2", or "engine"
const command = msg.command; // Expects "ON" or "OFF"

if (!instance || !COMMAND_MAP[instance]) {
    node.warn(
        `[encode_aquahot] Invalid instance: "${instance}". Expected one of: burner, ac_1, ac_2, engine`,
    );
    return null;
}

if (!command || !COMMAND_MAP[instance][command]) {
    node.warn(
        `[encode_aquahot] Invalid command: "${command}". Expected "ON" or "OFF"`,
    );
    return null;
}

// --- Build Payload ---
const dataByte2 = COMMAND_MAP[instance][command];

// Build the 8-byte data payload
const dataBytes = new Array(8).fill(0xff);
dataBytes[0] = CONTROL_BYTE; // AB
dataBytes[1] = dataByte2; // The specific command byte

const dataHex = dataBytes
    .map((byte) => byte.toString(16).padStart(2, "0"))
    .join("");

// --- Construct CAN ID ---
// PGN EF64 is a PDU1 format (PF < 240) so the destination address (0x9F) goes in the last byte
const canIdInt = (PRIORITY << 26) | (PGN_INT << 8) | DESTINATION_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// --- Send Message ---
node.send({
    topic: "can/send",
    payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
});

return null;

// HA Status Publisher for Geo Bridge (can/status/geo)
// Self-creating: publishes MQTT discovery on first valid reading.

if (!global.get("geoEnabled")) return null;

if (!msg.payload) {
  return null;
}

// In case the MQTT node isn't set to parse JSON automatically
let p = msg.payload;
if (typeof p === "string") {
  try {
    p = JSON.parse(p);
  } catch (e) {
    node.warn("Failed to parse geo payload as JSON");
    return null;
  }
}

if (p.status !== "online") {
  return null; // Ignore 'unavailable' or 'offline' status messages for now
}

// === Flow context: track which entities have had discovery published ===
const CREATED_KEY = "geoSensorsCreated";
let created = flow.get(CREATED_KEY);

const messages = [];

if (!created) {
  const device = {
    identifiers: ["librecoach-geo"],
    name: "Location",
    manufacturer: "LibreCoach",
  };

  const createSensor = (id, name, icon, unit) => {
    const entityId = `geo_${id}`;
    const payload = {
      name: name,
      unique_id: entityId,
      default_entity_id: `sensor.${entityId}`,
      icon: icon,
      state_topic: `homeassistant/sensor/${entityId}/state`,
      device: device,
    };
    if (unit) payload.unit_of_measurement = unit;

    messages.push({
      topic: `homeassistant/sensor/${entityId}/config`,
      payload: payload,
    });
  };

  createSensor("city", "City", "mdi:city");
  createSensor("state", "State", "mdi:map-marker");
  createSensor("timezone", "Timezone", "mdi:clock-outline");
  createSensor("elevation", "Elevation", "mdi:image-filter-hdr", "m");

  created = true;
  flow.set(CREATED_KEY, created);
}

// Publish states
if (p.city !== undefined)
  messages.push({
    topic: `homeassistant/sensor/geo_city/state`,
    payload: p.city,
  });
if (p.state !== undefined)
  messages.push({
    topic: `homeassistant/sensor/geo_state/state`,
    payload: p.state,
  });
if (p.timezone !== undefined)
  messages.push({
    topic: `homeassistant/sensor/geo_timezone/state`,
    payload: p.timezone,
  });
if (p.elevation !== undefined)
  messages.push({
    topic: `homeassistant/sensor/geo_elevation/state`,
    payload: p.elevation,
  });

return [messages];

// Unique Filter for Floor Heat

// --- Configuration ---
const instanceKey = "uniqueFloorHeat"; // Session-only
const levelsKey = "uniqueFloorHeatLevels"; // Persistent

// Get data from payload ---
const instanceId = msg.payload.instance;
const raw_setpoint = msg.payload.raw_setpoint;

// Validate input ---
if (typeof instanceId !== "number") {
  return null; // No instance, can't proceed
}

// We only want to discover a level if:
// The setpoint is within a plausible floor heat range (32°F–120°F)
// RVC raw range: 8746 (32°F/0°C) to 12576 (120°F/~49°C)
// Note: schedule_mode is not checked because the store level is always
// reported with schedule_mode "Disabled", preventing its discovery.
const isValidLevel =
  typeof raw_setpoint === "number" &&
  raw_setpoint >= 8746 &&
  raw_setpoint <= 12576;

// Get context lists ---
let instanceList = flow.get(instanceKey) || [];
let levelList = global.get(levelsKey, "file") || [];

let isNewInstance = false;
let isNewLevel = false;

// Process Instance ---
if (!instanceList.includes(instanceId)) {
  isNewInstance = true;
  instanceList.push(instanceId);
  flow.set(instanceKey, instanceList); // Save to session context
}

// Process Level ---
if (isValidLevel && !levelList.includes(raw_setpoint)) {
  isNewLevel = true;
  levelList.push(raw_setpoint);
  levelList.sort((a, b) => a - b);
