  if (value <= 200) {
    return value; // Direct instance number (Zone)
  } else if (value === 251) {
    return "Error";
  } else if (value === 252) {
    return "Not Supported";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

function decodeCurrentScheduleInstance(value) {
  // Current schedule instance — spec says uint8 instance, no labeled values defined
  if (value === 255) return null;
  return value; // Plain instance number
}

function decodeScheduleInstances(value) {
  // Number of schedule instances capacity
  if (value <= 200) {
    return value; // Direct count
  } else if (value === 251) {
    return "Error";
  } else if (value === 252) {
    return "Not Supported";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

