    0x03: "Off Delay",
    0x04: "Stop",
    0x05: "Toggle",
    0x06: "Memory Off",
    0x07: "Save Scene",
    0x0b: "Ramp Brightness",
    0x0c: "Ramp Toggle",
    0x0d: "Ramp Up",
    0x0e: "Ramp Down",
    0x0f: "Ramp Up/Down",
    0x10: "Ramp Up/Down Toggle",
    0x15: "Lock",
    0x16: "Unlock",
    0x1f: "Flash",
