// Status Updater for Charger AC
// Decodes CHARGER_AC_STATUS messages

// === Helper Functions ===

function decodeBits(value, startBit, endBit) {
  const mask = ((1 << (endBit - startBit + 1)) - 1) << startBit;
  return (value & mask) >> startBit;
}

// === CHARGER_AC_STATUS Specific Decoders ===

function decodeChargerACInstance(value) {
  // §6.20.2 / §6.19.2 — instance byte is a bit field
  return {
    charger_instance: value & 0x0f, // bits 0-3
    line: (value >> 4) & 0x03, // bits 4-5: 0=Line 1, 1=Line 2
    input_output: (value >> 6) & 0x03, // bits 6-7: 0=Input, 1=Output
  };
