  componentType === "select" ||
  componentType === "switch"
) {
  payload.command_topic = `librecoach/victron/set/${service_type}/${instance}${dbus_path}`;
  payload.optimistic = true;
}

if (componentType === "switch") {
  payload.payload_on = "1";
  payload.payload_off = "0";
  payload.state_on = "ON";
  payload.state_off = "OFF";
  payload.optimistic = false;
  payload.value_template =
    "{{ 'ON' if (value_json | default({'value': 0})).value | int == 1 else 'OFF' }}";
} else if (componentType === "number") {
  // Safe defaults for unknown numeric writable paths
  payload.min = 0;
  payload.max = 100;
  payload.step = 0.5;

  // Specific overrides based on path
  if (dbus_path.endsWith("/Soc")) {
    payload.max = 100;
    payload.step = 1;
  } else if (dbus_path.endsWith("/CurrentLimit")) {
    payload.max = 100;
    payload.step = 0.5;
    payload.mode = "box";
  }
}

// Add device_class if defined
if (haMetadata.device_class && componentType !== "select") {
  payload.device_class = haMetadata.device_class;
  payload.state_class = "measurement";
}

// Add unit_of_measurement if defined (excluding select)
if (haMetadata.unit && componentType !== "select") {
  payload.unit_of_measurement = haMetadata.unit;
}

// Apply precision formatting for numeric values, excluding switches and selects.
if (componentType === "sensor" || componentType === "number") {
  // Default to 1 decimal place if not specified
  const precision =
    haMetadata.precision !== undefined ? haMetadata.precision : 1;
  payload.value_template = `{{ (value_json | default({'value': 0})).value | float | round(${precision}) }}`;
}

// For enum values, build a Jinja2 template to map numeric values to labels
if (isEnum && componentType === "select") {
  const enumParts = effectiveUnit.split(";").map((p) => p.trim());
  const mappings = {};
  for (const part of enumParts) {
    const [val, label] = part.split("=");
    if (val !== undefined && label !== undefined) {
      mappings[val.trim()] = label.trim();
    }
  }

  // Build Jinja2 map template
  const mapEntries = Object.entries(mappings)
    .map(([k, v]) => `'${k}': '${v}'`)
    .join(", ");
  payload.value_template = `{% set vj = value_json | default({'value': ''}) %}{% set m = {${mapEntries}} %}{{ m.get(vj.value | string, vj.value) }}`;

  if (componentType === "select") {
    payload.options = Object.values(mappings);
  }
}

// Republish the discovery config only when its payload changes.
const sigKey = `victron_${entityId}_dsig`;
const signature = JSON.stringify(payload);
if (global.get(sigKey, "file") === signature) {
  return null;
}
global.set(sigKey, signature, "file");

// Prepare final message
msg.topic = discoveryTopic;
msg.payload = payload;
msg.stateTopic = stateTopic;

// Send cleanup payloads for obsolete component types so they don't linger in HA
if (dbus_path.endsWith("/CurrentLimit")) {
  node.send({ topic: `homeassistant/select/${entityId}/config`, payload: "" });
  node.send({ topic: `homeassistant/sensor/${entityId}/config`, payload: "" });
} else if (dbus_path.includes("/Relay/")) {
  node.send({ topic: `homeassistant/sensor/${entityId}/config`, payload: "" });
}

return msg;

// HA Status Updater for Victron

const incomingPayload = msg.payload;

// Gate: skip null/undefined/empty values
if (
  incomingPayload.value === null ||
  incomingPayload.value === undefined ||
  incomingPayload.value === ""
) {
  return null;
}

const { service_type, instance, dbus_path, value } = incomingPayload;

// 1. Context-Aware Rounding (Filter Logic)
let roundedValue = value;
if (typeof value === "number") {
  // Round SOC to whole numbers, everything else to 1 decimal
  const decimals = dbus_path.toLowerCase().includes("soc") ? 0 : 1;
  const factor = Math.pow(10, decimals);
  roundedValue = Math.round(value * factor) / factor;
}

// 2. Report by Exception (Filter Logic)
const lastValues = context.get("lastValues") || {};
const publishedState = context.get("publishedState") || {};
const cacheKey = `${service_type}_${instance}_${dbus_path}`;
const alwaysPublishState =
  dbus_path === "/Mode" || dbus_path === "/Ac/ActiveIn/CurrentLimit";

if (
  lastValues[cacheKey] === roundedValue &&
  publishedState[cacheKey] &&
  !alwaysPublishState
) {
  return null; // Block if rounded value hasn't changed
}
lastValues[cacheKey] = roundedValue;
publishedState[cacheKey] = true;
context.set("lastValues", lastValues);
context.set("publishedState", publishedState);

// 3. Build Entity ID (Status Logic)
const safePathRaw = dbus_path
  .replace(/^\//, "")
  .replace(/\//g, "_")
  .toLowerCase();

let safePath = safePathRaw;

// Standardization Rules
if (
  ["charger", "dcdc", "alternator", "solarcharger"].includes(service_type) &&
  safePath.includes("dc_0")
) {
  safePath = safePath.replace("dc_0", "dc_out");
}

safePath = safePath
  .replace("_activein", "_in")
  .replace("_active_in", "_in")
  .replace("_active_input", "_in");

// Suffix expansion
if (safePath.endsWith("_p")) safePath = safePath.slice(0, -2) + "_power";
else if (safePath.endsWith("_v")) safePath = safePath.slice(0, -2) + "_voltage";
else if (safePath.endsWith("_i")) safePath = safePath.slice(0, -2) + "_current";
else if (safePath.endsWith("_f"))
  safePath = safePath.slice(0, -2) + "_frequency";

// Total power enforcement
if (safePath.endsWith("_total_p"))
  safePath = safePath.replace(/_total_p$/, "_total_power");
else if (safePath.endsWith("_ac_power"))
  safePath = safePath.replace(/_ac_power$/, "_ac_total_power");
else if (safePath === "ac_power") safePath = "ac_total_power";

// Look up product name
const victronDevices = global.get("victronDevices", "file") || {};
const deviceInfo = victronDevices[`${service_type}_${instance}`];
const deviceName = deviceInfo ? deviceInfo.shortName : service_type;
const entityId = `victron_${deviceName}_${instance}_${safePath}`;

// 4. Determine Component Type & Topic
let componentType = "sensor";
if (dbus_path === "/Ac/ActiveIn/CurrentLimit") componentType = "number";
else if (dbus_path === "/Mode") componentType = "select";
else if (dbus_path.includes("/Relay/")) componentType = "switch";

// 5. Build Final Message
msg.topic = `homeassistant/${componentType}/${entityId}/state`;
msg.payload = { value: roundedValue };

return msg;

// Parse Victron attributes CSV and store as nested Map in global context

const csvText = msg.payload;

if (!csvText || typeof csvText !== "string") {
  node.warn("store_victron_map: No CSV data received");
  return null;
}

const lines = csvText.split("\n").filter((line) => line.trim().length > 0);

// Build nested Map: serviceType → Map(path → { type, unit, scale, access })
const victronMap = new Map();

for (const line of lines) {
  const parts = line.split(",");
  if (parts.length < 8) continue;

  const [service, path, type, unit, register, dataType, scale, access] =
    parts.map((p) => p.trim());

  // Strip "com.victronenergy." prefix to get short service type
  const serviceType = service.replace("com.victronenergy.", "");

  if (!victronMap.has(serviceType)) {
    victronMap.set(serviceType, new Map());
  }

  victronMap.get(serviceType).set(path, {
    type,
    unit,
    scale,
    access,
  });
}

// Store in global context
global.set("victronMap", victronMap);

// Count total records across all service types
let totalRecords = 0;
for (const [, pathMap] of victronMap) {
  totalRecords += pathMap.size;
}

node.status({
  fill: "green",
  shape: "dot",
  text: "Reference loaded",
});

return null;

// Encodes AUTOFILL_COMMAND messages (1FFB0)

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "1FFB0"; // AUTOFILL_COMMAND

// --- Input Validation ---
const command = msg.command; // Expects "ON" or "OFF"

// --- Command Mapping ---
let commandValue;
switch (command) {
  case "ON":
    // Universal ON command that works on standard and non-standard systems
    commandValue = 0xfd;
    break;
  case "OFF":
    // Universal OFF command
    commandValue = 0xfc;
    break;
  default:
    node.warn(
      `[encode_autofill_command] Invalid command: "${command}". Expected "ON" or "OFF"`,
    );
    return null;
}

// --- Build Payload ---
const dataBytes = new Array(8).fill(0xff);
dataBytes[0] = commandValue; // Byte 0: Command value

const dataHex = dataBytes
  .map((byte) => byte.toString(16).padStart(2, "0"))
  .join("");

// Construct the CAN ID
const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// --- Send Message ---
node.send({
  topic: "can/send",
  payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
});

return null;

// Polling Function for Water Pump
// Requests WATER_PUMP_STATUS (1FFB3)

// --- Configuration ---
// The source address of this Node-RED system.
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;       // Standard priority for requests
const DGN = "18EAFF";     // DGN for a broadcast request message

// Build the data payload
// This is the DGN for WATER_PUMP_STATUS (1FFB3), sent in little-endian format (least-significant byte first).
const data_payload = "B3FB01FFFFFFFF";

// Construct the CAN ID
const dgnInt = parseInt(DGN, 16);
const canIdInt = (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, '0');

// Construct the final output message in CAN bus format
msg.topic = "can/send";
msg.payload = `${canIdHex.toUpperCase()}#${data_payload.toUpperCase()}`;

//node.warn(`[Poll Water Pump] Sending global request for water pump status. CAN: ${msg.payload}`);

return msg;

