// Decodes FURNACE_STATUS messages (1FFE4)
// RV-C spec 6.15.2

// === Helper Functions ===

function decodeBits(value, startBit, endBit) {
  const mask = ((1 << (endBit - startBit + 1)) - 1) << startBit;
  return (value & mask) >> startBit;
}

function decodeOperatingMode(value) {
  const modes = {
    0: "Auto",
    1: "Manual",
    2: "Reserved",
    3: "Not Available",
  };
  return modes[value] || `Unknown (${value})`;
}

function decodeHeatSource(value) {
  const sources = {
    0: "Combustion",
    1: "AC Primary",
    2: "AC Secondary",
    3: "Engine",
    4: "Hydronic Combustion",
    5: "Hydronic Electric",
    6: "Hydronic Both",
  };
  // Handle standard RV-C default/missing values beyond the 6 values defined
  if (value === 0x3e) return "Reserved";
  if (value === 0x3f) return "Not Available";
  return sources[value] || `Unknown (${value})`;
}

function decodePercentage(value, step = 1) {
  if (value <= 250) {
    return parseFloat((value * step).toFixed(2));
  } else if (value === 251) {
    return "Error";
  } else if (value === 252) {
    return "Not Supported";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

function decodeDeadband(value) {
  if (value <= 250) {
    return parseFloat((value * 0.1).toFixed(1)); // 0.1°C step
  } else if (value === 251) {
    return "Error";
  } else if (value === 252) {
    return "Not Supported";
  } else if (value === 253) {
    return "Out of Range";
  } else if (value === 254) {
    return "Reserved";
  } else if (value === 255) {
    return "Not Available";
  }
  return "Invalid";
}

function decodeWarning(value) {
  const statuses = {
    0: "Normal",
    1: "Warning",
    2: "Reserved",
    3: "Not Available",
  };
  return statuses[value] || `Unknown (${value})`;
}

function decodeStatusFlag(value) {
  const statuses = {
    0: "Inactive",
    1: "Active",
    2: "Reserved",
    3: "Not Available",
  };
  return statuses[value] || `Unknown (${value})`;
}

// === Main Decode Function ===

function decodeFurnaceStatusMessage(dgn, data) {
  const result = {
    dgn: dgn,
    dgn_name: "FURNACE_STATUS",
  };

  if (data.length < 8) {
    result.error = "Data payload too short (expected 8 bytes)";
    return result;
  }

  // Byte 0: Instance
  result.instance = data[0];
  result.raw_instance = data[0];

  // Byte 1: Operating Mode (bits 0-1), Heat Source (bits 2-7)
  const byte1 = data[1];
  const operatingModeRaw = decodeBits(byte1, 0, 1);
  result.operating_mode = decodeOperatingMode(operatingModeRaw);
  result.raw_operating_mode = operatingModeRaw;

  const heatSourceRaw = decodeBits(byte1, 2, 7);
  result.heat_source = decodeHeatSource(heatSourceRaw);
  result.raw_heat_source = heatSourceRaw;

  // Byte 2: Circulation Fan Speed (0.5%/step)
  result.circulation_fan_speed = decodePercentage(data[2], 0.5);
  result.raw_circulation_fan_speed = data[2];

  // Byte 3: Heat Output Level (1%/step)
  result.heat_output_level = decodePercentage(data[3], 1.0);
  result.raw_heat_output_level = data[3];

  // Byte 4: Dead Band (0.1°C)
  result.dead_band = decodeDeadband(data[4]);
  result.raw_dead_band = data[4];

  // Byte 5: Second Stage Dead Band (0.1°C)
  result.second_stage_dead_band = decodeDeadband(data[5]);
  result.raw_second_stage_dead_band = data[5];

  // Byte 6: Faults
  const byte6 = data[6];
  const overcurrentRaw = decodeBits(byte6, 0, 1);
  result.overcurrent = decodeWarning(overcurrentRaw);

  const undercurrentRaw = decodeBits(byte6, 2, 3);
  result.undercurrent = decodeWarning(undercurrentRaw);

  const tempWarningRaw = decodeBits(byte6, 4, 5);
  result.temperature_warning = decodeWarning(tempWarningRaw);

  const analogInputRaw = decodeBits(byte6, 6, 7);
  result.analog_input_active = decodeStatusFlag(analogInputRaw);

  result.raw_byte6 = byte6;

  // Convenience fields
  result.is_hydronic =
    typeof heatSourceRaw === "number" &&
    heatSourceRaw >= 4 &&
    heatSourceRaw <= 6;

  result.furnace_active =
    (typeof result.circulation_fan_speed === "number" &&
      result.circulation_fan_speed > 0) ||
    (typeof result.heat_output_level === "number" &&
      result.heat_output_level > 0);

  result.has_fault =
    result.overcurrent === "Warning" ||
    result.undercurrent === "Warning" ||
    result.temperature_warning === "Warning";

  return result;
}

// === Main Logic ===

// Validate input payload
if (!msg.payload || typeof msg.payload !== "object") {
  node.warn("Invalid payload: expected object");
  return null;
}

const incomingPayload = msg.payload;
const { dgn, dgn_name, data_payload } = incomingPayload;

if (!dgn || !dgn_name || !data_payload) {
  node.warn("Missing required fields: dgn, dgn_name, and/or data_payload");
  return null;
}

// Validate and convert hex payload to byte array
if (typeof data_payload !== "string" || data_payload.length % 2 !== 0) {
  node.warn("Invalid data_payload: must be even-length hex string");
  return null;
}

const dataBytes = [];
for (let i = 0; i < data_payload.length; i += 2) {
  const hexByte = data_payload.substring(i, i + 2);
  const byteValue = parseInt(hexByte, 16);
  if (isNaN(byteValue)) {
    node.warn(`Invalid hex byte in data_payload: ${hexByte}`);
    return null;
  }
  dataBytes.push(byteValue);
}

// Decode the message
const decodedData = decodeFurnaceStatusMessage(dgn, dataBytes);

// Handle decode errors
if (decodedData.error) {
  incomingPayload.decoding_error = decodedData.error;
  msg.payload = incomingPayload;
  return msg;
}

// Merge the incoming payload and the decoded data into a single flat object
msg.payload = {
  ...incomingPayload,
  ...decodedData,
};

// Clean up the final object by removing the raw data field
delete msg.payload.data_payload;

return msg;

// Centralized Notification Handler
// Input: msg.payload with { title, message, notification_id }
// Output: msg configured for HTTP Request to HA notification service

const haBaseUrl = "http://supervisor/core";
const haToken = env.get("SUPERVISOR_TOKEN");

if (!haToken) {
    node.warn("No Supervisor token - skipping notification");
    return null;
}

const payload = msg.payload || {};

if (!payload.title || !payload.message) {
    node.warn("Notification missing title or message");
    return null;
}

msg.url = `${haBaseUrl}/api/services/persistent_notification/create`;
msg.method = "POST";
msg.headers = {
    Authorization: `Bearer ${haToken}`,
    "Content-Type": "application/json",
};

msg.payload = {
    title: payload.title,
    message: payload.message,
    notification_id: payload.notification_id || "librecoach_notification",
};

return msg;

// Broadcasts DATE_TIME_STATUS to the RV-C network (DGN 1FFFFh, §6.4)
// Fires every 60s via inject node. Gated by timeSyncEnabled global (default: false).
// Note: spec nominal interval is 1000 ms; 60s is adequate for clock correction without
// competing with a hardware master. No source-address arbitration is implemented here.

// --- Configuration ---
const PRIORITY = 6;
const DGN = 0x1ffff;
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;

// --- Feature Gate ---
const timeSyncEnabled = global.get("timeSyncEnabled");
if (!timeSyncEnabled) return null;

// --- Current Time ---
const dt = new Date();

// --- Helpers ---
// RV-C DOW: 1=Sunday..7=Saturday (JS getDay(): 0=Sun..6=Sat)
const rvcDow = (jsDow) => (jsDow === 0 ? 1 : jsDow + 1);

// Derive TZ code from system UTC offset: std offset in hours, minus 1 if DST active
const jan = new Date(dt.getFullYear(), 0, 1).getTimezoneOffset();
const jul = new Date(dt.getFullYear(), 6, 1).getTimezoneOffset();
const std = Math.max(jan, jul);
const isDst = dt.getTimezoneOffset() < std;
const tzCode = isDst ? std / 60 - 1 : std / 60;

// --- Payload ---
// Byte layout per RV-C §6.4 Table 6.4.2b: year(offset 2000), month, day, dow, hour, min, sec, tz
const dataBytes = [
  Math.max(0, Math.min(255, dt.getFullYear() - 2000)), // Byte 0: Year (2000..2255)
  dt.getMonth() + 1, // Byte 1: Month (1..12)
  dt.getDate(), // Byte 2: Day (1..31)
  rvcDow(dt.getDay()), // Byte 3: Day of week (1..7)
  dt.getHours(), // Byte 4: Hour (0..23)
  dt.getMinutes(), // Byte 5: Minute (0..59)
  dt.getSeconds(), // Byte 6: Second (0..59)
  tzCode & 0xff, // Byte 7: Timezone code
];

// --- Build and Send ---
const dataHex = dataBytes
  .map((b) => b.toString(16).padStart(2, "0"))
  .join("")
  .toUpperCase();
const canIdInt = (PRIORITY << 26) | (DGN << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0").toUpperCase();

node.status({
  fill: "green",
  shape: "dot",
  text: `${dt.getMonth() + 1}/${dt.getDate()} ${dt.getHours().toString().padStart(2, "0")}:${dt.getMinutes().toString().padStart(2, "0")}:${dt.getSeconds().toString().padStart(2, "0")} tz=${tzCode}`,
});

return { topic: "can/send", payload: `${canIdHex}#${dataHex}` };

// Encodes AquaHot switch commands via 1FE98 (WATERHEATER_COMMAND_2) and FF2F (AQUAHOT_COMMAND_2)
// Uses FF2F (AQUAHOT_COMMAND_2) cmd_type 0x0a for interior heating priority
// Entity IDs: aquahot_diesel_burner, aquahot_electric_element, aquahot_quiet_mode, aquahot_interior_heating

const SOURCE_ADDRESS = global.get("rvc_source_address") || 0x9e;

const entityId = msg.entityId;
const command = msg.command; // "ON" or "OFF"

if (!entityId || !command) return null;

function send1FE98(byte1, byte2) {
  // CAN ID: priority 6, DGN 1FE98, source address
  // DGN 1FE98 is PDU2 format (PF >= 240), so full 18-bit DGN goes in bits 25-8
  // Result for source 0x9E: 0x19FE989E
  const DGN_INT = 0x1FE98;
  const PRIORITY = 6;
  const canIdInt = (PRIORITY << 26) | (DGN_INT << 8) | SOURCE_ADDRESS;
  const canIdHex = canIdInt.toString(16).padStart(8, "0");
  const dataBytes = new Array(8).fill(0xff);
  dataBytes[1] = byte1;
  dataBytes[2] = byte2;
  const dataHex = dataBytes.map(b => b.toString(16).padStart(2, "0")).join("");
  node.send({ topic: "can/send", payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}` });
}

function sendFF2F(cmdType, isOn) {
  // CAN ID: priority 6, DGN FF2F, source address
  // Result for source 0x9E: 0x18FF2F9E
  const DGN_INT = 0xFF2F;
  const PRIORITY = 6;
  const canIdInt = (PRIORITY << 26) | (DGN_INT << 8) | SOURCE_ADDRESS;
  const canIdHex = canIdInt.toString(16).padStart(8, "0");
  const dataBytes = new Array(8).fill(0xff);
  dataBytes[0] = 0x01;      // instance
  dataBytes[1] = cmdType;
  dataBytes[2] = 0x00;
  dataBytes[3] = isOn ? 0x01 : 0x00;
  dataBytes[4] = 0x00;
  dataBytes[5] = 0x00;
  const dataHex = dataBytes.map(b => b.toString(16).padStart(2, "0")).join("");
  node.send({ topic: "can/send", payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}` });
}

switch (entityId) {
  case "aquahot_diesel_burner":
    // Toggle semantics — send toggle regardless of ON/OFF command
    send1FE98(0xF6, 0xFF);
    node.status({ fill: "blue", shape: "dot", text: `Diesel burner toggle (${command})` });
    break;
  case "aquahot_electric_element":
    // Toggle semantics
    send1FE98(0x6F, 0xFF);
    node.status({ fill: "blue", shape: "dot", text: `Electric element toggle (${command})` });
    break;
  case "aquahot_quiet_mode":
    sendFF2F(0x07, command === "ON");
    node.status({ fill: "blue", shape: "dot", text: `Quiet mode -> ${command}` });
    break;
  case "aquahot_interior_heating":
    sendFF2F(0x0a, command === "ON");
    node.status({ fill: "blue", shape: "dot", text: `Interior heating -> ${command}` });
    break;
  default:
    node.warn(`[encode_waterheater_command_2] Unknown entityId: ${entityId}`);
}

return null;

// HA Status Publisher for DC Load (DGN 1FFBDh, §6.23.2)
// Self-creating: publishes MQTT discovery on first valid reading per instance.
// Output 1: MQTT messages (discovery + state)
// Entity naming: switch_l_N (routing key "switch_l"), "Switches" device.

if (!msg.payload || typeof msg.payload !== "object") {
    return null;
}

const p = msg.payload;
const instance = p.instance;

if (typeof instance !== "number" || instance < 1 || instance > 250) {
    return null;
}

const opStatus = p.operating_status;
if (opStatus === undefined || opStatus === "Not Available") {
    return null;
}

// Dimmable detection
const dimmableLights = global.get("dimmableLights", "file") || [];
let isDimmable = dimmableLights.includes(instance);

function markDimmable() {
    if (!isDimmable) {
        dimmableLights.push(instance);
        global.set("dimmableLights", dimmableLights, "file");
        isDimmable = true;
    }
}

// Detect dimmable via spec bit
if (p.variable_level_capability === true) {
    markDimmable();
}

// Determine state and brightness
let haStatus;
let brightness;

if (typeof opStatus === "number") {
    haStatus = opStatus > 0 ? "ON" : "OFF";
    brightness = opStatus;

    // Detect dimmable via operating status range (1-99%)
    if (opStatus > 0 && opStatus < 100) {
        markDimmable();
    }
} else if (opStatus === "Load Delay Active") {
    haStatus = "ON";
} else {
    return null;
}

// Entity identifiers — switch_l_N distinguishes from DC_DIMMER's switch_N
const entityId = `switch_l_${instance}`;
const stateTopic = `homeassistant/light/${entityId}/state`;
const commandTopic = `homeassistant/light/${entityId}/set`;

const messages = [];

// Self-creating discovery: (re)publish whenever advertised capability differs
// from last published — self-corrects after any context/broker desync.
const CREATED_KEY = "dcLoadCreated";
const created = flow.get(CREATED_KEY) || {};
const desiredMode = isDimmable ? "brightness" : "onoff";

if (created[instance] !== desiredMode) {
    const config = {
        name: `Switch ${instance}`,
        unique_id: entityId,
        default_entity_id: `light.${entityId}`,
        icon: "mdi:light-recessed",
        schema: "json",
        command_topic: commandTopic,
        state_topic: stateTopic,
        availability_mode: "all",
        availability: [
            {
                topic: "librecoach/nodered/status",
                payload_available: "online",
                payload_not_available: "offline",
            },
            {
                topic: "can/status",
                value_template: "{{ 'online' if value == 'online' else 'offline' }}",
                payload_available: "online",
                payload_not_available: "offline",
            },
        ],
        device: {
            identifiers: ["librecoach-switches"],
            name: "Switches",
            manufacturer: "LibreCoach",
        },
    };

    if (isDimmable) {
        config.brightness = true;
        config.brightness_scale = 100;
        config.supported_color_modes = ["brightness"];
    } else {
        config.supported_color_modes = ["onoff"];
    }

    messages.push({
        topic: `homeassistant/light/${entityId}/config`,
        payload: config,
    });

    created[instance] = desiredMode;
    flow.set(CREATED_KEY, created);
}

// Store last brightness for dimmable recall on toggle
if (isDimmable && typeof brightness === "number" && brightness > 0) {
    global.set("dimmerBrightness_" + instance, brightness, "file");
}

// Build JSON state payload
const stateObj = { state: haStatus };

if (haStatus === "ON") {
    if (isDimmable) {
        stateObj.color_mode = "brightness";
        if (brightness !== undefined) {
            stateObj.brightness = brightness;
        }
    } else {
        stateObj.color_mode = "onoff";
    }
}

messages.push({
    topic: stateTopic,
    payload: JSON.stringify(stateObj),
});

return [messages];

const victronEnabled = global.get("victronEnabled");
if (!victronEnabled) return null;

const portalId = msg.payload.value;

// Store the ID in global context (file store — survives restarts)
global.set("victronPortalId", portalId, "file");

node.status({
    fill: "green",
    shape: "dot",
    text: portalId,
});

// Encode MicroAir Command to MQTT
// Input: HA command payload (string or number)
// Topic determines command type: .../mode/set, .../temp/set, .../fan/set
// Reads cached zone state from global context for mode-aware encoding

const topic = msg.topic;
const parts = topic.split("/");
// Expected: homeassistant/climate/microair_{safeMac}_zone_{z}/{cmd}/set

// 1. Extract Entity ID
const entityPart = parts[2]; // microair_{safeMac}_zone_{z}
if (!entityPart || !entityPart.startsWith("microair_")) return null;

const subParts = entityPart.split("_");
// microair, 78, e3, 6d, fc, 5e, ce, zone, {z}
const zoneIdx = subParts.indexOf("zone");
if (zoneIdx < 2) return null;

const safeMac = subParts.slice(1, zoneIdx).join("_");
const mac = subParts.slice(1, zoneIdx).join(":");
const zone = parseInt(subParts[zoneIdx + 1]);

if (!mac || isNaN(zone)) return null;

// Read cached zone state for mode-aware encoding
const cached = global.get(`microair_${safeMac}_zone_${zone}`, "file") || {};
const currentMode = cached.mode || "off";
const currentModeNum = cached.mode_num || 0;

// Read observed max fan speed for dynamic mapping
const maxFanSpeed =
  global.get(`microair_${safeMac}_zone_${zone}_maxfan`, "file") || 2;

// 2. Determine Command Type
let change = {};
let val = msg.payload;

const MODE_MAP = {
  off: 0,
  fan_only: 1,
  cool: 2,
  heat: 5,
  auto: 11,
};

// Dynamic fan map based on observed speed count
const FAN_MAP =
  maxFanSpeed >= 3
    ? { low: 1, medium: 2, high: 3, auto: 128 } // 3-speed
    : { low: 1, high: 2, auto: 128 }; // 2-speed

if (topic.endsWith("/mode/set")) {
  // HA sends: "cool", "heat", "off", etc.
  if (val in MODE_MAP) {
    let modeNum = MODE_MAP[val];
    // Preserve last-used heat type when switching back to heat mode
    if (val === "heat") {
      const lastHeat = global.get(
        `microair_${safeMac}_zone_${zone}_lastheat`,
        "file",
      );
      if (lastHeat) {
        modeNum = lastHeat;
      }
    }
    change.mode = modeNum;
    change.power = 1;
  } else {
    return null;
  }
} else if (topic.endsWith("/temp/set")) {
  // HA sends number: 72
  // Set only the setpoint for the current HVAC mode
  const temp = parseFloat(val);
  if (currentMode === "cool") {
    change.cool_sp = temp;
  } else if (currentMode === "heat") {
    change.heat_sp = temp;
  } else if (currentMode === "auto") {
    // HA MQTT climate sends a single temp for auto mode via this topic.
    // Set both setpoints — HA should use temp_high/temp_low topics for
    // separate auto setpoints, but fallback keeps behavior reasonable.
    change.autoCool_sp = temp;
    change.autoHeat_sp = temp;
  } else {
    // Fallback: set cool_sp as default
    change.cool_sp = temp;
  }
} else if (topic.endsWith("/temp_high/set")) {
  // Auto mode high setpoint (cool target)
  change.autoCool_sp = parseFloat(val);
} else if (topic.endsWith("/temp_low/set")) {
  // Auto mode low setpoint (heat target)
  change.autoHeat_sp = parseFloat(val);
} else if (topic.endsWith("/preset/set")) {
  // HA sends: "Heat Pump", "Furnace", "Gas Furnace", etc.
  const PRESET_MAP = {
    "Heat Pump": 5,
    Furnace: 4,
    "Gas Furnace": 3,
    "Heat Strip": 7,
    "Electric Heat": 12,
  };
  if (val in PRESET_MAP) {
    change.mode = PRESET_MAP[val];
    change.power = 1;
    // Set the correct fan field for this heat type
    const fanNum =
      change.mode === 3 || change.mode === 4
        ? cached.furnace_fan_mode_num || 128
        : cached.heat_fan_mode_num || 128;
    if (change.mode === 3 || change.mode === 4) {
      change.gasFan = fanNum;
    } else {
      change.eleFan = fanNum;
    }
  } else {
    return null;
  }
} else if (topic.endsWith("/fan/set")) {
  // HA sends: "low", "high", "medium", "auto"
  if (!(val in FAN_MAP)) return null;

  const fanValue = FAN_MAP[val];

  // Use mode-specific fan key based on current HVAC mode
  if (currentMode === "fan_only") {
    // Fan-only mode doesn't support auto — default to max speed
    change.fanOnly = fanValue === 128 ? maxFanSpeed : fanValue;
  } else if (currentMode === "cool") {
    change.coolFan = fanValue;
  } else if (currentMode === "heat") {
    // Gas furnace (mode 3,4) vs electric heat (mode 5,6,7,12)
    if (currentModeNum === 3 || currentModeNum === 4) {
      change.gasFan = fanValue;
    } else {
      change.eleFan = fanValue;
    }
  } else if (currentMode === "auto") {
    change.autoFan = fanValue;
  } else {
    // Fallback: use coolFan
    change.coolFan = fanValue;
  }
} else {
  // Unknown topic suffix
  return null;
}

change.zone = zone;

// 3. Construct Bridge Message
msg.payload = {
  Type: "Change",
  Changes: change,
};
msg.topic = `librecoach/ble/microair/${mac}/set`;

return msg;

// Optimistic MicroAir State Update
// Input: Encoded bridge command from microair_encode_command.js
// Output 1: Optimistic HA state update (MQTT out to HA state topic)
// Output 2: Original bridge command passthrough (MQTT out to bridge /set topic)
//
// Merges pending changes into cached zone state and publishes
// immediately so the HA UI updates without waiting for the next poll cycle.

const command = msg.payload;
if (!command || command.Type !== "Change" || !command.Changes)
  return [null, msg];

const changes = command.Changes;
const zone = changes.zone;

// Extract MAC from the bridge topic: librecoach/ble/microair/{mac}/set
const topicParts = msg.topic.split("/");
if (topicParts.length < 5) return [null, msg];

const mac = topicParts[3];
const safeMac = mac.replace(/:/g, "_");

// Read cached state
const cached = global.get(`microair_${safeMac}_zone_${zone}`);
if (!cached) {
  // No cached state yet — can't build optimistic update, just forward command
  return [null, msg];
}

// Read observed max fan speed for dynamic mapping
const maxFanSpeed =
  global.get(`microair_${safeMac}_zone_${zone}_maxfan`, "file") || 2;

// Build optimistic state by merging changes into cached state
const optimistic = Object.assign({}, cached);

// Mode changes
if ("mode" in changes) {
  optimistic.mode_num = changes.mode;
  // Map numeric mode to string mode
  const MODE_NUM_TO_MODE = {
    0: "off",
    1: "fan_only",
    2: "cool",
    3: "heat",
    4: "heat",
    5: "heat",
    6: "off",
    7: "heat",
    8: "auto",
    9: "auto",
    10: "auto",
    11: "auto",
    12: "heat",
  };
  optimistic.mode = MODE_NUM_TO_MODE[changes.mode] || "off";

  // Update heat_source for preset state reporting
  const HEAT_TYPE_REVERSE = {
    5: "Heat Pump",
    4: "Furnace",
    3: "Gas Furnace",
    7: "Heat Strip",
    12: "Electric Heat",
  };
  if (changes.mode in HEAT_TYPE_REVERSE) {
    optimistic.heat_source = HEAT_TYPE_REVERSE[changes.mode];
    // Persist last-used heat mode so it survives off/on cycles
    global.set(
      `microair_${safeMac}_zone_${zone}_lastheat`,
      changes.mode,
      "file",
    );
  }
}

// Setpoint changes
if ("cool_sp" in changes) optimistic.cool_sp = changes.cool_sp;
if ("heat_sp" in changes) optimistic.heat_sp = changes.heat_sp;
if ("autoCool_sp" in changes) optimistic.autoCool_sp = changes.autoCool_sp;
if ("autoHeat_sp" in changes) optimistic.autoHeat_sp = changes.autoHeat_sp;

// Fan changes — update the correct fan field
if ("fanOnly" in changes) optimistic.fan_mode_num = changes.fanOnly;
if ("coolFan" in changes) optimistic.cool_fan_mode_num = changes.coolFan;
if ("gasFan" in changes) optimistic.furnace_fan_mode_num = changes.gasFan;
if ("eleFan" in changes) optimistic.heat_fan_mode_num = changes.eleFan;
if ("autoFan" in changes) optimistic.auto_fan_mode_num = changes.autoFan;

// Dynamic fan mode map based on observed speed count
const FAN_MODE_MAP =
  maxFanSpeed >= 3
    ? { 0: "auto", 1: "low", 2: "medium", 3: "high", 128: "auto" } // 3-speed
    : { 0: "auto", 1: "low", 2: "high", 128: "auto" }; // 2-speed
const mode = optimistic.mode || "off";
let fanNum = 0;
if (mode === "fan_only") fanNum = optimistic.fan_mode_num || 0;
else if (mode === "cool") fanNum = optimistic.cool_fan_mode_num || 0;
else if (mode === "heat")
  fanNum = optimistic.heat_fan_mode_num || optimistic.furnace_fan_mode_num || 0;
else if (mode === "auto") fanNum = optimistic.auto_fan_mode_num || 0;
optimistic.fan_mode = FAN_MODE_MAP[fanNum] || "auto";

// Power state
if ("power" in changes) {
  optimistic.on = changes.power === 1;
  optimistic.off = changes.power === 0;
}

// Update cache with optimistic state
global.set(`microair_${safeMac}_zone_${zone}`, optimistic);

// Output 1: Publish optimistic state to HA state topic
const haMsg = {
  topic: `librecoach/ble/microair/${mac}/zone/${zone}/state`,
  payload: JSON.stringify(optimistic),
};

// Output 2: Forward original command to bridge
const bridgeMsg = {
  topic: msg.topic,
  payload: msg.payload,
};

return [haMsg, bridgeMsg];

// Encodes DC_LOAD_COMMAND messages (DGN 1FFBCh, §6.23.4)

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const CMD_SET_LEVEL = 0x00;
const CMD_ON = 0x01;
const CMD_OFF = 0x03;
const CMD_STOP = 0x04;
const CMD_UNLOCK = 0x22;
const LEVEL_FULL_ON = 200;
const NON_GROUP = 0xff;
const DGN = "1FFBC";

// --- Input Validation ---
const instance = msg.instance;

if (typeof instance !== "number" || instance < 1 || instance > 250) {
    node.warn(`[encode_dc_load_command] Invalid instance: ${instance}`);
    return null;
}

// --- Parse Command ---
// JSON schema: payload is always an object
const command = msg.payload.state;
const brightness = msg.payload.brightness;

const dimmableLights = global.get("dimmableLights", "file") || [];
const isDimmable = dimmableLights.includes(instance);

// --- Command Mapping ---
let commandCode, desiredLevel;

if (command === "OFF") {
    commandCode = CMD_OFF;
    desiredLevel = 0;
} else if (command === "ON" && brightness !== undefined && brightness > 0) {
    commandCode = CMD_SET_LEVEL;
    desiredLevel = Math.round(brightness * 2);
} else if (isDimmable) {
    const lastBrightness =
        global.get("dimmerBrightness_" + instance, "file") || 100;
    commandCode = CMD_SET_LEVEL;
    desiredLevel = Math.round(lastBrightness * 2);
} else {
    commandCode = CMD_ON;
    desiredLevel = LEVEL_FULL_ON;
}

// --- Helper Functions ---
function buildCanMessage(instance, level, cmd) {
    const dataBytes = new Array(8).fill(0xff);
    dataBytes[0] = instance; // Byte 0: Instance
    dataBytes[1] = NON_GROUP; // Byte 1: Group
    dataBytes[2] = level; // Byte 2: Desired Level
    dataBytes[3] = 0xff; // Byte 3: Mode/Interlock/Direction (no change)
    dataBytes[4] = cmd; // Byte 4: Command
    dataBytes[5] = 0xff; // Byte 5: Delay/Duration
    dataBytes[6] = 0xff; // Byte 6: Reserved
    dataBytes[7] = 0xff; // Byte 7: Reserved

    const dataHex = dataBytes
        .map((byte) => byte.toString(16).padStart(2, "0"))
        .join("");

    const dgnInt = parseInt(DGN, 16);
    const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
    const canIdHex = canIdInt.toString(16).padStart(8, "0");

    return `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`;
}

// --- Store last brightness for dimmable recall ---
if (brightness !== undefined && brightness > 0) {
    global.set("dimmerBrightness_" + instance, brightness, "file");
}

// --- Build and Send ---
// Message 1: UNLOCK
node.send({
    topic: "can/send",
    payload: buildCanMessage(instance, desiredLevel, CMD_UNLOCK),
});

// Message 2: Command
node.send({
    topic: "can/send",
    payload: buildCanMessage(instance, desiredLevel, commandCode),
});

return null;

// A simple gate node to allow messages to pass only if Beta features are enabled.

// Check the global betaEnabled flag
const isBetaEnabled = global.get("betaEnabled");

// If beta is enabled, pass the message through unmodified.
// Otherwise, return null to drop the message and stop the flow along this path.
if (isBetaEnabled === true) {
  return msg;
}

return null;

// Self-creating HA Status Publisher for GENERIC_INDICATOR_COMMAND (DGN 1FED9h, §6.26.2)
// Eavesdrops on indicator commands to infer light state.
// Entity naming: switch_i_N (instance) or switch_g_N (group).
// Routing keys: "switch_i" (instance), "switch_g" (group).
// Output 1: [messages] → MQTT Out

if (!msg.payload || typeof msg.payload !== "object") {
  return null;
}

const p = msg.payload;

if (typeof p.instance !== "number" || typeof p.function_raw !== "number") {
  return null;
}

// --- State inference ---
// Only 0x00 and 0x11 reach here (decoder gates all other function types).
function inferState(fn, bRaw) {
  if (typeof bRaw === "number" && bRaw <= 200) {
    return bRaw > 0 ? "ON" : "OFF";
  }
  return null;
}

const haStatus = inferState(p.function_raw, p.brightness_raw);
if (haStatus === null) {
  return null;
}

// Brightness as 0-100%
let brightness;
if (typeof p.brightness_raw === "number" && p.brightness_raw <= 200) {
  brightness = parseFloat((p.brightness_raw * 0.5).toFixed(1));
}

// --- Build target list ---
const targets = [];

if (p.instance >= 1 && p.instance <= 250) {
  // Specific instance
  targets.push({
    entityId: `switch_i_${p.instance}`,
    displayName: `Switch ${p.instance}`,
  }); // routing key: switch_i
} else if (
  p.instance === 255 &&
  p.is_group_command &&
  Array.isArray(p.groups) &&
  p.groups.length > 0
) {
  // Group command — one entity per targeted group
  for (const g of p.groups) {
    targets.push({
      entityId: `switch_g_${g}`,
      displayName: `Switch Group ${g}`,
    }); // routing key: switch_g
  }
} else {
  // instance=0 (all instances broadcast) — no specific entity to update
  return null;
}

// --- Dimmable detection ---
// Uses separate array from DC_DIMMER/DC_LOAD to avoid cross-contamination
// (those store numeric instances; indicators use entityId strings for group support)
const dimmableIndicators = global.get("dimmableIndicators", "file") || [];
const CREATED_KEY = "genericIndicatorCreated";
const created = flow.get(CREATED_KEY) || {};
const messages = [];

for (const { entityId, displayName } of targets) {
  let isDimmable = dimmableIndicators.includes(entityId);

  // Intermediate brightness (1-199 raw = 0.5-99.5%) or Ramp → dimmable
  if (!isDimmable) {
    if (
      (typeof p.brightness_raw === "number" &&
        p.brightness_raw >= 1 &&
        p.brightness_raw <= 199) ||
      p.function_raw === 0x11
    ) {
      dimmableIndicators.push(entityId);
      isDimmable = true;
    }
  }

  // (Re)publish whenever advertised capability differs from last published —
  // self-corrects after any context/broker desync.
  const desiredMode = isDimmable ? "brightness" : "onoff";

  if (created[entityId] !== desiredMode) {
    const config = {
      name: displayName,
      unique_id: entityId,
      default_entity_id: `light.${entityId}`,
      icon: "mdi:light-recessed",
      schema: "json",
