    duration = "Momentary";
} else if (durationRaw <= 240) {
    duration = `${durationRaw}s`;
} else if (durationRaw >= 241 && durationRaw <= 250) {
    duration = `${durationRaw - 236}min`;
} else if (durationRaw === 255) {
    duration = "Continuous";
} else {
    duration = "Reserved";
}

