const functionNames = {
    0x00: "Set Brightness",
    0x01: "LED1 Off, LED2 Off",
    0x02: "LED1 On, LED2 Off",
    0x03: "LED1 Off, LED2 On",
    0x04: "LED1 On, LED2 On",
    0x11: "Ramp Brightness",
    0x21: "Flash Alternate",
};
