            originalMessage: incomingPayload.originalMessage || null,
            data_payload,
            function_raw: functionRaw,
            function: functionName,
            instance,
            group_raw: groupRaw,
            groups,
            brightness_raw: brightnessRaw,
            count: 0,
            first_seen: Date.now(),
