    ...incomingPayload,
    dgn,
    dgn_name: "GENERIC_INDICATOR_COMMAND",
    instance,
    group_raw: groupRaw,
    groups,
    is_group_command: isGroupCommand,
    brightness_raw: brightnessRaw,
    brightness,
