    result.is_unlocked = lockStatusRaw === 0;
    result.is_moving = data[2] === 1 || data[2] === 2;
    result.is_opening = data[2] === 1;
    result.is_closing = data[2] === 2;
    result.is_stationary = data[2] === 0;

