if (parts.length < 3) {
  node.error(`Invalid command topic structure: ${topic}`);
  return null;
}

const serviceType = parts[0];
const instance = parts[1];
const dbusPath = "/" + parts.slice(2).join("/");

let value = msg.payload;

// Convert string payloads to numbers if applicable
if (typeof value === "string") {
  const num = Number(value);
  if (!isNaN(num)) {
    value = num;
  } else if (serviceType === "vebus" && dbusPath === "/Mode") {
    const mapped = VEBUS_MODE_MAP[value.toLowerCase()];
    if (mapped !== undefined) {
      value = mapped;
    } else {
      node.warn(`Unknown VE.Bus mode value: ${value}`);
      return null;
    }
  }
}

// Gate: Ensure active Portal ID
const victronPortalId = global.get("victronPortalId", "file");
if (!victronPortalId) {
  node.warn("Cannot send Victron command: victronPortalId not set");
  return null;
}

// --- Output 1: Victron Write ---
const victronMsg = {
  topic: `W/${victronPortalId}/${serviceType}/${instance}${dbusPath}`,
  payload: JSON.stringify({ value: value }),
};

// --- Output 2: HA System Relay Status Feedback ---
let haStatusMsg = null;

// Filter: Only proceed if it is a "system" service AND contains "relay"
const isSystemRelay =
  serviceType === "system" && dbusPath.toLowerCase().includes("relay");

if (isSystemRelay) {
  const sanitizedPath = parts
    .slice(2)
    .map((p) => p.toLowerCase())
    .join("_");

  haStatusMsg = {
    topic: `homeassistant/switch/victron_${serviceType}_${instance}_${sanitizedPath}/state`,
    payload: { value: value },
  };
}

// Return array: [Victron, HA Status (if system relay)]
return [victronMsg, haStatusMsg];

// Encodes FLOOR_HEAT_COMMAND messages (1FEFB)

// --- Configuration ---
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;
const PRIORITY = 6;
const DGN = "1FEFB";

// --- Input Validation ---
const instance = msg.instance;
const command = msg.command;

if (typeof instance !== "number") {
  node.warn(`[encode_floor_heat_command] Invalid instance: ${instance}`);
  return null;
}

// --- Get Context ---
const levelMap = global.get("floorHeatLevelMap", "file");
const scheduleContextKey = `floorHeat_${instance}_ScheduleOn`;
const isScheduleOn = global.get(scheduleContextKey, "file") || false;

// Store and retrieve the last used non-store preset's rawValue
const lastPresetKey = `floorHeat_${instance}_LastRawSetpoint`;
const lastRawSetpoint = global.get(lastPresetKey, "file") || 0;

// Get the currently active preset name from the status flow
const currentPresetKey = `floorHeat_${instance}_CurrentPreset`;
const currentPresetName = global.get(currentPresetKey, "file") || "level_1";

if (!levelMap && command !== "OFF") {
  node.warn(
    "[encode_floor_heat_command] Floor heat level map not found. Levels must be discovered first.",
  );
  return null;
}

// Determine the raw value to send during mode changes (HEAT/AUTO)
let rawValueToSend;
const storeLevelInfo = levelMap?.["store"];

if (currentPresetName === "store" && storeLevelInfo) {
  rawValueToSend = storeLevelInfo.rawValue;
} else if (lastRawSetpoint > 0) {
  rawValueToSend = lastRawSetpoint;
} else if (levelMap?.["level_1"]?.rawValue) {
  rawValueToSend = levelMap["level_1"].rawValue;
} else {
  node.warn(
    "[encode_floor_heat_command] No valid setpoint available. Levels must be discovered first.",
  );
  return null;
}

// --- Build Payload ---
const dataBytes = new Array(8).fill(0xff);
dataBytes[0] = instance; // Byte 0: Instance

// --- Command Mapping ---
if (command === "OFF") {
  dataBytes[1] = 0xc0; // Byte 1: Command (Off)
  dataBytes[2] = 0x00; // Byte 2: Setpoint LSB
  dataBytes[3] = 0x00; // Byte 3: Setpoint MSB
  global.set(scheduleContextKey, false, "file");
} else if (command === "HEAT") {
  // HEAT command: Turn ON, force Schedule OFF (Manual Mode)
  dataBytes[1] = 0xc4; // Byte 1: Command (ON + Schedule OFF)
  dataBytes[2] = rawValueToSend & 0xff; // Byte 2: Setpoint LSB
  dataBytes[3] = (rawValueToSend >> 8) & 0xff; // Byte 3: Setpoint MSB
  global.set(scheduleContextKey, false, "file");
} else if (command === "AUTO") {
  // AUTO command: Turn ON, force Schedule ON (Automatic Mode)
  dataBytes[1] = 0xd7; // Byte 1: Command (ON + Schedule ON)
  dataBytes[2] = rawValueToSend & 0xff; // Byte 2: Setpoint LSB
  dataBytes[3] = (rawValueToSend >> 8) & 0xff; // Byte 3: Setpoint MSB
  global.set(scheduleContextKey, true, "file");
} else if (command === "SET_PRESET") {
  if (!levelMap) {
    node.error(
      "[encode_floor_heat_command] Cannot set preset, level map is missing.",
    );
    return null;
  }

  const presetName = msg.value;
  const normalizedPresetName =
    presetName === "none" || !presetName ? "store" : presetName;
  const levelInfo = levelMap[normalizedPresetName];

  if (!levelInfo || typeof levelInfo.rawValue === "undefined") {
    node.warn(`[encode_floor_heat_command] Unknown preset name: ${presetName}`);
    return null;
  }

  const rawValue = levelInfo.rawValue;
  dataBytes[1] = isScheduleOn ? 0xd4 : 0xc4; // Byte 1: Command (maintain schedule state)
  dataBytes[2] = rawValue & 0xff; // Byte 2: Setpoint LSB
  dataBytes[3] = (rawValue >> 8) & 0xff; // Byte 3: Setpoint MSB

  // Update last non-store setpoint
  if (normalizedPresetName !== "store") {
    global.set(lastPresetKey, rawValue, "file");
  }
} else {
  node.warn(`[encode_floor_heat_command] Invalid command: "${command}"`);
  return null;
}

const dataHex = dataBytes
  .map((byte) => byte.toString(16).padStart(2, "0"))
  .join("");

// --- Construct CAN ID ---
const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// --- Send Message ---
node.send({
  topic: "can/send",
  payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
});

return null;

// Encodes GENERIC_INDICATOR_COMMAND (DGN 1FED9h, §6.26.2)
// Handles both routing keys:
//   switch_i → instance-targeted command (byte 0 = instance, byte 1 = 0xFF non-group)
//   switch_g → group-targeted command   (byte 0 = 0xFF,      byte 1 = group bitmap)

const PRIORITY = 6;
const DGN = "1FED9";
const SOURCE_ADDRESS = global.get("rvc_source_address") || 254;

const routingKey = msg.routingKey;
const instance = msg.instance; // instance number OR group number depending on routingKey

if (typeof instance !== "number") {
  node.warn(`[encode_generic_indicator_command] Invalid instance: ${instance}`);
  return null;
}

// Build byte 0 (instance) and byte 1 (group bitmap)
let byte0, byte1;

if (routingKey === "switch_i") {
  if (instance < 1 || instance > 250) {
    node.warn(
      `[encode_generic_indicator_command] Instance out of range: ${instance}`,
    );
    return null;
  }
  byte0 = instance;
  byte1 = 0xff; // non-group command
} else if (routingKey === "switch_g") {
  if (instance < 1 || instance > 7) {
    node.warn(
      `[encode_generic_indicator_command] Group out of range: ${instance}`,
    );
    return null;
  }
  byte0 = 0xff; // no specific instance (group command)
  // Bit 7=0 (group command), bit (group-1)=0 (targets this group), all others=1
  byte1 = 0x7f & ~(1 << (instance - 1));
} else {
  node.warn(
    `[encode_generic_indicator_command] Unknown routingKey: ${routingKey}`,
  );
  return null;
}

// Parse HA command — JSON schema: msg.payload is always an object
const command = msg.payload.state;
const brightnessIn = msg.payload.brightness;

// Resolve entity ID for dimmable/brightness lookups
const entityId =
  routingKey === "switch_g" ? `switch_g_${instance}` : `switch_i_${instance}`;
const dimmableIndicators = global.get("dimmableIndicators", "file") || [];
const isDimmable = dimmableIndicators.includes(entityId);

// Determine brightness raw value (0-200 scale, 0.5% per step)
// HA sends brightness as 0-100% (brightness_scale: 100 set in discovery)
let brightnessRaw;

if (command === "OFF") {
  brightnessRaw = 0;
} else if (brightnessIn !== undefined && brightnessIn > 0) {
  brightnessRaw = Math.min(200, Math.round(brightnessIn * 2));
} else if (isDimmable) {
  const lastBrightness =
    global.get("indicatorBrightness_" + entityId, "file") || 100;
  brightnessRaw = Math.min(200, Math.round(lastBrightness * 2));
} else {
  brightnessRaw = 200; // full brightness for non-dimmable ON
}

// Store last brightness (in 0-100% scale) and state for recall / optimistic update
if (command !== "OFF" && brightnessRaw > 0) {
  global.set("indicatorBrightness_" + entityId, brightnessRaw / 2, "file");
}
global.set("indicatorState_" + entityId, command, "file");

// Optimistic HA state publish — no CAN echo expected for self-sent commands
const storedBrightness = global.get("indicatorBrightness_" + entityId, "file");

const stateObj = { state: command };
if (command === "ON") {
  if (
    isDimmable &&
    typeof storedBrightness === "number" &&
    storedBrightness > 0
  ) {
    stateObj.color_mode = "brightness";
    stateObj.brightness = storedBrightness;
  } else {
    stateObj.color_mode = "onoff";
  }
}

// Build 8-byte data payload per §6.26.2 Table 6.26.2b
const dataBytes = [
  byte0, // Byte 0: Instance
  byte1, // Byte 1: Group bitmap
  brightnessRaw, // Byte 2: Brightness (0-200)
  0xff, // Byte 3: Bank Select (0xFF = not supported)
  0xff, // Byte 4: Duration (0xFF = continuous)
  0xff, // Byte 5: Reserved
  0x00, // Byte 6: Function (0x00 = Set Brightness)
  0xff, // Byte 7: Reserved
];

const dataHex = dataBytes
  .map((byte) => byte.toString(16).padStart(2, "0"))
  .join("");

const dgnInt = parseInt(DGN, 16);
const canIdInt = (PRIORITY << 26) | (dgnInt << 8) | SOURCE_ADDRESS;
const canIdHex = canIdInt.toString(16).padStart(8, "0");

// Send both through output 1: CAN frame to bridge, then optimistic HA state update
return [
  [
    {
      topic: "can/send",
      payload: `${canIdHex.toUpperCase()}#${dataHex.toUpperCase()}`,
    },
    {
      topic: `homeassistant/light/${entityId}/state`,
      payload: JSON.stringify(stateObj),
      retain: true,
    },
  ],
];

// Prepares persistent notification for entity list export
// Input: msg with msg.exportFilename, msg.entityCount, and (per variant)
//        msg.downloadPage, msg.notificationId, msg.notifyTitle
// Output: msg.payload configured for notify_user

const filename = msg.exportFilename || "librecoach_dashboard_prompt.txt";
const downloadPage = msg.downloadPage || "librecoach_download_dashboard.html";
const haBaseUrl = env.get("HA_BASE_URL") || "http://homeassistant.local:8123";
const downloadUrl = `${haBaseUrl}/local/${downloadPage}`;

msg.payload = {
  title: msg.notifyTitle || "LibreCoach AI Dashboard Prompt",
  message: `<a href="${downloadUrl}" target="_blank">Download ${filename} (${msg.entityCount || "?"} entities)</a><br><br>Upload the file to your AI, then type:<br><b>Read the attached file and create a Home Assistant dashboard following all instructions in the file.</b>`,
  notification_id: msg.notificationId || "librecoach_export_entities",
  data: { filename },
};

node.status({ fill: "green", shape: "dot", text: "Notification prepared" });
return msg;

// Sets up HA Template API call to render the full LibreCoach entity list with area info
// Input: msg (triggered by export button)
// Output: msg configured for POST /api/template

const haBaseUrl = "http://supervisor/core";
const haToken = env.get("SUPERVISOR_TOKEN");

if (!haToken) {
  node.error("SUPERVISOR_TOKEN not configured.", msg);
  node.status({ fill: "red", shape: "ring", text: "No Supervisor token" });
  return null;
}

msg.headers = {
  Authorization: `Bearer ${haToken}`,
  "Content-Type": "application/json",
};
msg.url = `${haBaseUrl}/api/template`;

// Jinja2 template rendered by HA — catches every LibreCoach entity via
// device manufacturer check (authoritative) plus keyword fallbacks.
// Sorted by area so output groups naturally by room for dashboard building.
const template = `{%- set ns = namespace(rows=[]) -%}
{%- for s in states -%}
{%- set eid = s.entity_id -%}
{%- set domain = eid.split('.')[0] -%}
{%- if domain == 'automation' -%}{%- continue -%}{%- endif -%}
{%- if 'librecoach_victron_' in eid -%}{%- continue -%}{%- endif -%}
{%- set dev_id = device_id(eid) -%}
{%- set is_lc = dev_id is not none and device_attr(dev_id, 'manufacturer') == 'LibreCoach' -%}
{%- if is_lc or 'switch_' in eid or 'tank_' in eid or 'thermostat' in eid or 'aquahot' in eid or 'generator' in eid or 'hughes_' in eid or 'waterheater' in eid or 'circ_pump' in eid or 'battery_house' in eid or 'signal_quality' in eid or 'librecoach' in eid or 'rv_' in eid -%}
{%- set area = area_name(eid) | default('(no area)', true) -%}
{%- set fname = s.attributes.friendly_name | default(eid) -%}
{%- if fname.startswith('LibreCoach:') and domain not in ('button', 'text', 'select') and 'record_unknown' not in eid -%}{%- continue -%}{%- endif -%}
{%- if 'switch_' in eid and fname.startswith('Switches ') -%}{%- continue -%}{%- endif -%}
{%- if s.state in ('unavailable', 'unknown') and domain not in ('button', 'text', 'select') -%}{%- continue -%}{%- endif -%}
{%- set dc = s.attributes.device_class | default('') -%}
{%- set unit = s.attributes.unit_of_measurement | default('') -%}
{%- set dimmable = 'true' if 'brightness' in s.attributes.get('supported_color_modes', []) else 'false' -%}
{%- set ns.rows = ns.rows + [area ~ '|' ~ domain ~ '|' ~ eid ~ '|' ~ fname ~ '|' ~ dc ~ '|' ~ unit ~ '|' ~ dimmable] -%}
{%- endif -%}
{%- endfor -%}
AREA|DOMAIN|ENTITY_ID|FRIENDLY_NAME|DEVICE_CLASS|UNIT|DIMMABLE
{%- for row in ns.rows | sort %}
{{ row }}
{%- endfor %}`;

msg.payload = { template };
return msg;

// Builds export configuration from Home Assistant states
// Input:
//   msg.states - Array from /api/states
//   msg.rvInfo - Object with RV metadata (manufacturer, model, year, other)
// Output: msg.exportConfig (object), msg.exportFilename (string)

const ENTITY_PATTERNS = [
  /^light\.switch_\d+$/,
  /^cover\.shade_\d+$/,
  /^lock\.lock_\d+$/,
  /^switch\.water_pump$/,
  /^switch\.autofill$/,
  /^sensor\.\w+_tank$/,
  /^sensor\.\w+_battery$/,
  /^climate\.floor_heat_\d+$/,
  /^light\.aquahot_(burner|ac_1|ac_2|engine)$/,
];

if (!msg.states || !Array.isArray(msg.states)) {
  node.error("Input missing 'states' array from /api/states", msg);
  return null;
}

const entities = {};

for (const state of msg.states) {
  const entityId = state.entity_id;

  const isLibreCoachEntity = ENTITY_PATTERNS.some((pattern) =>
    pattern.test(entityId),
  );

  if (!isLibreCoachEntity) {
    continue;
  }

  const attributes = state.attributes || {};
  const friendlyName = attributes.friendly_name || entityId;

  // Skip entities with the default HA-generated name (not user-customized)
  if (friendlyName.startsWith("LibreCoach: ")) {
    continue;
  }

  const parts = entityId.split(".");
  const domain = parts[0];
  const entityName = parts[1];

  let instance = null;
  const instanceMatch = entityName.match(/_(\d+)$/);
  if (instanceMatch) {
    instance = parseInt(instanceMatch[1], 10);
  } else if (entityName === "water_pump" || entityName === "autofill") {
    instance = entityName;
  } else {
    const aquahotMatch = entityName.match(
      /^aquahot_(burner|ac_1|ac_2|engine)$/,
    );
    if (aquahotMatch) {
      instance = aquahotMatch[1];
    }
  }

  let originalName = entityName
    .replace(/_/g, " ")
    .replace(/\b\w/g, (c) => c.toUpperCase());

  entities[entityId] = {
    entity_id: entityId,
    original_name: originalName,
    friendly_name: friendlyName,
    device_class: domain,
    instance: instance,
  };
}

const exportConfig = {
  export_date: new Date().toISOString(),
  rv_info: msg.rvInfo || {
    manufacturer: "Unknown",
    model: "Unknown",
    year: "Unknown",
    other: "Unknown",
  },
  entities: entities,
};

msg.exportConfig = exportConfig;

const rvInfo = msg.rvInfo || {};
const filenameParts = ["manufacturer", "model", "year", "other"]
  .map((key) => (rvInfo[key] || "").toString().trim())
  .filter((val) => val.length > 0 && val !== "Unknown")
  .map((val) => val.replace(/\s+/g, "-"));

msg.exportFilename =
  filenameParts.length > 0
    ? filenameParts.join("_") + ".json"
    : "librecoach_config.json";

const entityCount = Object.keys(entities).length;
node.status({ fill: "green", shape: "dot", text: `${entityCount} entities` });

return msg;

// Writes export config and download page to /homeassistant/www/
// Input: msg.exportConfig (object from Build Export Config)
//        msg.exportFilename (dynamic filename from export_ha_config)
// Output: two messages to File Write node (JSON export + HTML download page)

if (!msg.exportConfig) {
    node.error("Missing exportConfig object", msg);
    return null;
}

const entityCount = Object.keys(msg.exportConfig.entities || {}).length;
const filename = msg.exportFilename || "librecoach_config.json";

// Message 1: the JSON export file
const jsonMsg = {
    filename: `/homeassistant/www/${filename}`,
    payload: JSON.stringify(msg.exportConfig, null, 2),
    entityCount: entityCount,
    exportFilename: filename,
};

// Message 2: HTML download page that auto-triggers the file download
const htmlMsg = {
    filename: "/homeassistant/www/librecoach_download.html",
    payload: `<!DOCTYPE html>
<html><head><title>LibreCoach Download</title></head>
<body>
<script>
var a = document.createElement("a");
a.href = "/local/${filename}";
a.download = "${filename}";
document.body.appendChild(a);
a.click();
setTimeout(function() { window.close(); }, 1000);
</script>
<p>Your download should start automatically. If not, <a href="/local/${filename}" download="${filename}">click here</a>.</p>
</body></html>`,
    entityCount: entityCount,
    exportFilename: filename,
};

return [[jsonMsg, htmlMsg]];

// Reads RV info and sets up HA API request configuration
// Input: msg (triggered by export button)
// Output: msg with rvInfo, headers, and url for first API call

const haBaseUrl = "http://supervisor/core";
const haToken = env.get("SUPERVISOR_TOKEN");

if (!haToken) {
  node.error(
    "SUPERVISOR_TOKEN not configured. Ensure the add-on provides it.",
    msg,
  );
  node.status({ fill: "red", shape: "ring", text: "No Supervisor token" });
  return null;
}

// Store base URL and headers for subsequent HTTP requests
msg.haBaseUrl = haBaseUrl;
msg.headers = {
  Authorization: `Bearer ${haToken}`,
  "Content-Type": "application/json",
};

// Set URL for first API call
msg.url = `${haBaseUrl}/api/states`;

// Read RV info from flow context
const rvInfo = flow.get("rvInfo") || {};
msg.rvInfo = {
  manufacturer: rvInfo.rv_manufacturer || "Unknown",
  model: rvInfo.rv_model || "Unknown",
  year: rvInfo.rv_year || "Unknown",
  other: rvInfo.rv_other || "Unknown",
};

return msg;

// Stores RV info values from text input entities to flow context
// Input: msg.topic = "librecoach/rv_info/{field}/set"
//        msg.payload = value string
// Output: Republishes to state topic for HA sync

// Parse the topic to get the field name
const topicMatch = msg.topic.match(/^librecoach\/rv_info\/(\w+)\/set$/);
if (!topicMatch) {
  node.warn(`Unexpected topic format: ${msg.topic}`);
  return null;
}

const field = topicMatch[1];
const value = String(msg.payload).trim();

// Valid fields
const validFields = ["rv_manufacturer", "rv_model", "rv_year", "rv_other"];
if (!validFields.includes(field)) {
  node.warn(`Unknown RV info field: ${field}`);
  return null;
}

// Get current RV info from flow context or initialize
let rvInfo = flow.get("rvInfo") || {
  rv_manufacturer: "",
  rv_model: "",
  rv_year: "",
  rv_other: "",
};

// Update the field
rvInfo[field] = value;

// Store back to flow context
flow.set("rvInfo", rvInfo);

// Also persist to global file store so create_user_toggles.js can restore on restart
global.set(field, value, "file");

// Republish to state topic for HA to confirm the update
msg.topic = `librecoach/rv_info/${field}`;
msg.payload = value;

node.status({ fill: "green", shape: "dot" });

return msg;

// Stores Home Assistant states response
// Input: msg.payload = response from GET /api/states (array of state objects)
// Output: msg with states array ready for export function

// Validate response
if (!msg.payload || !Array.isArray(msg.payload)) {
  node.error("Invalid response from /api/states - expected array", msg);
  return null;
}

// Store states in message for downstream processing
msg.states = msg.payload;

// Log count for debugging
node.status({
  fill: "blue",
  shape: "dot",
  text: `${msg.states.length} entities`,
});

return msg;

// Decodes CHARGER_STATUS messages (1FFC7)
// RV-C §6.20.8 — CHARGER_STATUS

// === Helper Functions ===

function decodeUint16LE(data, offset) {
  return data[offset] | (data[offset + 1] << 8);
}

function decodeDCVoltage(raw) {
  // Table 5.3: 0.05 V/bit, 65535=Not Available, 65534=Out of Range
  if (raw === 65535) return null;
  if (raw === 65534) return "Out of Range";
  return parseFloat((raw * 0.05).toFixed(2));
}

function decodeDCCurrent(raw) {
  // Table 5.3: 0.05 A/bit, 65535=Not Available, 65534=Out of Range
  if (raw === 65535) return null;
  if (raw === 65534) return "Out of Range";
  return parseFloat((raw * 0.05).toFixed(2));
}

function decodePercent(raw) {
  // Table 5.3: 0.5%/bit, 200=100%, 255=Not Available
  if (raw === 255) return null;
  return parseFloat((raw * 0.5).toFixed(1));
}

function decodeOperatingState(raw) {
  // §6.20.8b byte 6
  const states = {
    0: "Disabled",
    1: "Not Charging",
    2: "Bulk",
    3: "Absorption",
    4: "Overcharge",
    5: "Equalize",
    6: "Float",
    7: "Constant Voltage/Current",
  };
  if (raw === 255) return null;
  return states[raw] || `Unknown (${raw})`;
}

// === Main Decode Function ===

function decodeChargerStatus(dgn, data) {
  const result = {
    dgn: dgn,
    dgn_name: "CHARGER_STATUS",
  };

  // Byte 0: Instance
  result.instance = data[0];
  result.raw_instance = data[0];

  // Bytes 1–2: Charge voltage (uint16 LE, Vdc)
  const rawVoltage = decodeUint16LE(data, 1);
  result.charge_voltage = decodeDCVoltage(rawVoltage);
  result.raw_charge_voltage = rawVoltage;

  // Bytes 3–4: Charge current (uint16 LE, Adc)
  const rawCurrent = decodeUint16LE(data, 3);
  result.charge_current = decodeDCCurrent(rawCurrent);
  result.raw_charge_current = rawCurrent;

  // Byte 5: Charge current percent of maximum
  result.charge_current_pct = decodePercent(data[5]);
  result.raw_charge_current_pct = data[5];

  // Byte 6: Operating state
  result.operating_state = decodeOperatingState(data[6]);
  result.raw_operating_state = data[6];

  // Byte 7: Flags
  const flags = data[7];
  result.default_state_on_powerup =
    (flags & 0x03) === 0x01 ? "Enabled" : "Disabled";
  result.auto_recharge_enabled = ((flags >> 2) & 0x03) === 0x01;
  const fc = (flags >> 4) & 0x03;
  const forceChargeStates = {
    0: "Not Forced",
    1: "Force Bulk",
    2: "Force Float",
  };
  result.force_charge = forceChargeStates[fc] ?? `Unknown (${fc})`;
  result.raw_flags = flags;

  // Convenience booleans
  const state = result.operating_state;
  result.charger_active =
    typeof state === "string" && !["Disabled", "Not Charging"].includes(state);
  result.charger_charging =
    typeof state === "string" &&
    [
      "Bulk",
      "Absorption",
      "Overcharge",
      "Equalize",
      "Float",
      "Constant Voltage/Current",
    ].includes(state);

  // Calculated power (W)
  if (
    typeof result.charge_voltage === "number" &&
    typeof result.charge_current === "number"
  ) {
    result.charge_power = parseFloat(
      (result.charge_voltage * result.charge_current).toFixed(1),
    );
  }

  return result;
}

